import type { BibleBook } from '../bibleData';

// Auto-generated from public-domain sources: World English Bible (WEB, EN)
// and João Ferreira de Almeida (Almeida, PT), via seven1m/open-bibles (USFX).
// Do not edit by hand — regenerate with scripts/generate-bible.

const book: BibleBook = {
  id: 'john',
  name: 'João',
  englishName: 'John',
  testament: 'new',
  chapters: {
    1: [
      { v: 1, en: 'In the beginning was the Word, and the Word was with God, and the Word was God.', pt: 'No princípio era o Verbo, e o Verbo estava com Deus, e o Verbo era Deus.' },
      { v: 2, en: 'The same was in the beginning with God.', pt: 'Ele estava no princípio com Deus.' },
      { v: 3, en: 'All things were made through him. Without him was not anything made that has been made.', pt: 'Todas as coisas foram feitas por intermédio dele, e sem ele nada do que foi feito se fez.' },
      { v: 4, en: 'In him was life, and the life was the light of men.', pt: 'Nele estava a vida, e a vida era a luz dos homens;' },
      { v: 5, en: 'The light shines in the darkness, and the darkness hasn’t overcome it.', pt: 'a luz resplandece nas trevas, e as trevas não prevaleceram contra ela.' },
      { v: 6, en: 'There came a man, sent from God, whose name was John.', pt: 'Houve um homem enviado de Deus, cujo nome era João.' },
      { v: 7, en: 'The same came as a witness, that he might testify about the light, that all might believe through him.', pt: 'Este veio como testemunha, a fim de dar testemunho da luz, para que todos cressem por meio dele.' },
      { v: 8, en: 'He was not the light, but was sent that he might testify about the light.', pt: 'Ele não era a luz, mas veio para dar testemunho da luz.' },
      { v: 9, en: 'The true light that enlightens everyone was coming into the world.', pt: 'Pois a verdadeira luz, que alumia a todo homem, estava chegando ao mundo.' },
      { v: 10, en: 'He was in the world, and the world was made through him, and the world didn’t recognize him.', pt: 'Estava ele no mundo, e o mundo foi feito por intermédio dele, e o mundo não o conheceu.' },
      { v: 11, en: 'He came to his own, and those who were his own didn’t receive him.', pt: 'Veio para o que era seu, e os seus não o receberam.' },
      { v: 12, en: 'But as many as received him, to them he gave the right to become God’s children, to those who believe in his name:', pt: 'Mas, a todos quantos o receberam, aos que crêem no seu nome, deu-lhes o poder de se tornarem filhos de Deus;' },
      { v: 13, en: 'who were born not of blood, nor of the will of the flesh, nor of the will of man, but of God.', pt: 'os quais não nasceram do sangue, nem da vontade da carne, nem da vontade do varão, mas de Deus.' },
      { v: 14, en: 'The Word became flesh, and lived among us. We saw his glory, such glory as of the one and only Son of the Father, full of grace and truth.', pt: 'E o Verbo se fez carne, e habitou entre nós, cheio de graça e de verdade; e vimos a sua glória, como a glória do unigênito do Pai.' },
      { v: 15, en: 'John testified about him. He cried out, saying, “This was he of whom I said, ‘He who comes after me has surpassed me, for he was before me.’”', pt: 'João deu testemunho dele, e clamou, dizendo: Este é aquele de quem eu disse: O que vem depois de mim, passou adiante de mim; porque antes de mim ele já existia.' },
      { v: 16, en: 'From his fullness we all received grace upon grace.', pt: 'Pois todos nós recebemos da sua plenitude, e graça sobre graça.' },
      { v: 17, en: 'For the law was given through Moses. Grace and truth were realized through Jesus Christ.', pt: 'Porque a lei foi dada por meio de Moisés; a graça e a verdade vieram por Jesus Cristo.' },
      { v: 18, en: 'No one has seen God at any time. The one and only Son, who is in the bosom of the Father, he has declared him.', pt: 'Ninguém jamais viu a Deus. O Deus unigênito, que está no seio do Pai, esse o deu a conhecer.' },
      { v: 19, en: 'This is John’s testimony, when the Jews sent priests and Levites from Jerusalem to ask him, “Who are you?”', pt: 'E este foi o testemunho de João, quando os judeus lhe enviaram de Jerusalém sacerdotes e levitas para que lhe perguntassem: Quem és tu?' },
      { v: 20, en: 'He declared, and didn’t deny, but he declared, “I am not the Christ.”', pt: 'Ele, pois, confessou e não negou; sim, confessou: Eu não sou o Cristo.' },
      { v: 21, en: 'They asked him, “What then? Are you Elijah?” He said, “I am not.” “Are you the prophet?” He answered, “No.”', pt: 'Ao que lhe perguntaram: Pois que? És tu Elias? Respondeu ele: Não sou. És tu o profeta? E respondeu: Não.' },
      { v: 22, en: 'They said therefore to him, “Who are you? Give us an answer to take back to those who sent us. What do you say about yourself?”', pt: 'Disseram-lhe, pois: Quem és? para podermos dar resposta aos que nos enviaram; que dizes de ti mesmo?' },
      { v: 23, en: 'He said, “I am the voice of one crying in the wilderness, ‘Make straight the way of the Lord,’ as Isaiah the prophet said.”', pt: 'Respondeu ele: Eu sou a voz do que clama no deserto: Endireitai o caminho do Senhor, como disse o profeta Isaías.' },
      { v: 24, en: 'The ones who had been sent were from the Pharisees.', pt: 'E os que tinham sido enviados eram dos fariseus.' },
      { v: 25, en: 'They asked him, “Why then do you baptize, if you are not the Christ, nor Elijah, nor the prophet?”', pt: 'Então lhe perguntaram: Por que batizas, pois, se tu não és o Cristo, nem Elias, nem o profeta?' },
      { v: 26, en: 'John answered them, “I baptize in water, but among you stands one whom you don’t know.', pt: 'Respondeu-lhes João: Eu batizo em água; no meio de vós está um a quem vós não conheceis.' },
      { v: 27, en: 'He is the one who comes after me, who is preferred before me, whose sandal strap I’m not worthy to loosen.”', pt: 'aquele que vem depois de mim, de quem eu não sou digno de desatar a correia da alparca.' },
      { v: 28, en: 'These things were done in Bethany beyond the Jordan, where John was baptizing.', pt: 'Estas coisas aconteceram em Betânia, além do Jordão, onde João estava batizando.' },
      { v: 29, en: 'The next day, he saw Jesus coming to him, and said, “Behold, the Lamb of God, who takes away the sin of the world!', pt: 'No dia seguinte João viu a Jesus, que vinha para ele, e disse: Eis o Cordeiro de Deus, que tira o pecado do mundo.' },
      { v: 30, en: 'This is he of whom I said, ‘After me comes a man who is preferred before me, for he was before me.’', pt: 'este é aquele de quem eu disse: Depois de mim vem um varão que passou adiante de mim, porque antes de mim ele já existia.' },
      { v: 31, en: 'I didn’t know him, but for this reason I came baptizing in water: that he would be revealed to Israel.”', pt: 'Eu não o conhecia; mas, para que ele fosse manifestado a Israel, é que vim batizando em água.' },
      { v: 32, en: 'John testified, saying, “I have seen the Spirit descending like a dove out of heaven, and it remained on him.', pt: 'E João deu testemunho, dizendo: Vi o Espírito descer do céu como pomba, e repousar sobre ele.' },
      { v: 33, en: 'I didn’t recognize him, but he who sent me to baptize in water, he said to me, ‘On whomever you will see the Spirit descending, and remaining on him, the same is he who baptizes in the Holy Spirit.’', pt: 'Eu não o conhecia; mas o que me enviou a batizar em água, esse me disse: Aquele sobre quem vires descer o Espírito, e sobre ele permanecer, esse é o que batiza no Espírito Santo.' },
      { v: 34, en: 'I have seen, and have testified that this is the Son of God.”', pt: 'Eu mesmo vi e já vos dei testemunho de que este é o Filho de Deus.' },
      { v: 35, en: 'Again, the next day, John was standing with two of his disciples,', pt: 'No dia seguinte João estava outra vez ali, com dois dos seus discípulos' },
      { v: 36, en: 'and he looked at Jesus as he walked, and said, “Behold, the Lamb of God!”', pt: 'e, olhando para Jesus, que passava, disse: Eis o Cordeiro de Deus!' },
      { v: 37, en: 'The two disciples heard him speak, and they followed Jesus.', pt: 'Aqueles dois discípulos ouviram-no dizer isto, e seguiram a Jesus.' },
      { v: 38, en: 'Jesus turned, and saw them following, and said to them, “What are you looking for?” They said to him, “Rabbi” (which is to say, being interpreted, Teacher), “where are you staying?”', pt: 'Voltando-se Jesus e vendo que o seguiam, perguntou-lhes: Que buscais? Disseram-lhe eles: rabi (que, traduzido, quer dizer Mestre), onde pousas?' },
      { v: 39, en: 'He said to them, “Come, and see.” They came and saw where he was staying, and they stayed with him that day. It was about the tenth hour.', pt: 'Respondeu-lhes: Vinde, e vereis. Foram, pois, e viram onde pousava; e passaram o dia com ele; era cerca da hora décima.' },
      { v: 40, en: 'One of the two who heard John, and followed him, was Andrew, Simon Peter’s brother.', pt: 'André, irmão de Simão Pedro, era um dos dois que ouviram João falar, e que seguiram a Jesus.' },
      { v: 41, en: 'He first found his own brother, Simon, and said to him, “We have found the Messiah!” (which is, being interpreted, Christ ).', pt: 'Ele achou primeiro a seu irmão Simão, e disse-lhe: Havemos achado o Messias (que, traduzido, quer dizer Cristo).' },
      { v: 42, en: 'He brought him to Jesus. Jesus looked at him, and said, “You are Simon the son of Jonah. You shall be called Cephas” (which is by interpretation, Peter).', pt: 'E o levou a Jesus. Jesus, fixando nele o olhar, disse: Tu és Simão, filho de João, tu serás chamado Cefas (que quer dizer Pedro).' },
      { v: 43, en: 'On the next day, he was determined to go out into Galilee, and he found Philip. Jesus said to him, “Follow me.”', pt: 'No dia seguinte Jesus resolveu partir para a Galiléia, e achando a Felipe disse-lhe: Segue-me.' },
      { v: 44, en: 'Now Philip was from Bethsaida, of the city of Andrew and Peter.', pt: 'Ora, Felipe era de Betsaida, cidade de André e de Pedro.' },
      { v: 45, en: 'Philip found Nathanael, and said to him, “We have found him, of whom Moses in the law, and the prophets, wrote: Jesus of Nazareth, the son of Joseph.”', pt: 'Felipe achou a Natanael, e disse-lhe: Acabamos de achar aquele de quem escreveram Moisés na lei, e os profetas: Jesus de Nazaré, filho de José.' },
      { v: 46, en: 'Nathanael said to him, “Can any good thing come out of Nazareth?” Philip said to him, “Come and see.”', pt: 'Perguntou-lhe Natanael: Pode haver coisa bem vinda de Nazaré? Disse-lhe Felipe: Vem e vê.' },
      { v: 47, en: 'Jesus saw Nathanael coming to him, and said about him, “Behold, an Israelite indeed, in whom is no deceit!”', pt: 'Jesus, vendo Natanael aproximar-se dele, disse a seu respeito: Eis um verdadeiro israelita, em quem não há dolo!' },
      { v: 48, en: 'Nathanael said to him, “How do you know me?” Jesus answered him, “Before Philip called you, when you were under the fig tree, I saw you.”', pt: 'Perguntou-lhe Natanael: Donde me conheces? Respondeu-lhe Jesus: Antes que Felipe te chamasse, eu te vi, quando estavas debaixo da figueira.' },
      { v: 49, en: 'Nathanael answered him, “Rabbi, you are the Son of God! You are King of Israel!”', pt: 'Respondeu-lhe Natanael: Rabi, tu és o Filho de Deus, tu és rei de Israel.' },
      { v: 50, en: 'Jesus answered him, “Because I told you, ‘I saw you underneath the fig tree,’ do you believe? You will see greater things than these!”', pt: 'Ao que lhe disse Jesus: Porque te disse: Vi-te debaixo da figueira, crês? coisas maiores do que estas verás.' },
      { v: 51, en: 'He said to him, “Most certainly, I tell you all, hereafter you will see heaven opened, and the angels of God ascending and descending on the Son of Man.”', pt: 'E acrescentou: Em verdade, em verdade vos digo que vereis o céu aberto, e os anjos de Deus subindo e descendo sobre o Filho do homem.' },
    ],
    2: [
      { v: 1, en: 'The third day, there was a marriage in Cana of Galilee. Jesus’ mother was there.', pt: 'Três dias depois, houve um casamento em Caná da Galiléia, e estava ali a mãe de Jesus;' },
      { v: 2, en: 'Jesus also was invited, with his disciples, to the marriage.', pt: 'e foi também convidado Jesus com seus discípulos para o casamento.' },
      { v: 3, en: 'When the wine ran out, Jesus’ mother said to him, “They have no wine.”', pt: 'E, tendo acabado o vinho, a mãe de Jesus lhe disse: Eles não têm vinho.' },
      { v: 4, en: 'Jesus said to her, “Woman, what does that have to do with you and me? My hour has not yet come.”', pt: 'Respondeu-lhes Jesus: Mulher, que tenho eu contigo? Ainda não é chegada a minha hora.' },
      { v: 5, en: 'His mother said to the servants, “Whatever he says to you, do it.”', pt: 'Disse então sua mãe aos serventes: Fazei tudo quanto ele vos disser.' },
      { v: 6, en: 'Now there were six water pots of stone set there after the Jews’ way of purifying, containing two or three metretes apiece.', pt: 'Ora, estavam ali postas seis talhas de pedra, para as purificações dos judeus, e em cada uma cabiam duas ou três metretas.' },
      { v: 7, en: 'Jesus said to them, “Fill the water pots with water.” They filled them up to the brim.', pt: 'Ordenou-lhe Jesus: Enchei de água essas talhas. E encheram- nas até em cima.' },
      { v: 8, en: 'He said to them, “Now draw some out, and take it to the ruler of the feast.” So they took it.', pt: 'Então lhes disse: Tirai agora, e levai ao mestre-sala. E eles o fizeram.' },
      { v: 9, en: 'When the ruler of the feast tasted the water now become wine, and didn’t know where it came from (but the servants who had drawn the water knew), the ruler of the feast called the bridegroom,', pt: 'Quando o mestre-sala provou a água tornada em vinho, não sabendo donde era, se bem que o sabiam os serventes que tinham tirado a água, chamou o mestre-sala ao noivo' },
      { v: 10, en: 'and said to him, “Everyone serves the good wine first, and when the guests have drunk freely, then that which is worse. You have kept the good wine until now!”', pt: 'e lhe disse: Todo homem põe primeiro o vinho bom e, quando já têm bebido bem, então o inferior; mas tu guardaste até agora o bom vinho.' },
      { v: 11, en: 'This beginning of his signs Jesus did in Cana of Galilee, and revealed his glory; and his disciples believed in him.', pt: 'Assim deu Jesus início aos seus sinais em Caná da Galiléia, e manifestou a sua glória; e os seus discípulos creram nele.' },
      { v: 12, en: 'After this, he went down to Capernaum, he, and his mother, his brothers, and his disciples; and they stayed there a few days.', pt: 'Depois disso desceu a Cafarnaum, ele, sua mãe, seus irmãos, e seus discípulos; e ficaram ali não muitos dias.' },
      { v: 13, en: 'The Passover of the Jews was at hand, and Jesus went up to Jerusalem.', pt: 'Estando próxima a páscoa dos judeus, Jesus subiu a Jerusalém.' },
      { v: 14, en: 'He found in the temple those who sold oxen, sheep, and doves, and the changers of money sitting.', pt: 'E achou no templo os que vendiam bois, ovelhas e pombas, e também os cambistas ali sentados;' },
      { v: 15, en: 'He made a whip of cords, and threw all out of the temple, both the sheep and the oxen; and he poured out the changers’ money, and overthrew their tables.', pt: 'e tendo feito um azorrague de cordas, lançou todos fora do templo, bem como as ovelhas e os bois; e espalhou o dinheiro dos cambistas, e virou-lhes as mesas;' },
      { v: 16, en: 'To those who sold the doves, he said, “Take these things out of here! Don’t make my Father’s house a marketplace!”', pt: 'e disse aos que vendiam as pombas: Tirai daqui estas coisas; não façais da casa de meu Pai casa de negócio.' },
      { v: 17, en: 'His disciples remembered that it was written, “Zeal for your house will eat me up.”', pt: 'Lembraram-se então os seus discípulos de que está escrito: O zelo da tua casa me devorará.' },
      { v: 18, en: 'The Jews therefore answered him, “What sign do you show us, seeing that you do these things?”', pt: 'Protestaram, pois, os judeus, perguntando-lhe: Que sinal de autoridade nos mostras, uma vez que fazes isto?' },
      { v: 19, en: 'Jesus answered them, “Destroy this temple, and in three days I will raise it up.”', pt: 'Respondeu-lhes Jesus: Derribai este santuário, e em três dias o levantarei.' },
      { v: 20, en: 'The Jews therefore said, “It took forty-six years to build this temple! Will you raise it up in three days?”', pt: 'Disseram, pois, os judeus: Em quarenta e seis anos foi edificado este santuário, e tu o levantarás em três dias?' },
      { v: 21, en: 'But he spoke of the temple of his body.', pt: 'Mas ele falava do santuário do seu corpo.' },
      { v: 22, en: 'When therefore he was raised from the dead, his disciples remembered that he said this, and they believed the Scripture, and the word which Jesus had said.', pt: 'Quando, pois ressurgiu dentre os mortos, seus discípulos se lembraram de que dissera isto, e creram na Escritura, e na palavra que Jesus havia dito.' },
      { v: 23, en: 'Now when he was in Jerusalem at the Passover, during the feast, many believed in his name, observing his signs which he did.', pt: 'Ora, estando ele em Jerusalém pela festa da páscoa, muitos, vendo os sinais que fazia, creram no seu nome.' },
      { v: 24, en: 'But Jesus didn’t entrust himself to them, because he knew everyone,', pt: 'Mas o próprio Jesus não confiava a eles, porque os conhecia a todos,' },
      { v: 25, en: 'and because he didn’t need for anyone to testify concerning man; for he himself knew what was in man.', pt: 'e não necessitava de que alguém lhe desse testemunho do homem, pois bem sabia o que havia no homem.' },
    ],
    3: [
      { v: 1, en: 'Now there was a man of the Pharisees named Nicodemus, a ruler of the Jews.', pt: 'Ora, havia entre os fariseus um homem chamado Nicodemos, um dos principais dos judeus.' },
      { v: 2, en: 'The same came to him by night, and said to him, “Rabbi, we know that you are a teacher come from God, for no one can do these signs that you do, unless God is with him.”', pt: 'Este foi ter com Jesus, de noite, e disse-lhe: Rabi, sabemos que és Mestre, vindo de Deus; pois ninguém pode fazer estes sinais que tu fazes, se Deus não estiver com ele.' },
      { v: 3, en: 'Jesus answered him, “Most certainly, I tell you, unless one is born anew, he can’t see God’s Kingdom.”', pt: 'Respondeu-lhe Jesus: Em verdade, em verdade te digo que se alguém não nascer de novo, não pode ver o reino de Deus.' },
      { v: 4, en: 'Nicodemus said to him, “How can a man be born when he is old? Can he enter a second time into his mother’s womb, and be born?”', pt: 'Perguntou-lhe Nicodemos: Como pode um homem nascer, sendo velho? porventura pode tornar a entrar no ventre de sua mãe, e nascer?' },
      { v: 5, en: 'Jesus answered, “Most certainly I tell you, unless one is born of water and spirit, he can’t enter into God’s Kingdom.', pt: 'Jesus respondeu: Em verdade, em verdade te digo que se alguém não nascer da água e do Espírito, não pode entrar no reino de Deus.' },
      { v: 6, en: 'That which is born of the flesh is flesh. That which is born of the Spirit is spirit.', pt: 'O que é nascido da carne é carne, e o que é nascido do Espírito é espírito.' },
      { v: 7, en: 'Don’t marvel that I said to you, ‘You must be born anew.’', pt: 'Não te admires de eu te haver dito: Necessário vos é nascer de novo.' },
      { v: 8, en: 'The wind blows where it wants to, and you hear its sound, but don’t know where it comes from and where it is going. So is everyone who is born of the Spirit.”', pt: 'O vento sopra onde quer, e ouves a sua voz; mas não sabes donde vem, nem para onde vai; assim é todo aquele que é nascido do Espírito.' },
      { v: 9, en: 'Nicodemus answered him, “How can these things be?”', pt: 'Perguntou-lhe Nicodemos: Como pode ser isto?' },
      { v: 10, en: 'Jesus answered him, “Are you the teacher of Israel, and don’t understand these things?', pt: 'Respondeu-lhe Jesus: Tu és mestre em Israel, e não entendes estas coisas?' },
      { v: 11, en: 'Most certainly I tell you, we speak that which we know, and testify of that which we have seen, and you don’t receive our witness.', pt: 'Em verdade, em verdade te digo que nós dizemos o que sabemos e testemunhamos o que temos visto; e não aceitais o nosso testemunho!' },
      { v: 12, en: 'If I told you earthly things and you don’t believe, how will you believe if I tell you heavenly things?', pt: 'Se vos falei de coisas terrestres, e não credes, como crereis, se vos falar das celestiais?' },
      { v: 13, en: 'No one has ascended into heaven, but he who descended out of heaven, the Son of Man, who is in heaven.', pt: 'Ora, ninguém subiu ao céu, senão o que desceu do céu, o Filho do homem.' },
      { v: 14, en: 'As Moses lifted up the serpent in the wilderness, even so must the Son of Man be lifted up,', pt: 'E como Moisés levantou a serpente no deserto, assim importa que o Filho do homem seja levantado;' },
      { v: 15, en: 'that whoever believes in him should not perish, but have eternal life.', pt: 'para que todo aquele que nele crê tenha a vida eterna.' },
      { v: 16, en: 'For God so loved the world, that he gave his one and only Son, that whoever believes in him should not perish, but have eternal life.', pt: 'Porque Deus amou o mundo de tal maneira que deu o seu Filho unigênito, para que todo aquele que nele crê não pereça, mas tenha a vida eterna.' },
      { v: 17, en: 'For God didn’t send his Son into the world to judge the world, but that the world should be saved through him.', pt: 'Porque Deus enviou o seu Filho ao mundo, não para que julgasse o mundo, mas para que o mundo fosse salvo por ele.' },
      { v: 18, en: 'He who believes in him is not judged. He who doesn’t believe has been judged already, because he has not believed in the name of the one and only Son of God.', pt: 'Quem crê nele não é julgado; mas quem não crê, já está julgado; porquanto não crê no nome do unigênito Filho de Deus.' },
      { v: 19, en: 'This is the judgment, that the light has come into the world, and men loved the darkness rather than the light; for their works were evil.', pt: 'E o julgamento é este: A luz veio ao mundo, e os homens amaram antes as trevas que a luz, porque as suas obras eram más.' },
      { v: 20, en: 'For everyone who does evil hates the light, and doesn’t come to the light, lest his works would be exposed.', pt: 'Porque todo aquele que faz o mal aborrece a luz, e não vem para a luz, para que as suas obras não sejam reprovadas.' },
      { v: 21, en: 'But he who does the truth comes to the light, that his works may be revealed, that they have been done in God.”', pt: 'Mas quem pratica a verdade vem para a luz, a fim de que seja manifesto que as suas obras são feitas em Deus.' },
      { v: 22, en: 'After these things, Jesus came with his disciples into the land of Judea. He stayed there with them, and baptized.', pt: 'Depois disto foi Jesus com seus discípulos para a terra da Judéia, onde se demorou com eles e batizava.' },
      { v: 23, en: 'John also was baptizing in Enon near Salim, because there was much water there. They came, and were baptized.', pt: 'Ora, João também estava batizando em Enom, perto de Salim, porque havia ali muitas águas; e o povo ía e se batizava.' },
      { v: 24, en: 'For John was not yet thrown into prison.', pt: 'Pois João ainda não fora lançado no cárcere.' },
      { v: 25, en: 'There arose therefore a questioning on the part of John’s disciples with some Jews about purification.', pt: 'Surgiu então uma contenda entre os discípulos de João e um judeu acerca da purificação.' },
      { v: 26, en: 'They came to John, and said to him, “Rabbi, he who was with you beyond the Jordan, to whom you have testified, behold, the same baptizes, and everyone is coming to him.”', pt: 'E foram ter com João e disseram-lhe: Rabi, aquele que estava contigo além do Jordão, do qual tens dado testemunho, eis que está batizando, e todos vão ter com ele.' },
      { v: 27, en: 'John answered, “A man can receive nothing, unless it has been given him from heaven.', pt: 'Respondeu João: O homem não pode receber coisa alguma, se não lhe for dada do céu.' },
      { v: 28, en: 'You yourselves testify that I said, ‘I am not the Christ,’ but, ‘I have been sent before him.’', pt: 'Vós mesmos me sois testemunhas de que eu disse: Não sou o Cristo, mas sou enviado adiante dele.' },
      { v: 29, en: 'He who has the bride is the bridegroom; but the friend of the bridegroom, who stands and hears him, rejoices greatly because of the bridegroom’s voice. This, my joy, therefore is made full.', pt: 'Aquele que tem a noiva é o noivo; mas o amigo do noivo, que está presente e o ouve, regozija-se muito com a voz do noivo. Assim, pois, este meu gozo está completo.' },
      { v: 30, en: 'He must increase, but I must decrease.', pt: 'É necessário que ele cresça e que eu diminua.' },
      { v: 31, en: 'He who comes from above is above all. He who is from the earth belongs to the earth, and speaks of the earth. He who comes from heaven is above all.', pt: 'Aquele que vem de cima é sobre todos; aquele que vem da terra é da terra, e fala da terra. Aquele que vem do céu é sobre todos.' },
      { v: 32, en: 'What he has seen and heard, of that he testifies; and no one receives his witness.', pt: 'Aquilo que ele tem visto e ouvido, isso testifica; e ninguém aceita o seu testemunho.' },
      { v: 33, en: 'He who has received his witness has set his seal to this, that God is true.', pt: 'Mas o que aceitar o seu testemunho, esse confirma que Deus é verdadeiro.' },
      { v: 34, en: 'For he whom God has sent speaks the words of God; for God gives the Spirit without measure.', pt: 'Pois aquele que Deus enviou fala as palavras de Deus; porque Deus não dá o Espírito por medida.' },
      { v: 35, en: 'The Father loves the Son, and has given all things into his hand.', pt: 'O Pai ama ao Filho, e todas as coisas entregou nas suas mãos.' },
      { v: 36, en: 'One who believes in the Son has eternal life, but one who disobeys the Son won’t see life, but the wrath of God remains on him.”', pt: 'Quem crê no Filho tem a vida eterna; o que, porém, desobedece ao Filho não verá a vida, mas sobre ele permanece a ira de Deus.' },
    ],
    4: [
      { v: 1, en: 'Therefore when the Lord knew that the Pharisees had heard that Jesus was making and baptizing more disciples than John', pt: 'Quando, pois, o Senhor soube que os fariseus tinham ouvido dizer que ele, Jesus, fazia e batizava mais discípulos do que João' },
      { v: 2, en: '(although Jesus himself didn’t baptize, but his disciples),', pt: '(ainda que Jesus mesmo não batizava, mas os seus discípulos)' },
      { v: 3, en: 'he left Judea, and departed into Galilee.', pt: 'deixou a Judéia, e foi outra vez para a Galiléia.' },
      { v: 4, en: 'He needed to pass through Samaria.', pt: 'E era-lhe necessário passar por Samária.' },
      { v: 5, en: 'So he came to a city of Samaria, called Sychar, near the parcel of ground that Jacob gave to his son, Joseph.', pt: 'Chegou, pois, a uma cidade de Samária, chamada Sicar, junto da herdade que Jacó dera a seu filho José;' },
      { v: 6, en: 'Jacob’s well was there. Jesus therefore, being tired from his journey, sat down by the well. It was about the sixth hour.', pt: 'achava-se ali o poço de Jacó. Jesus, pois, cansado da viagem, sentou-se assim junto do poço; era cerca da hora sexta.' },
      { v: 7, en: 'A woman of Samaria came to draw water. Jesus said to her, “Give me a drink.”', pt: 'Veio uma mulher de Samária tirar água. Disse-lhe Jesus: Dá- me de beber.' },
      { v: 8, en: 'For his disciples had gone away into the city to buy food.', pt: 'Pois seus discípulos tinham ido à cidade comprar comida.' },
      { v: 9, en: 'The Samaritan woman therefore said to him, “How is it that you, being a Jew, ask for a drink from me, a Samaritan woman?” (For Jews have no dealings with Samaritans.)', pt: 'Disse-lhe então a mulher samaritana: Como, sendo tu judeu, me pedes de beber a mim, que sou mulher samaritana? (Porque os judeus não se comunicavam com os samaritanos.)' },
      { v: 10, en: 'Jesus answered her, “If you knew the gift of God, and who it is who says to you, ‘Give me a drink,’ you would have asked him, and he would have given you living water.”', pt: 'Respondeu-lhe Jesus: Se tivesses conhecido o dom de Deus e quem é o que te diz: Dá-me de beber, tu lhe terias pedido e ele te haveria dado água viva.' },
      { v: 11, en: 'The woman said to him, “Sir, you have nothing to draw with, and the well is deep. So where do you get that living water?', pt: 'Disse-lhe a mulher: Senhor, tu não tens com que tirá-la, e o poço é fundo; donde, pois, tens essa água viva?' },
      { v: 12, en: 'Are you greater than our father, Jacob, who gave us the well, and drank of it himself, as did his children, and his livestock?”', pt: 'És tu, porventura, maior do que o nosso pai Jacó, que nos deu o poço, do qual também ele mesmo bebeu, e os filhos, e o seu gado?.' },
      { v: 13, en: 'Jesus answered her, “Everyone who drinks of this water will thirst again,', pt: 'Replicou-lhe Jesus: Todo o que beber desta água tornará a ter sede;' },
      { v: 14, en: 'but whoever drinks of the water that I will give him will never thirst again; but the water that I will give him will become in him a well of water springing up to eternal life.”', pt: 'mas aquele que beber da água que eu lhe der nunca terá sede; pelo contrário, a água que eu lhe der se fará nele uma fonte de água que jorre para a vida eterna.' },
      { v: 15, en: 'The woman said to him, “Sir, give me this water, so that I don’t get thirsty, neither come all the way here to draw.”', pt: 'Disse-lhe a mulher: Senhor, dá-me dessa água, para que não mais tenha sede, nem venha aqui tirá-la.' },
      { v: 16, en: 'Jesus said to her, “Go, call your husband, and come here.”', pt: 'Disse-lhe Jesus: Vai, chama o teu marido e vem cá.' },
      { v: 17, en: 'The woman answered, “I have no husband.” Jesus said to her, “You said well, ‘I have no husband,’', pt: 'Respondeu a mulher: Não tenho marido. Disse-lhe Jesus: Disseste bem: Não tenho marido;' },
      { v: 18, en: 'for you have had five husbands; and he whom you now have is not your husband. This you have said truly.”', pt: 'porque cinco maridos tiveste, e o que agora tens não é teu marido; isso disseste com verdade.' },
      { v: 19, en: 'The woman said to him, “Sir, I perceive that you are a prophet.', pt: 'Disse-lhe a mulher: Senhor, vejo que és profeta.' },
      { v: 20, en: 'Our fathers worshiped in this mountain, and you Jews say that in Jerusalem is the place where people ought to worship.”', pt: 'Nossos pais adoraram neste monte, e vós dizeis que em Jerusalém é o lugar onde se deve adorar.' },
      { v: 21, en: 'Jesus said to her, “Woman, believe me, the hour comes, when neither in this mountain, nor in Jerusalem, will you worship the Father.', pt: 'Disse-lhe Jesus: Mulher, crê-me, a hora vem, em que nem neste monte, nem em Jerusalém adorareis o Pai.' },
      { v: 22, en: 'You worship that which you don’t know. We worship that which we know; for salvation is from the Jews.', pt: 'Vós adorais o que não conheceis; nós adoramos o que conhecemos; porque a salvação vem dos judeus.' },
      { v: 23, en: 'But the hour comes, and now is, when the true worshipers will worship the Father in spirit and truth, for the Father seeks such to be his worshipers.', pt: 'Mas a hora vem, e agora é, em que os verdadeiros adoradores adorarão o Pai em espírito e em verdade; porque o Pai procura a tais que assim o adorem.' },
      { v: 24, en: 'God is spirit, and those who worship him must worship in spirit and truth.”', pt: 'Deus é Espírito, e é necessário que os que o adoram o adorem em espírito e em verdade.' },
      { v: 25, en: 'The woman said to him, “I know that Messiah comes, he who is called Christ. When he has come, he will declare to us all things.”', pt: 'Replicou-lhe a mulher: Eu sei que vem o Messias (que se chama o Cristo); quando ele vier há de nos anunciar todas as coisas.' },
      { v: 26, en: 'Jesus said to her, “I am he, the one who speaks to you.”', pt: 'Disse-lhe Jesus: Eu o sou, eu que falo contigo.' },
      { v: 27, en: 'At this, his disciples came. They marveled that he was speaking with a woman; yet no one said, “What are you looking for?” or, “Why do you speak with her?”', pt: 'E nisto vieram os seus discípulos, e se admiravam de que estivesse falando com uma mulher; todavia nenhum lhe perguntou: Que é que procuras? ou: Por que falas com ela?' },
      { v: 28, en: 'So the woman left her water pot, and went away into the city, and said to the people,', pt: 'Deixou, pois, a mulher o seu cântaro, foi à cidade e disse àqueles homens:' },
      { v: 29, en: '“Come, see a man who told me everything that I did. Can this be the Christ?”', pt: 'Vinde, vede um homem que me disse tudo quanto eu tenho feito; será este, porventura, o Cristo?' },
      { v: 30, en: 'They went out of the city, and were coming to him.', pt: 'Saíram, pois, da cidade e vinham ter com ele.' },
      { v: 31, en: 'In the meanwhile, the disciples urged him, saying, “Rabbi, eat.”', pt: 'Entrementes os seus discípulos lhe rogavam, dizendo: Rabi, come.' },
      { v: 32, en: 'But he said to them, “I have food to eat that you don’t know about.”', pt: 'Ele, porém, respondeu: Uma comida tenho para comer que vós não conheceis.' },
      { v: 33, en: 'The disciples therefore said to one another, “Has anyone brought him something to eat?”', pt: 'Então os discípulos diziam uns aos outros: Acaso alguém lhe trouxe de comer?' },
      { v: 34, en: 'Jesus said to them, “My food is to do the will of him who sent me, and to accomplish his work.', pt: 'Disse-lhes Jesus: A minha comida é fazer a vontade daquele que me enviou, e completar a sua obra.' },
      { v: 35, en: 'Don’t you say, ‘There are yet four months until the harvest?’ Behold, I tell you, lift up your eyes, and look at the fields, that they are white for harvest already.', pt: 'Não dizeis vós: Ainda há quatro meses até que venha a ceifa? Ora, eu vos digo: levantai os vossos olhos, e vede os campos, que já estão brancos para a ceifa.' },
      { v: 36, en: 'He who reaps receives wages, and gathers fruit to eternal life; that both he who sows and he who reaps may rejoice together.', pt: 'Quem ceifa já está recebendo recompensa e ajuntando fruto para a vida eterna; para que o que semeia e o que ceifa juntamente se regozijem.' },
      { v: 37, en: 'For in this the saying is true, ‘One sows, and another reaps.’', pt: 'Porque nisto é verdadeiro o ditado: Um é o que semeia, e outro o que ceifa.' },
      { v: 38, en: 'I sent you to reap that for which you haven’t labored. Others have labored, and you have entered into their labor.”', pt: 'Eu vos enviei a ceifar onde não trabalhaste; outros trabalharam, e vós entrastes no seu trabalho.' },
      { v: 39, en: 'From that city many of the Samaritans believed in him because of the word of the woman, who testified, “He told me everything that I did.”', pt: 'E muitos samaritanos daquela cidade creram nele, por causa da palavra da mulher, que testificava: Ele me disse tudo quanto tenho feito.' },
      { v: 40, en: 'So when the Samaritans came to him, they begged him to stay with them. He stayed there two days.', pt: 'Indo, pois, ter com ele os samaritanos, rogaram-lhe que ficasse com eles; e ficou ali dois dias.' },
      { v: 41, en: 'Many more believed because of his word.', pt: 'E muitos mais creram por causa da palavra dele;' },
      { v: 42, en: 'They said to the woman, “Now we believe, not because of your speaking; for we have heard for ourselves, and know that this is indeed the Christ, the Savior of the world.”', pt: 'e diziam à mulher: Já não é pela tua palavra que nós cremos; pois agora nós mesmos temos ouvido e sabemos que este é verdadeiramente o Salvador do mundo.' },
      { v: 43, en: 'After the two days he went out from there and went into Galilee.', pt: 'Passados os dois dias partiu dali para a Galiléia.' },
      { v: 44, en: 'For Jesus himself testified that a prophet has no honor in his own country.', pt: 'Porque Jesus mesmo testificou que um profeta não recebe honra na sua própria pátria.' },
      { v: 45, en: 'So when he came into Galilee, the Galileans received him, having seen all the things that he did in Jerusalem at the feast, for they also went to the feast.', pt: 'Assim, pois, que chegou à Galiléia, os galileus o receberam, porque tinham visto todas as coisas que fizera em Jerusalém na ocasião da festa; pois também eles tinham ido à festa.' },
      { v: 46, en: 'Jesus came therefore again to Cana of Galilee, where he made the water into wine. There was a certain nobleman whose son was sick at Capernaum.', pt: 'Foi, então, outra vez a Caná da Galiléia, onde da água fizera vinho. Ora, havia um oficial do rei, cujo filho estava enfermo em Cafarnaum.' },
      { v: 47, en: 'When he heard that Jesus had come out of Judea into Galilee, he went to him, and begged him that he would come down and heal his son, for he was at the point of death.', pt: 'Quando ele soube que Jesus tinha vindo da Judéia para a Galiléia, foi ter com ele, e lhe rogou que descesse e lhe curasse o filho; pois estava à morte.' },
      { v: 48, en: 'Jesus therefore said to him, “Unless you see signs and wonders, you will in no way believe.”', pt: 'Então Jesus lhe disse: Se não virdes sinais e prodígios, de modo algum crereis.' },
      { v: 49, en: 'The nobleman said to him, “Sir, come down before my child dies.”', pt: 'Rogou-lhe o oficial: Senhor, desce antes que meu filho morra.' },
      { v: 50, en: 'Jesus said to him, “Go your way. Your son lives.” The man believed the word that Jesus spoke to him, and he went his way.', pt: 'Respondeu-lhe Jesus: Vai, o teu filho vive. E o homem creu na palavra que Jesus lhe dissera, e partiu.' },
      { v: 51, en: 'As he was now going down, his servants met him and reported, saying “Your child lives!”', pt: 'Quando ele já ia descendo, saíram-lhe ao encontro os seus servos, e lhe disseram que seu filho vivia.' },
      { v: 52, en: 'So he inquired of them the hour when he began to get better. They said therefore to him, “Yesterday at the seventh hour, the fever left him.”', pt: 'Perguntou-lhes, pois, a que hora começara a melhorar; ao que lhe disseram: Ontem à hora sétima a febre o deixou.' },
      { v: 53, en: 'So the father knew that it was at that hour in which Jesus said to him, “Your son lives.” He believed, as did his whole house.', pt: 'Reconheceu, pois, o pai ser aquela hora a mesma em que Jesus lhe dissera: O teu filho vive; e creu ele e toda a sua casa.' },
      { v: 54, en: 'This is again the second sign that Jesus did, having come out of Judea into Galilee.', pt: 'Foi esta a segunda vez que Jesus, ao voltar da Judéia para a Galiléia, ali operou sinal.' },
    ],
    5: [
      { v: 1, en: 'After these things, there was a feast of the Jews, and Jesus went up to Jerusalem.', pt: 'Depois disso havia uma festa dos judeus; e Jesus subiu a Jerusalém.' },
      { v: 2, en: 'Now in Jerusalem by the sheep gate, there is a pool, which is called in Hebrew, “Bethesda”, having five porches.', pt: 'Ora, em Jerusalém, próximo à porta das ovelhas, há um tanque, chamado em hebraico Betesda, o qual tem cinco alpendres.' },
      { v: 3, en: 'In these lay a great multitude of those who were sick, blind, lame, or paralyzed, waiting for the moving of the water;', pt: 'Nestes jazia grande multidão de enfermos, cegos, mancos e ressicados [esperando o movimento da água.]' },
      { v: 4, en: 'for an angel went down at certain times into the pool, and stirred up the water. Whoever stepped in first after the stirring of the water was healed of whatever disease he had.', pt: '[Porquanto um anjo descia em certo tempo ao tanque, e agitava a água; então o primeiro que ali descia, depois do movimento da água, sarava de qualquer enfermidade que tivesse.]' },
      { v: 5, en: 'A certain man was there, who had been sick for thirty-eight years.', pt: 'Achava-se ali um homem que, havia trinta e oito anos, estava enfermo.' },
      { v: 6, en: 'When Jesus saw him lying there, and knew that he had been sick for a long time, he asked him, “Do you want to be made well?”', pt: 'Jesus, vendo-o deitado e sabendo que estava assim havia muito tempo, perguntou-lhe: Queres ficar são?' },
      { v: 7, en: 'The sick man answered him, “Sir, I have no one to put me into the pool when the water is stirred up, but while I’m coming, another steps down before me.”', pt: 'Respondeu-lhe o enfermo: Senhor, não tenho ninguém que, ao ser agitada a água, me ponha no tanque; assim, enquanto eu vou, desce outro antes de mim.' },
      { v: 8, en: 'Jesus said to him, “Arise, take up your mat, and walk.”', pt: 'Disse-lhe Jesus: Levanta-te, toma o teu leito e anda.' },
      { v: 9, en: 'Immediately, the man was made well, and took up his mat and walked. Now it was the Sabbath on that day.', pt: 'Imediatamente o homem ficou são; e, tomando o seu leito, começou a andar. Ora, aquele dia era sábado.' },
      { v: 10, en: 'So the Jews said to him who was cured, “It is the Sabbath. It is not lawful for you to carry the mat.”', pt: 'Pelo que disseram os judeus ao que fora curado: Hoje é sábado, e não te é lícito carregar o leito.' },
      { v: 11, en: 'He answered them, “He who made me well, the same said to me, ‘Take up your mat, and walk.’ ”', pt: 'Ele, porém, lhes respondeu: Aquele que me curou, esse mesmo me disse: Toma o teu leito e anda.' },
      { v: 12, en: 'Then they asked him, “Who is the man who said to you, ‘Take up your mat, and walk’ ?”', pt: 'Perguntaram-lhe, pois: Quem é o homem que te disse: Toma o teu leito e anda?' },
      { v: 13, en: 'But he who was healed didn’t know who it was, for Jesus had withdrawn, a crowd being in the place.', pt: 'Mas o que fora curado não sabia quem era; porque Jesus se retirara, por haver muita gente naquele lugar.' },
      { v: 14, en: 'Afterward Jesus found him in the temple, and said to him, “Behold, you are made well. Sin no more, so that nothing worse happens to you.”', pt: 'Depois Jesus o encontrou no templo, e disse-lhe: Olha, já estás curado; não peques mais, para que não te suceda coisa pior.' },
      { v: 15, en: 'The man went away, and told the Jews that it was Jesus who had made him well.', pt: 'Retirou-se, então, o homem, e contou aos judeus que era Jesus quem o curara.' },
      { v: 16, en: 'For this cause the Jews persecuted Jesus, and sought to kill him, because he did these things on the Sabbath.', pt: 'Por isso os judeus perseguiram a Jesus, porque fazia estas coisas no sábado.' },
      { v: 17, en: 'But Jesus answered them, “My Father is still working, so I am working, too.”', pt: 'Mas Jesus lhes respondeu: Meu Pai trabalha até agora, e eu trabalho também.' },
      { v: 18, en: 'For this cause therefore the Jews sought all the more to kill him, because he not only broke the Sabbath, but also called God his own Father, making himself equal with God.', pt: 'Por isso, pois, os judeus ainda mais procuravam matá-lo, porque não só violava o sábado, mas também dizia que Deus era seu próprio Pai, fazendo-se igual a Deus.' },
      { v: 19, en: 'Jesus therefore answered them, “Most certainly, I tell you, the Son can do nothing of himself, but what he sees the Father doing. For whatever things he does, these the Son also does likewise.', pt: 'Disse-lhes, pois, Jesus: Em verdade, em verdade vos digo que o Filho de si mesmo nada pode fazer, senão o que vir o Pai fazer; porque tudo quanto ele faz, o Filho o faz igualmente.' },
      { v: 20, en: 'For the Father has affection for the Son, and shows him all things that he himself does. He will show him greater works than these, that you may marvel.', pt: 'Porque o Pai ama ao Filho, e mostra-lhe tudo o que ele mesmo faz; e maiores obras do que estas lhe mostrará, para que vos maravilheis.' },
      { v: 21, en: 'For as the Father raises the dead and gives them life, even so the Son also gives life to whom he desires.', pt: 'Pois, assim como o Pai levanta os mortos e lhes dá vida, assim também o Filho dá vida a quem ele quer.' },
      { v: 22, en: 'For the Father judges no one, but he has given all judgment to the Son,', pt: 'Porque o Pai a niguém julga, mas deu ao Filho todo o julgamento,' },
      { v: 23, en: 'that all may honor the Son, even as they honor the Father. He who doesn’t honor the Son doesn’t honor the Father who sent him.', pt: 'para que todos honrem o Filho, assim como honram o Pai. Quem não honra o Filho, não honra o Pai que o enviou.' },
      { v: 24, en: '“Most certainly I tell you, he who hears my word, and believes him who sent me, has eternal life, and doesn’t come into judgment, but has passed out of death into life.', pt: 'Em verdade, em verdade vos digo que quem ouve a minha palavra, e crê naquele que me enviou, tem a vida eterna e não entra em juízo, mas já passou da morte para a vida.' },
      { v: 25, en: 'Most certainly, I tell you, the hour comes, and now is, when the dead will hear the Son of God’s voice; and those who hear will live.', pt: 'Em verdade, em verdade vos digo que vem a hora, e agora é, em que os mortos ouvirão a voz do Filho de Deus, e os que a ouvirem viverão.' },
      { v: 26, en: 'For as the Father has life in himself, even so he gave to the Son also to have life in himself.', pt: 'Pois assim como o Pai tem vida em si mesmo, assim também deu ao Filho ter vida em si mesmos;' },
      { v: 27, en: 'He also gave him authority to execute judgment, because he is a son of man.', pt: 'e deu-lhe autoridade para julgar, porque é o Filho do homem.' },
      { v: 28, en: 'Don’t marvel at this, for the hour comes, in which all that are in the tombs will hear his voice,', pt: 'Não vos admireis disso, porque vem a hora em que todos os que estão nos sepulcros ouvirão a sua voz e sairão:' },
      { v: 29, en: 'and will come out; those who have done good, to the resurrection of life; and those who have done evil, to the resurrection of judgment.', pt: 'os que tiverem feito o bem, para a ressurreição da vida, e os que tiverem praticado o mal, para a ressurreição do juízo.' },
      { v: 30, en: 'I can of myself do nothing. As I hear, I judge, and my judgment is righteous; because I don’t seek my own will, but the will of my Father who sent me.', pt: 'Eu não posso de mim mesmo fazer coisa alguma; como ouço, assim julgo; e o meu juízo é justo, porque não procuro a minha vontade, mas a vontade daquele que me enviou.' },
      { v: 31, en: '“If I testify about myself, my witness is not valid.', pt: 'Se eu der testemunho de mim mesmo, o meu testemunho não é verdadeiro.' },
      { v: 32, en: 'It is another who testifies about me. I know that the testimony which he testifies about me is true.', pt: 'Outro é quem dá testemunho de mim; e sei que o testemunho que ele dá de mim é verdadeiro.' },
      { v: 33, en: 'You have sent to John, and he has testified to the truth.', pt: 'Vós mandastes mensageiros a João, e ele deu testemunho da verdade;' },
      { v: 34, en: 'But the testimony which I receive is not from man. However, I say these things that you may be saved.', pt: 'eu, porém, não recebo testemunho de homem; mas digo isto para que sejais salvos.' },
      { v: 35, en: 'He was the burning and shining lamp, and you were willing to rejoice for a while in his light.', pt: 'Ele era a lâmpada que ardia e alumiava; e vós quisestes alegrar-vos por um pouco de tempo com a sua luz.' },
      { v: 36, en: 'But the testimony which I have is greater than that of John, for the works which the Father gave me to accomplish, the very works that I do, testify about me, that the Father has sent me.', pt: 'Mas o testemunho que eu tenho é maior do que o de João; porque as obras que o Pai me deu para realizar, as mesmas obras que faço dão testemunho de mim que o Pai me enviou.' },
      { v: 37, en: 'The Father himself, who sent me, has testified about me. You have neither heard his voice at any time, nor seen his form.', pt: 'E o Pai que me enviou, ele mesmo tem dado testemunho de mim. Vós nunca ouvistes a sua voz, nem vistes a sua forma;' },
      { v: 38, en: 'You don’t have his word living in you; because you don’t believe him whom he sent.', pt: 'e a sua palavra não permanece em vós; porque não credes naquele que ele enviou.' },
      { v: 39, en: '“You search the Scriptures, because you think that in them you have eternal life; and these are they which testify about me.', pt: 'Examinais as Escrituras, porque julgais ter nelas a vida eterna; e são elas que dão testemunho de mim;' },
      { v: 40, en: 'Yet you will not come to me, that you may have life.', pt: 'mas não quereis vir a mim para terdes vida!' },
      { v: 41, en: 'I don’t receive glory from men.', pt: 'Eu não recebo glória da parte dos homens;' },
      { v: 42, en: 'But I know you, that you don’t have God’s love in yourselves.', pt: 'mas bem vos conheço, que não tendes em vós o amor de Deus.' },
      { v: 43, en: 'I have come in my Father’s name, and you don’t receive me. If another comes in his own name, you will receive him.', pt: 'Eu vim em nome de meu Pai, e não me recebeis; se outro vier em seu próprio nome, a esse recebereis.' },
      { v: 44, en: 'How can you believe, who receive glory from one another, and you don’t seek the glory that comes from the only God?', pt: 'Como podeis crer, vós que recebeis glória uns dos outros e não buscais a glória que vem do único Deus?' },
      { v: 45, en: '“Don’t think that I will accuse you to the Father. There is one who accuses you, even Moses, on whom you have set your hope.', pt: 'Não penseis que eu vos hei de acusar perante o Pai. Há um que vos acusa, Moisés, em quem vós esperais.' },
      { v: 46, en: 'For if you believed Moses, you would believe me; for he wrote about me.', pt: 'Pois se crêsseis em Moisés, creríeis em mim; porque de mim ele escreveu.' },
      { v: 47, en: 'But if you don’t believe his writings, how will you believe my words?”', pt: 'Mas, se não credes nos escritos, como crereis nas minhas palavras?' },
    ],
    6: [
      { v: 1, en: 'After these things, Jesus went away to the other side of the sea of Galilee, which is also called the Sea of Tiberias.', pt: 'Depois disto partiu Jesus para o outro lado do mar da Galiléia, também chamado de Tiberíades.' },
      { v: 2, en: 'A great multitude followed him, because they saw his signs which he did on those who were sick.', pt: 'E seguia-o uma grande multidão, porque via os sinais que operava sobre os enfermos.' },
      { v: 3, en: 'Jesus went up into the mountain, and he sat there with his disciples.', pt: 'Subiu, pois, Jesus ao monte e sentou-se ali com seus discípulos.' },
      { v: 4, en: 'Now the Passover, the feast of the Jews, was at hand.', pt: 'Ora, a páscoa, a festa dos judeus, estava próxima.' },
      { v: 5, en: 'Jesus therefore lifting up his eyes, and seeing that a great multitude was coming to him, said to Philip, “Where are we to buy bread, that these may eat?”', pt: 'Então Jesus, levantando os olhos, e vendo que uma grande multidão vinha ter com ele, disse a Felipe: Onde compraremos pão, para estes comerem?' },
      { v: 6, en: 'This he said to test him, for he himself knew what he would do.', pt: 'Mas dizia isto para o experimentar; pois ele bem sabia o que ia fazer.' },
      { v: 7, en: 'Philip answered him, “Two hundred denarii worth of bread is not sufficient for them, that everyone of them may receive a little.”', pt: 'Respondeu-lhe Felipe: Duzentos denários de pão não lhes bastam, para que cada um receba um pouco.' },
      { v: 8, en: 'One of his disciples, Andrew, Simon Peter’s brother, said to him,', pt: 'Ao que lhe disse um dos seus discípulos, André, irmão de Simão Pedro:' },
      { v: 9, en: '“There is a boy here who has five barley loaves and two fish, but what are these among so many?”', pt: 'Está aqui um rapaz que tem cinco pães de cevada e dois peixinhos; mas que é isto para tantos?' },
      { v: 10, en: 'Jesus said, “Have the people sit down.” Now there was much grass in that place. So the men sat down, in number about five thousand.', pt: 'Disse Jesus: Fazei reclinar-se o povo. Ora, naquele lugar havia muita relva. Reclinaram-se aí, pois, os homens em número de quase cinco mil.' },
      { v: 11, en: 'Jesus took the loaves; and having given thanks, he distributed to the disciples, and the disciples to those who were sitting down; likewise also of the fish as much as they desired.', pt: 'Jesus, então, tomou os pães e, havendo dado graças, repartiu-os pelos que estavam reclinados; e de igual modo os peixes, quanto eles queriam.' },
      { v: 12, en: 'When they were filled, he said to his disciples, “Gather up the broken pieces which are left over, that nothing be lost.”', pt: 'E quando estavam saciados, disse aos seus discípulos: Recolhei os pedaços que sobejaram, para que nada se perca.' },
      { v: 13, en: 'So they gathered them up, and filled twelve baskets with broken pieces from the five barley loaves, which were left over by those who had eaten.', pt: 'Recolheram-nos, pois e encheram doze cestos de pedaços dos cinco pães de cevada, que sobejaram aos que haviam comido.' },
      { v: 14, en: 'When therefore the people saw the sign which Jesus did, they said, “This is truly the prophet who comes into the world.”', pt: 'Vendo, pois, aqueles homens o sinal que Jesus operara, diziam: este é verdadeiramente o profeta que havia de vir ao mundo.' },
      { v: 15, en: 'Jesus therefore, perceiving that they were about to come and take him by force, to make him king, withdrew again to the mountain by himself.', pt: 'Percebendo, pois, Jesus que estavam prestes a vir e levá-lo à força para o fazerem rei, tornou a retirar-se para o monte, ele sozinho.' },
      { v: 16, en: 'When evening came, his disciples went down to the sea,', pt: 'Ao cair da tarde, desceram os seus discípulos ao mar;' },
      { v: 17, en: 'and they entered into the boat, and were going over the sea to Capernaum. It was now dark, and Jesus had not come to them.', pt: 'e, entrando num barco, atravessavam o mar em direção a Cafarnaum; enquanto isso, escurecera e Jesus ainda não tinha vindo ter com eles;' },
      { v: 18, en: 'The sea was tossed by a great wind blowing.', pt: 'ademais, o mar se empolava, porque soprava forte vento.' },
      { v: 19, en: 'When therefore they had rowed about twenty-five or thirty stadia, they saw Jesus walking on the sea, and drawing near to the boat; and they were afraid.', pt: 'Tendo, pois, remado uns vinte e cinco ou trinta estádios, viram a Jesus andando sobre o mar e aproximando-se do barco; e ficaram atemorizados.' },
      { v: 20, en: 'But he said to them, “It is I. Don’t be afraid.”', pt: 'Mas ele lhes disse: Sou eu; não temais.' },
      { v: 21, en: 'They were willing therefore to receive him into the boat. Immediately the boat was at the land where they were going.', pt: 'Então eles de boa mente o receberam no barco; e logo o barco chegou à terra para onde iam.' },
      { v: 22, en: 'On the next day, the multitude that stood on the other side of the sea saw that there was no other boat there, except the one in which his disciples had embarked, and that Jesus hadn’t entered with his disciples into the boat, but his disciples had gone away alone.', pt: 'No dia seguinte, a multidão que ficara no outro lado do mar, sabendo que não houvera ali senão um barquinho, e que Jesus não embarcara nele com seus discípulos, mas que estes tinham ido sós' },
      { v: 23, en: 'However boats from Tiberias came near to the place where they ate the bread after the Lord had given thanks.', pt: '(contudo, outros barquinhos haviam chegado a Tiberíades para perto do lugar onde comeram o pão, havendo o Senhor dado graças);' },
      { v: 24, en: 'When the multitude therefore saw that Jesus wasn’t there, nor his disciples, they themselves got into the boats, and came to Capernaum, seeking Jesus.', pt: 'quando, pois, viram que Jesus não estava ali nem os seus discípulos, entraram eles também nos barcos, e foram a Cafarnaum, em busca de Jesus.' },
      { v: 25, en: 'When they found him on the other side of the sea, they asked him, “Rabbi, when did you come here?”', pt: 'E, achando-o no outro lado do mar, perguntaram-lhe: Rabi, quando chegaste aqui?' },
      { v: 26, en: 'Jesus answered them, “Most certainly I tell you, you seek me, not because you saw signs, but because you ate of the loaves, and were filled.', pt: 'Respondeu-lhes Jesus: Em verdade, em verdade vos digo que me buscais, não porque vistes sinais, mas porque comestes do pão e vos saciastes.' },
      { v: 27, en: 'Don’t work for the food which perishes, but for the food which remains to eternal life, which the Son of Man will give to you. For God the Father has sealed him.”', pt: 'Trabalhai, não pela comida que perece, mas pela comida que permanece para a vida eterna, a qual o Filho do homem vos dará; pois neste, Deus, o Pai, imprimiu o seu selo.' },
      { v: 28, en: 'They said therefore to him, “What must we do, that we may work the works of God?”', pt: 'Pergutaram-lhe, pois: Que havemos de fazer para praticarmos as obras de Deus?' },
      { v: 29, en: 'Jesus answered them, “This is the work of God, that you believe in him whom he has sent.”', pt: 'Jesus lhes respondeu: A obra de Deus é esta: Que creiais naquele que ele enviou.' },
      { v: 30, en: 'They said therefore to him, “What then do you do for a sign, that we may see, and believe you? What work do you do?', pt: 'Perguntaram-lhe, então: Que sinal, pois, fazes tu, para que o vejamos e te creiamos? Que operas tu?' },
      { v: 31, en: 'Our fathers ate the manna in the wilderness. As it is written, ‘He gave them bread out of heaven to eat.’”', pt: 'Nossos pais comeram o maná no deserto, como está escrito: Do céu deu-lhes pão a comer.' },
      { v: 32, en: 'Jesus therefore said to them, “Most certainly, I tell you, it wasn’t Moses who gave you the bread out of heaven, but my Father gives you the true bread out of heaven.', pt: 'Respondeu-lhes Jesus: Em verdade, em verdade vos digo: Não foi Moisés que vos deu o pão do céu; mas meu Pai vos dá o verdadeiro pão do céu.' },
      { v: 33, en: 'For the bread of God is that which comes down out of heaven, and gives life to the world.”', pt: 'Porque o pão de Deus é aquele que desce do céu e dá vida ao mundo.' },
      { v: 34, en: 'They said therefore to him, “Lord, always give us this bread.”', pt: 'Disseram-lhe, pois: Senhor, dá-nos sempre desse pão.' },
      { v: 35, en: 'Jesus said to them, “I am the bread of life. He who comes to me will not be hungry, and he who believes in me will never be thirsty.', pt: 'Declarou-lhes Jesus. Eu sou o pão da vida; aquele que vem a mim, de modo algum terá fome, e quem crê em mim jamais tará sede.' },
      { v: 36, en: 'But I told you that you have seen me, and yet you don’t believe.', pt: 'Mas como já vos disse, vós me tendes visto, e contudo não credes.' },
      { v: 37, en: 'All those whom the Father gives me will come to me. He who comes to me I will in no way throw out.', pt: 'Todo o que o Pai me dá virá a mim; e o que vem a mim de maneira nenhuma o lançarei fora.' },
      { v: 38, en: 'For I have come down from heaven, not to do my own will, but the will of him who sent me.', pt: 'Porque eu desci do céu, não para fazer a minha vontade, mas a vontade daquele que me enviou.' },
      { v: 39, en: 'This is the will of my Father who sent me, that of all he has given to me I should lose nothing, but should raise him up at the last day.', pt: 'E a vontade do que me enviou é esta: Que eu não perca nenhum de todos aqueles que me deu, mas que eu o ressuscite no último dia.' },
      { v: 40, en: 'This is the will of the one who sent me, that everyone who sees the Son, and believes in him, should have eternal life; and I will raise him up at the last day.”', pt: 'Porquanto esta é a vontade de meu Pai: Que todo aquele que vê o Filho e crê nele, tenha a vida eterna; e eu o ressuscitarei no último dia.' },
      { v: 41, en: 'The Jews therefore murmured concerning him, because he said, “I am the bread which came down out of heaven.”', pt: 'Murmuravam, pois, dele os judeus, porque dissera: Eu sou o pão que desceu do céu;' },
      { v: 42, en: 'They said, “Isn’t this Jesus, the son of Joseph, whose father and mother we know? How then does he say, ‘I have come down out of heaven?’”', pt: 'e perguntavam: Não é Jesus, o filho de José, cujo pai e mãe nós conhecemos? Como, pois, diz agora: Desci do céu?' },
      { v: 43, en: 'Therefore Jesus answered them, “Don’t murmur among yourselves.', pt: 'Respondeu-lhes Jesus: Não murmureis entre vós.' },
      { v: 44, en: 'No one can come to me unless the Father who sent me draws him, and I will raise him up in the last day.', pt: 'Ninguém pode vir a mim, se o Pai que me enviou não o trouxer; e eu o ressuscitarei no último dia.' },
      { v: 45, en: 'It is written in the prophets, ‘They will all be taught by God.’ Therefore everyone who hears from the Father, and has learned, comes to me.', pt: 'Está escrito nos profetas: E serão todos ensinados por Deus. Portanto todo aquele que do Pai ouviu e aprendeu vem a mim.' },
      { v: 46, en: 'Not that anyone has seen the Father, except he who is from God. He has seen the Father.', pt: 'Não que alguém tenha visto o Pai, senão aquele que é vindo de Deus; só ele tem visto o Pai.' },
      { v: 47, en: 'Most certainly, I tell you, he who believes in me has eternal life.', pt: 'Em verdade, em verdade vos digo: Aquele que crê tem a vida eterna.' },
      { v: 48, en: 'I am the bread of life.', pt: 'Eu sou o pão da vida.' },
      { v: 49, en: 'Your fathers ate the manna in the wilderness, and they died.', pt: 'Vossos pais comeram o maná no deserto e morreram.' },
      { v: 50, en: 'This is the bread which comes down out of heaven, that anyone may eat of it and not die.', pt: 'Este é o pão que desce do céu, para que o que dele comer não morra.' },
      { v: 51, en: 'I am the living bread which came down out of heaven. If anyone eats of this bread, he will live forever. Yes, the bread which I will give for the life of the world is my flesh.”', pt: 'Eu sou o pão vivo que desceu do céu; se alguém comer deste pão, viverá para sempre; e o pão que eu darei pela vida do mundo é a minha carne.' },
      { v: 52, en: 'The Jews therefore contended with one another, saying, “How can this man give us his flesh to eat?”', pt: 'Disputavam, pois, os judeus entre si, dizendo: Como pode este dar-nos a sua carne a comer?' },
      { v: 53, en: 'Jesus therefore said to them, “Most certainly I tell you, unless you eat the flesh of the Son of Man and drink his blood, you don’t have life in yourselves.', pt: 'Disse-lhes Jesus: Em verdade, em verdade vos digo: Se não comerdes a carne do Filho do homem, e não beberdes o seu sangue, não tereis vida em vós mesmos.' },
      { v: 54, en: 'He who eats my flesh and drinks my blood has eternal life, and I will raise him up at the last day.', pt: 'Quem come a minha carne e bebe o meu sangue tem a vida eterna; e eu o ressuscitarei no último dia.' },
      { v: 55, en: 'For my flesh is food indeed, and my blood is drink indeed.', pt: 'Porque a minha carne verdadeiramente é comida, e o meu sangue verdadeiramente é bebida.' },
      { v: 56, en: 'He who eats my flesh and drinks my blood lives in me, and I in him.', pt: 'Quem come a minha carne e bebe o meu sangue permanece em mim e eu nele.' },
      { v: 57, en: 'As the living Father sent me, and I live because of the Father; so he who feeds on me, he will also live because of me.', pt: 'Assim como o Pai, que vive, me enviou, e eu vivo pelo Pai, assim, quem de mim se alimenta, também viverá por mim.' },
      { v: 58, en: 'This is the bread which came down out of heaven—not as our fathers ate the manna, and died. He who eats this bread will live forever.”', pt: 'Este é o pão que desceu do céu; não é como o caso de vossos pais, que comeram o maná e morreram; quem comer este pão viverá para sempre.' },
      { v: 59, en: 'He said these things in the synagogue, as he taught in Capernaum.', pt: 'Estas coisas falou Jesus quando ensinava na sinagoga em Cafarnaum.' },
      { v: 60, en: 'Therefore many of his disciples, when they heard this, said, “This is a hard saying! Who can listen to it?”', pt: 'Muitos, pois, dos seus discípulos, ouvindo isto, disseram: Duro é este discurso; quem o pode ouvir?' },
      { v: 61, en: 'But Jesus knowing in himself that his disciples murmured at this, said to them, “Does this cause you to stumble?', pt: 'Mas, sabendo Jesus em si mesmo que murmuravam disto os seus discípulos, disse-lhes: Isto vos escandaliza?' },
      { v: 62, en: 'Then what if you would see the Son of Man ascending to where he was before?', pt: 'Que seria, pois, se vísseis subir o Filho do homem para onde primeiro estava?' },
      { v: 63, en: 'It is the spirit who gives life. The flesh profits nothing. The words that I speak to you are spirit, and are life.', pt: 'O espírito é o que vivifica, a carne para nada aproveita; as palavras que eu vos tenho dito são espírito e são vida.' },
      { v: 64, en: 'But there are some of you who don’t believe.” For Jesus knew from the beginning who they were who didn’t believe, and who it was who would betray him.', pt: 'Mas há alguns de vós que não crêem. Pois Jesus sabia, desde o princípio, quem eram os que não criam, e quem era o que o havia de entregar.' },
      { v: 65, en: 'He said, “For this cause I have said to you that no one can come to me, unless it is given to him by my Father.”', pt: 'E continuou: Por isso vos disse que ninguém pode vir a mim, se pelo Pai lhe não for concedido.' },
      { v: 66, en: 'At this, many of his disciples went back, and walked no more with him.', pt: 'Por causa disso muitos dos seus discípulos voltaram para trás e não andaram mais com ele.' },
      { v: 67, en: 'Jesus said therefore to the twelve, “You don’t also want to go away, do you?”', pt: 'Perguntou então Jesus aos doze: Quereis vós também retirar-vos?' },
      { v: 68, en: 'Simon Peter answered him, “Lord, to whom would we go? You have the words of eternal life.', pt: 'Respondeu-lhe Simão Pedro: Senhor, para quem iremos nós? Tu tens as palavras da vida eterna.' },
      { v: 69, en: 'We have come to believe and know that you are the Christ, the Son of the living God.”', pt: 'E nós já temos crido e bem sabemos que tu és o Santo de Deus.' },
      { v: 70, en: 'Jesus answered them, “Didn’t I choose you, the twelve, and one of you is a devil?”', pt: 'Respondeu-lhes Jesus: Não vos escolhi a vós os doze? Contudo um de vós é o diabo.' },
      { v: 71, en: 'Now he spoke of Judas, the son of Simon Iscariot, for it was he who would betray him, being one of the twelve.', pt: 'Referia-se a Judas, filho de Simão Iscariotes; porque era ele o que o havia de entregar, sendo um dos doze.' },
    ],
    7: [
      { v: 1, en: 'After these things, Jesus was walking in Galilee, for he wouldn’t walk in Judea, because the Jews sought to kill him.', pt: 'Depois disto andava Jesus pela Galiléia; pois não queria andar pela Judéia, porque os judeus procuravam matá-lo.' },
      { v: 2, en: 'Now the feast of the Jews, the Feast of Booths, was at hand.', pt: 'Ora, estava próxima a festa dos judeus, a dos tabernáculos.' },
      { v: 3, en: 'His brothers therefore said to him, “Depart from here, and go into Judea, that your disciples also may see your works which you do.', pt: 'Disseram-lhe, então, seus irmãos: Retira-te daqui e vai para a Judéia, para que também os teus discípulos vejam as obras que fazes.' },
      { v: 4, en: 'For no one does anything in secret, and himself seeks to be known openly. If you do these things, reveal yourself to the world.”', pt: 'Porque ninguém faz coisa alguma em oculto, quando procura ser conhecido. Já que fazes estas coisas, manifesta-te ao mundo.' },
      { v: 5, en: 'For even his brothers didn’t believe in him.', pt: 'Pois nem seus irmãos criam nele.' },
      { v: 6, en: 'Jesus therefore said to them, “My time has not yet come, but your time is always ready.', pt: 'Disse-lhes, então, Jesus: Ainda não é chegado o meu tempo; mas o vosso tempo sempre está presente.' },
      { v: 7, en: 'The world can’t hate you, but it hates me, because I testify about it, that its works are evil.', pt: 'O mundo não vos pode odiar; mas ele me odeia a mim, porquanto dele testifico que as suas obras são más.' },
      { v: 8, en: 'You go up to the feast. I am not yet going up to this feast, because my time is not yet fulfilled.”', pt: 'Subi vós à festa; eu não subo ainda a esta festa, porque ainda não é chegado o meu tempo.' },
      { v: 9, en: 'Having said these things to them, he stayed in Galilee.', pt: 'E, havendo-lhes dito isto, ficou na Galiléia.' },
      { v: 10, en: 'But when his brothers had gone up to the feast, then he also went up, not publicly, but as it were in secret.', pt: 'Mas quando seus irmãos já tinham subido à festa, então subiu ele também, não publicamente, mas como em secreto.' },
      { v: 11, en: 'The Jews therefore sought him at the feast, and said, “Where is he?”', pt: 'Ora, os judeus o procuravam na festa, e perguntavam: Onde está ele?' },
      { v: 12, en: 'There was much murmuring among the multitudes concerning him. Some said, “He is a good man.” Others said, “Not so, but he leads the multitude astray.”', pt: 'E era grande a murmuração a respeito dele entre as multidões. Diziam alguns: Ele é bom. Mas outros diziam: não, antes engana o povo.' },
      { v: 13, en: 'Yet no one spoke openly of him for fear of the Jews.', pt: 'Todavia ninguém falava dele abertamente, por medo dos judeus.' },
      { v: 14, en: 'But when it was now the middle of the feast, Jesus went up into the temple and taught.', pt: 'Estando, pois, a festa já em meio, subiu Jesus ao templo e começou a ensinar.' },
      { v: 15, en: 'The Jews therefore marveled, saying, “How does this man know letters, having never been educated?”', pt: 'Então os judeus se admiravam, dizendo: Como sabe este letras, sem ter estudado?' },
      { v: 16, en: 'Jesus therefore answered them, “My teaching is not mine, but his who sent me.', pt: 'Respondeu-lhes Jesus: A minha doutrina não é minha, mas daquele que me enviou.' },
      { v: 17, en: 'If anyone desires to do his will, he will know about the teaching, whether it is from God, or if I am speaking from myself.', pt: 'Se alguém quiser fazer a vontade de Deus, há de saber se a doutrina é dele, ou se eu falo por mim mesmo.' },
      { v: 18, en: 'He who speaks from himself seeks his own glory, but he who seeks the glory of him who sent him is true, and no unrighteousness is in him.', pt: 'Quem fala por si mesmo busca a sua própria glória; mas o que busca a glória daquele que o enviou, esse é verdadeiro, e não há nele injustiça.' },
      { v: 19, en: 'Didn’t Moses give you the law, and yet none of you keeps the law? Why do you seek to kill me?”', pt: 'Não vos deu Moisés a lei? no entanto nenhum de vós cumpre a lei. Por que procurais matar-me?' },
      { v: 20, en: 'The multitude answered, “You have a demon! Who seeks to kill you?”', pt: 'Respondeu a multidão: Tens demônio; quem procura matar-te?' },
      { v: 21, en: 'Jesus answered them, “I did one work, and you all marvel because of it.', pt: 'Replicou-lhes Jesus: Uma só obra fiz, e todos vós admirais por causa disto.' },
      { v: 22, en: 'Moses has given you circumcision (not that it is of Moses, but of the fathers), and on the Sabbath you circumcise a boy.', pt: 'Moisés vos ordenou a circuncisão (não que fosse de Moisés, mas dos pais), e no sábado circuncidais um homem.' },
      { v: 23, en: 'If a boy receives circumcision on the Sabbath, that the law of Moses may not be broken, are you angry with me, because I made a man completely healthy on the Sabbath?', pt: 'Ora, se um homem recebe a circuncisão no sábado, para que a lei de Moisés não seja violada, como vos indignais contra mim, porque no sábado tornei um homem inteiramente são?' },
      { v: 24, en: 'Don’t judge according to appearance, but judge righteous judgment.”', pt: 'Não julgueis pela aparência mas julgai segundo o reto juízo.' },
      { v: 25, en: 'Therefore some of them of Jerusalem said, “Isn’t this he whom they seek to kill?', pt: 'Diziam então alguns dos de Jerusalém: Não é este o que procuram matar?' },
      { v: 26, en: 'Behold, he speaks openly, and they say nothing to him. Can it be that the rulers indeed know that this is truly the Christ?', pt: 'E eis que ele está falando abertamente, e nada lhe dizem. Será que as autoridades realmente o reconhecem como o Cristo?' },
      { v: 27, en: 'However we know where this man comes from, but when the Christ comes, no one will know where he comes from.”', pt: 'Entretanto sabemos donde este é; mas, quando vier o Cristo, ninguém saberá donde ele é.' },
      { v: 28, en: 'Jesus therefore cried out in the temple, teaching and saying, “You both know me, and know where I am from. I have not come of myself, but he who sent me is true, whom you don’t know.', pt: 'Jesus, pois, levantou a voz no templo e ensinava, dizendo: Sim, vós me conheceis, e sabeis donde sou; contudo eu não vim de mim mesmo, mas aquele que me enviou é verdadeiro, o qual vós não conheceis.' },
      { v: 29, en: 'I know him, because I am from him, and he sent me.”', pt: 'Mas eu o conheço, porque dele venho, e ele me enviou.' },
      { v: 30, en: 'They sought therefore to take him; but no one laid a hand on him, because his hour had not yet come.', pt: 'Procuravam, pois, prendê-lo; mas ninguém lhe deitou as mãos, porque ainda não era chegada a sua hora.' },
      { v: 31, en: 'But of the multitude, many believed in him. They said, “When the Christ comes, he won’t do more signs than those which this man has done, will he?”', pt: 'Contudo muitos da multidão creram nele, e diziam: Será que o Cristo, quando vier, fará mais sinais do que este tem feito?' },
      { v: 32, en: 'The Pharisees heard the multitude murmuring these things concerning him, and the chief priests and the Pharisees sent officers to arrest him.', pt: 'Os fariseus ouviram a multidão murmurar estas coisas a respeito dele; e os principais sacerdotes e os fariseus mandaram guardas para o prenderem.' },
      { v: 33, en: 'Then Jesus said, “I will be with you a little while longer, then I go to him who sent me.', pt: 'Disse, pois, Jesus: Ainda um pouco de tempo estou convosco, e depois vou para aquele que me enviou.' },
      { v: 34, en: 'You will seek me, and won’t find me; and where I am, you can’t come.”', pt: 'Vós me buscareis, e não me achareis; e onde eu estou, vós não podeis vir.' },
      { v: 35, en: 'The Jews therefore said among themselves, “Where will this man go that we won’t find him? Will he go to the Dispersion among the Greeks, and teach the Greeks?', pt: 'Disseram, pois, os judeus uns aos outros: Para onde irá ele, que não o acharemos? Irá, porventura, à Dispersão entre os gregos, e ensinará os gregos?' },
      { v: 36, en: 'What is this word that he said, ‘You will seek me, and won’t find me; and where I am, you can’t come’ ?”', pt: 'Que palavra é esta que disse: Buscar-me-eis, e não me achareis; e, Onde eu estou, vós não podeis vir?' },
      { v: 37, en: 'Now on the last and greatest day of the feast, Jesus stood and cried out, “If anyone is thirsty, let him come to me and drink!', pt: 'Ora, no seu último dia, o grande dia da festa, Jesus pôs-se em pé e clamou, dizendo: Se alguém tem sede, venha a mim e beba.' },
      { v: 38, en: 'He who believes in me, as the Scripture has said, from within him will flow rivers of living water.”', pt: 'Quem crê em mim, como diz a Escritura, do seu interior correrão rios de água viva.' },
      { v: 39, en: 'But he said this about the Spirit, which those believing in him were to receive. For the Holy Spirit was not yet given, because Jesus wasn’t yet glorified.', pt: 'Ora, isto ele disse a respeito do Espírito que haviam de receber os que nele cressem; pois o Espírito ainda não fora dado, porque Jesus ainda não tinha sido glorificado.' },
      { v: 40, en: 'Many of the multitude therefore, when they heard these words, said, “This is truly the prophet.”', pt: 'Então alguns dentre o povo, ouvindo essas palavras, diziam: Verdadeiramente este é o profeta.' },
      { v: 41, en: 'Others said, “This is the Christ.” But some said, “What, does the Christ come out of Galilee?', pt: 'Outros diziam: Este é o Cristo; mas outros replicavam: Vem, pois, o Cristo da Galiléia?' },
      { v: 42, en: 'Hasn’t the Scripture said that the Christ comes of the offspring of David, and from Bethlehem, the village where David was?”', pt: 'Não diz a Escritura que o Cristo vem da descendência de Davi, e de Belém, a aldeia donde era Davi?' },
      { v: 43, en: 'So there arose a division in the multitude because of him.', pt: 'Assim houve uma dissensão entre o povo por causa dele.' },
      { v: 44, en: 'Some of them would have arrested him, but no one laid hands on him.', pt: 'Alguns deles queriam prendê-lo; mas ninguém lhe pôs as mãos.' },
      { v: 45, en: 'The officers therefore came to the chief priests and Pharisees, and they said to them, “Why didn’t you bring him?”', pt: 'Os guardas, pois, foram ter com os principais dos sacerdotes e fariseus, e estes lhes perguntaram: Por que não o trouxestes?' },
      { v: 46, en: 'The officers answered, “No man ever spoke like this man!”', pt: 'Responderam os guardas: Nunca homem algum falou assim como este homem.' },
      { v: 47, en: 'The Pharisees therefore answered them, “You aren’t also led astray, are you?', pt: 'Replicaram-lhes, pois, os fariseus: Também vós fostes enganados?' },
      { v: 48, en: 'Have any of the rulers believed in him, or of the Pharisees?', pt: 'Creu nele porventura alguma das autoridades, ou alguém dentre os fariseus?' },
      { v: 49, en: 'But this multitude that doesn’t know the law is accursed.”', pt: 'Mas esta multidão, que não sabe a lei, é maldita.' },
      { v: 50, en: 'Nicodemus (he who came to him by night, being one of them) said to them,', pt: 'Nicodemos, um deles, que antes fora ter com Jesus, perguntou-lhes:' },
      { v: 51, en: '“Does our law judge a man, unless it first hears from him personally and knows what he does?”', pt: 'A nossa lei, porventura, julga um homem sem primeiro ouvi-lo e ter conhecimento do que ele faz?' },
      { v: 52, en: 'They answered him, “Are you also from Galilee? Search, and see that no prophet has arisen out of Galilee.”', pt: 'Responderam-lhe eles: És tu também da Galiléia? Examina e vê que da Galiléia não surge profeta.' },
      { v: 53, en: 'Everyone went to his own house,', pt: '[E cada um foi para sua casa.' },
    ],
    8: [
      { v: 1, en: 'but Jesus went to the Mount of Olives.', pt: 'Mas Jesus foi para o Monte das Oliveiras.' },
      { v: 2, en: 'Now very early in the morning, he came again into the temple, and all the people came to him. He sat down, and taught them.', pt: 'Pela manhã cedo voltou ao templo, e todo o povo vinha ter com ele; e Jesus, sentando-se o ensinava.' },
      { v: 3, en: 'The scribes and the Pharisees brought a woman taken in adultery. Having set her in the middle,', pt: 'Então os escribas e fariseus trouxeram-lhe uma mulher apanhada em adultério; e pondo-a no meio,' },
      { v: 4, en: 'they told him, “Teacher, we found this woman in adultery, in the very act.', pt: 'disseram-lhe: Mestre, esta mulher foi apanhada em flagrante adultério.' },
      { v: 5, en: 'Now in our law, Moses commanded us to stone such women. What then do you say about her?”', pt: 'Ora, Moisés nos ordena na lei que as tais sejam apedrejadas. Tu, pois, que dizes?' },
      { v: 6, en: 'They said this testing him, that they might have something to accuse him of. But Jesus stooped down, and wrote on the ground with his finger.', pt: 'Isto diziam eles, tentando-o, para terem de que o acusar. Jesus, porém, inclinando-se, começou a escrever no chão com o dedo.' },
      { v: 7, en: 'But when they continued asking him, he looked up and said to them, “He who is without sin among you, let him throw the first stone at her.”', pt: 'Mas, como insistissem em perguntar-lhe, ergueu-se e disse- lhes: Aquele dentre vós que está sem pecado seja o primeiro que lhe atire uma pedra.' },
      { v: 8, en: 'Again he stooped down, and with his finger wrote on the ground.', pt: 'E, tornando a inclinar-se, escrevia na terra.' },
      { v: 9, en: 'They, when they heard it, being convicted by their conscience, went out one by one, beginning from the oldest, even to the last. Jesus was left alone with the woman where she was, in the middle.', pt: 'Quando ouviram isto foram saindo um a um, a começar pelos mais velhos, até os últimos; ficou só Jesus, e a mulher ali em pé.' },
      { v: 10, en: 'Jesus, standing up, saw her and said, “Woman, where are your accusers? Did no one condemn you?”', pt: 'Então, erguendo-se Jesus e não vendo a ninguém senão a mulher, perguntou-lhe: Mulher, onde estão aqueles teus acusadores? Ninguém te condenou?' },
      { v: 11, en: 'She said, “No one, Lord.” Jesus said, “Neither do I condemn you. Go your way. From now on, sin no more.”', pt: 'Respondeu ela: Ninguém, Senhor. E disse-lhe Jesus: Nem eu te condeno; vai-te, e não peques mais.]' },
      { v: 12, en: 'Again, therefore, Jesus spoke to them, saying, “I am the light of the world. He who follows me will not walk in the darkness, but will have the light of life.”', pt: 'Então Jesus tornou a falar-lhes, dizendo: Eu sou a luz do mundo; quem me segue de modo algum andará em trevas, mas terá a luz da vida.' },
      { v: 13, en: 'The Pharisees therefore said to him, “You testify about yourself. Your testimony is not valid.”', pt: 'Disseram-lhe, pois, os fariseus: Tu dás testemunho de ti mesmo; o teu testemunho não é verdadeiro.' },
      { v: 14, en: 'Jesus answered them, “Even if I testify about myself, my testimony is true, for I know where I came from, and where I am going; but you don’t know where I came from, or where I am going.', pt: 'Respondeu-lhes Jesus: Ainda que eu dou testemunho de mim mesmo, o meu testemunho é verdadeiro; porque sei donde vim, e para onde vou; mas vós não sabeis donde venho, nem para onde vou.' },
      { v: 15, en: 'You judge according to the flesh. I judge no one.', pt: 'Vós julgais segundo a carne; eu a ninguém julgo.' },
      { v: 16, en: 'Even if I do judge, my judgment is true, for I am not alone, but I am with the Father who sent me.', pt: 'E, mesmo que eu julgue, o meu juízo é verdadeiro; porque não sou eu só, mas eu e o Pai que me enviou.' },
      { v: 17, en: 'It’s also written in your law that the testimony of two people is valid.', pt: 'Ora, na vossa lei está escrito que o testemunho de dois homens é verdadeiro.' },
      { v: 18, en: 'I am one who testifies about myself, and the Father who sent me testifies about me.”', pt: 'Sou eu que dou testemunho de mim mesmo, e o Pai que me enviou, também dá testemunho de mim.' },
      { v: 19, en: 'They said therefore to him, “Where is your Father?” Jesus answered, “You know neither me, nor my Father. If you knew me, you would know my Father also.”', pt: 'Perguntavam-lhe, pois: Onde está teu pai? Jesus respondeu: Não me conheceis a mim, nem a meu Pai; se vós me conhecêsseis a mim, também conheceríeis a meu Pai.' },
      { v: 20, en: 'Jesus spoke these words in the treasury, as he taught in the temple. Yet no one arrested him, because his hour had not yet come.', pt: 'Essas palavras proferiu Jesus no lugar do tesouro, quando ensinava no templo; e ninguém o prendeu, porque ainda não era chegada a sua hora.' },
      { v: 21, en: 'Jesus said therefore again to them, “I am going away, and you will seek me, and you will die in your sins. Where I go, you can’t come.”', pt: 'Disse-lhes, pois, Jesus outra vez: Eu me retiro; buscar-me- eis, e morrereis no vosso pecado. Para onde eu vou, vós não podeis ir.' },
      { v: 22, en: 'The Jews therefore said, “Will he kill himself, because he says, ‘Where I am going, you can’t come’ ?”', pt: 'Então diziam os judeus: Será que ele vai suicidar-se, pois diz: Para onde eu vou, vós não podeis ir?' },
      { v: 23, en: 'He said to them, “You are from beneath. I am from above. You are of this world. I am not of this world.', pt: 'Disse-lhes ele: Vós sois de baixo, eu sou de cima; vós sois deste mundo, eu não sou deste mundo.' },
      { v: 24, en: 'I said therefore to you that you will die in your sins; for unless you believe that I am he, you will die in your sins.”', pt: 'Por isso vos disse que morrereis em vossos pecados; porque, se não crerdes que eu sou, morrereis em vossos pecados.' },
      { v: 25, en: 'They said therefore to him, “Who are you?” Jesus said to them, “Just what I have been saying to you from the beginning.', pt: 'Perguntavam-lhe então: Quem és tu? Respondeu-lhes Jesus: Exatamente o que venho dizendo que sou.' },
      { v: 26, en: 'I have many things to speak and to judge concerning you. However he who sent me is true; and the things which I heard from him, these I say to the world.”', pt: 'Muitas coisas tenho que dizer e julgar acerca de vós; mas aquele que me enviou é verdadeiro; e o que dele ouvi, isso falo ao mundo.' },
      { v: 27, en: 'They didn’t understand that he spoke to them about the Father.', pt: 'Eles não perceberam que lhes falava do Pai.' },
      { v: 28, en: 'Jesus therefore said to them, “When you have lifted up the Son of Man, then you will know that I am he, and I do nothing of myself, but as my Father taught me, I say these things.', pt: 'Prosseguiu, pois, Jesus: Quando tiverdes levantado o Filho do homem, então conhecereis que eu sou, e que nada faço de mim mesmo; mas como o Pai me ensinou, assim falo.' },
      { v: 29, en: 'He who sent me is with me. The Father hasn’t left me alone, for I always do the things that are pleasing to him.”', pt: 'E aquele que me enviou está comigo; não me tem deixado só; porque faço sempre o que é do seu agrado.' },
      { v: 30, en: 'As he spoke these things, many believed in him.', pt: 'Falando ele estas coisas, muitos creram nele.' },
      { v: 31, en: 'Jesus therefore said to those Jews who had believed him, “If you remain in my word, then you are truly my disciples.', pt: 'Dizia, pois, Jesus aos judeus que nele creram: Se vós permanecerdes na minha palavra, verdadeiramente sois meus discípulos;' },
      { v: 32, en: 'You will know the truth, and the truth will make you free.”', pt: 'e conhecereis a verdade, e a verdade vos libertará.' },
      { v: 33, en: 'They answered him, “We are Abraham’s offspring, and have never been in bondage to anyone. How do you say, ‘You will be made free’ ?”', pt: 'Responderam-lhe: Somos descendentes de Abraão, e nunca fomos escravos de ninguém; como dizes tu: Sereis livres?' },
      { v: 34, en: 'Jesus answered them, “Most certainly I tell you, everyone who commits sin is the bondservant of sin.', pt: 'Replicou-lhes Jesus: Em verdade, em verdade vos digo que todo aquele que comete pecado é escravo do pecado.' },
      { v: 35, en: 'A bondservant doesn’t live in the house forever. A son remains forever.', pt: 'Ora, o escravo não fica para sempre na casa; o filho fica para sempre.' },
      { v: 36, en: 'If therefore the Son makes you free, you will be free indeed.', pt: 'Se, pois, o Filho vos libertar, verdadeiramente sereis livres.' },
      { v: 37, en: 'I know that you are Abraham’s offspring, yet you seek to kill me, because my word finds no place in you.', pt: 'Bem sei que sois descendência de Abraão; contudo, procurais matar-me, porque a minha palavra não encontra lugar em vós.' },
      { v: 38, en: 'I say the things which I have seen with my Father; and you also do the things which you have seen with your father.”', pt: 'Eu falo do que vi junto de meu Pai; e vós fazeis o que também ouvistes de vosso pai.' },
      { v: 39, en: 'They answered him, “Our father is Abraham.” Jesus said to them, “If you were Abraham’s children, you would do the works of Abraham.', pt: 'Responderam-lhe: Nosso pai é Abraão. Disse-lhes Jesus: Se sois filhos de Abraão, fazei as obras de Abraão.' },
      { v: 40, en: 'But now you seek to kill me, a man who has told you the truth, which I heard from God. Abraham didn’t do this.', pt: 'Mas agora procurais matar-me, a mim que vos falei a verdade que de Deus ouvi; isso Abraão não fez.' },
      { v: 41, en: 'You do the works of your father.” They said to him, “We were not born of sexual immorality. We have one Father, God.”', pt: 'Vós fazeis as obras de vosso pai. Replicaram-lhe eles: Nós não somos nascidos de prostituição; temos um Pai, que é Deus.' },
      { v: 42, en: 'Therefore Jesus said to them, “If God were your father, you would love me, for I came out and have come from God. For I haven’t come of myself, but he sent me.', pt: 'Respondeu-lhes Jesus: Se Deus fosse o vosso Pai, vós me amaríeis, porque eu saí e vim de Deus; pois não vim de mim mesmo, mas ele me enviou.' },
      { v: 43, en: 'Why don’t you understand my speech? Because you can’t hear my word.', pt: 'Por que não compreendeis a minha linguagem? é porque não podeis ouvir a minha palavra.' },
      { v: 44, en: 'You are of your father, the devil, and you want to do the desires of your father. He was a murderer from the beginning, and doesn’t stand in the truth, because there is no truth in him. When he speaks a lie, he speaks on his own; for he is a liar, and the father of lies.', pt: 'Vós tendes por pai o Diabo, e quereis satisfazer os desejos de vosso pai; ele é homicida desde o princípio, e nunca se firmou na verdade, porque nele não há verdade; quando ele profere mentira, fala do que lhe é próprio; porque é mentiroso, e pai da mentira.' },
      { v: 45, en: 'But because I tell the truth, you don’t believe me.', pt: 'Mas porque eu digo a verdade, não me credes.' },
      { v: 46, en: 'Which of you convicts me of sin? If I tell the truth, why do you not believe me?', pt: 'Quem dentre vós me convence de pecado? Se digo a verdade, por que não me credes?' },
      { v: 47, en: 'He who is of God hears the words of God. For this cause you don’t hear, because you are not of God.”', pt: 'Quem é de Deus ouve as palavras de Deus; por isso vós não as ouvis, porque não sois de Deus.' },
      { v: 48, en: 'Then the Jews answered him, “Don’t we say well that you are a Samaritan, and have a demon?”', pt: 'Responderam-lhe os judeus: Não dizemos com razão que és samaritano, e que tens demônio?' },
      { v: 49, en: 'Jesus answered, “I don’t have a demon, but I honor my Father, and you dishonor me.', pt: 'Jesus respondeu: Eu não tenho demônio; antes honro a meu Pai, e vós me desonrais.' },
      { v: 50, en: 'But I don’t seek my own glory. There is one who seeks and judges.', pt: 'Eu não busco a minha glória; há quem a busque, e julgue.' },
      { v: 51, en: 'Most certainly, I tell you, if a person keeps my word, he will never see death.”', pt: 'Em verdade, em verdade vos digo que, se alguém guardar a minha palavra, nunca verá a morte.' },
      { v: 52, en: 'Then the Jews said to him, “Now we know that you have a demon. Abraham died, and the prophets; and you say, ‘If a man keeps my word, he will never taste of death.’', pt: 'Disseram-lhe os judeus: Agora sabemos que tens demônios. Abraão morreu, e também os profetas; e tu dizes: Se alguém guardar a minha palavra, nunca provará a morte!' },
      { v: 53, en: 'Are you greater than our father, Abraham, who died? The prophets died. Who do you make yourself out to be?”', pt: 'Porventura és tu maior do que nosso pai Abraão, que morreu? Também os profetas morreram; quem pretendes tu ser?' },
      { v: 54, en: 'Jesus answered, “If I glorify myself, my glory is nothing. It is my Father who glorifies me, of whom you say that he is our God.', pt: 'Respondeu Jesus: Se eu me glorificar a mim mesmo, a minha glória não é nada; quem me glorifica é meu Pai, do qual vós dizeis que é o vosso Deus;' },
      { v: 55, en: 'You have not known him, but I know him. If I said, ‘I don’t know him,’ I would be like you, a liar. But I know him, and keep his word.', pt: 'e vós não o conheceis; mas eu o conheço; e se disser que não o conheço, serei mentiroso como vós; mas eu o conheço, e guardo a sua palavra.' },
      { v: 56, en: 'Your father Abraham rejoiced to see my day. He saw it, and was glad.”', pt: 'Abraão, vosso pai, exultou por ver o meu dia; viu-o, e alegrou-se.' },
      { v: 57, en: 'The Jews therefore said to him, “You are not yet fifty years old, and have you seen Abraham?”', pt: 'Disseram-lhe, pois, os judeus: Ainda não tens cinquenta anos, e viste Abraão?' },
      { v: 58, en: 'Jesus said to them, “Most certainly, I tell you, before Abraham came into existence, I AM. ”', pt: 'Respondeu-lhes Jesus: Em verdade, em verdade vos digo que antes que Abraão existisse, eu sou.' },
      { v: 59, en: 'Therefore they took up stones to throw at him, but Jesus was hidden, and went out of the temple, having gone through the middle of them, and so passed by.', pt: 'Então pegaram em pedras para lhe atirarem; mas Jesus ocultou-se, e saiu do templo.' },
    ],
    9: [
      { v: 1, en: 'As he passed by, he saw a man blind from birth.', pt: 'E passando Jesus, viu um homem cego de nascença.' },
      { v: 2, en: 'His disciples asked him, “Rabbi, who sinned, this man or his parents, that he was born blind?”', pt: 'Perguntaram-lhe os seus discípulos: Rabi, quem pecou, este ou seus pais, para que nascesse cego?' },
      { v: 3, en: 'Jesus answered, “Neither did this man sin, nor his parents; but, that the works of God might be revealed in him.', pt: 'Respondeu Jesus: Nem ele pecou nem seus pais; mas foi para que nele se manifestem as obras de Deus.' },
      { v: 4, en: 'I must work the works of him who sent me, while it is day. The night is coming, when no one can work.', pt: 'Importa que façamos as obras daquele que me enviou, enquanto é dia; vem a noite, quando ninguém pode trabalhar.' },
      { v: 5, en: 'While I am in the world, I am the light of the world.”', pt: 'Enquanto estou no mundo, sou a luz do mundo.' },
      { v: 6, en: 'When he had said this, he spat on the ground, made mud with the saliva, anointed the blind man’s eyes with the mud,', pt: 'Dito isto, cuspiu no chão e com a saliva fez lodo, e untou com lodo os olhos do cego,' },
      { v: 7, en: 'and said to him, “Go, wash in the pool of Siloam” (which means “Sent”). So he went away, washed, and came back seeing.', pt: 'e disse-lhe: Vai, lava-te no tanque de Siloé (que significa Enviado). E ele foi, lavou-se, e voltou vendo.' },
      { v: 8, en: 'The neighbors therefore, and those who saw that he was blind before, said, “Isn’t this he who sat and begged?”', pt: 'Então os vizinhos e aqueles que antes o tinham visto, quando mendigo, perguntavam: Não é este o mesmo que se sentava a mendigar?' },
      { v: 9, en: 'Others were saying, “It is he.” Still others were saying, “He looks like him.” He said, “I am he.”', pt: 'Uns diziam: É ele. E outros: Não é, mas se parece com ele. Ele dizia: Sou eu.' },
      { v: 10, en: 'They therefore were asking him, “How were your eyes opened?”', pt: 'Perguntaram-lhe, pois: Como se te abriram os olhos?' },
      { v: 11, en: 'He answered, “A man called Jesus made mud, anointed my eyes, and said to me, ‘Go to the pool of Siloam, and wash.’ So I went away and washed, and I received sight.”', pt: 'Respondeu ele: O homem que se chama Jesus fez lodo, untou-me os olhos, e disse-me: Vai a Siloé e lava-te. Fui, pois, lavei-me, e fiquei vendo.' },
      { v: 12, en: 'Then they asked him, “Where is he?” He said, “I don’t know.”', pt: 'E perguntaram-lhe: Onde está ele? Respondeu: Não sei.' },
      { v: 13, en: 'They brought him who had been blind to the Pharisees.', pt: 'Levaram aos fariseus o que fora cego.' },
      { v: 14, en: 'It was a Sabbath when Jesus made the mud and opened his eyes.', pt: 'Ora, era sábado o dia em que Jesus fez o lodo e lhe abriu os olhos.' },
      { v: 15, en: 'Again therefore the Pharisees also asked him how he received his sight. He said to them, “He put mud on my eyes, I washed, and I see.”', pt: 'Então os fariseus também se puseram a perguntar-lhe como recebera a vista. Respondeu-lhes ele: Pôs-me lodo sobre os olhos, lavei-me e vejo.' },
      { v: 16, en: 'Some therefore of the Pharisees said, “This man is not from God, because he doesn’t keep the Sabbath.” Others said, “How can a man who is a sinner do such signs?” There was division among them.', pt: 'Por isso alguns dos fariseus diziam: Este homem não é de Deus; pois não guarda o sábado. Diziam outros: Como pode um homem pecador fazer tais sinais? E havia dissensão entre eles.' },
      { v: 17, en: 'Therefore they asked the blind man again, “What do you say about him, because he opened your eyes?” He said, “He is a prophet.”', pt: 'Tornaram, pois, a perguntar ao cego: Que dizes tu a respeito dele, visto que te abriu os olhos? E ele respondeu: É profeta.' },
      { v: 18, en: 'The Jews therefore did not believe concerning him, that he had been blind, and had received his sight, until they called the parents of him who had received his sight,', pt: 'Os judeus, porém, não acreditaram que ele tivesse sido cego e recebido a vista, enquanto não chamaram os pais do que fora curado,' },
      { v: 19, en: 'and asked them, “Is this your son, whom you say was born blind? How then does he now see?”', pt: 'e lhes perguntaram: É este o vosso filho, que dizeis ter nascido cego? Como, pois, vê agora?' },
      { v: 20, en: 'His parents answered them, “We know that this is our son, and that he was born blind;', pt: 'Responderam seus pais: Sabemos que este é o nosso filho, e que nasceu cego;' },
      { v: 21, en: 'but how he now sees, we don’t know; or who opened his eyes, we don’t know. He is of age. Ask him. He will speak for himself.”', pt: 'mas como agora vê, não sabemos; ou quem lhe abriu os olhos, nós não sabemos; perguntai a ele mesmo; tem idade; ele falará por si mesmo.' },
      { v: 22, en: 'His parents said these things because they feared the Jews; for the Jews had already agreed that if any man would confess him as Christ, he would be put out of the synagogue.', pt: 'Isso disseram seus pais, porque temiam os judeus, porquanto já tinham estes combinado que se alguém confessasse ser Jesus o Cristo, fosse expulso da sinagoga.' },
      { v: 23, en: 'Therefore his parents said, “He is of age. Ask him.”', pt: 'Por isso é que seus pais disseram: Tem idade, perguntai-lho a ele mesmo.' },
      { v: 24, en: 'So they called the man who was blind a second time, and said to him, “Give glory to God. We know that this man is a sinner.”', pt: 'Então chamaram pela segunda vez o homem que fora cego, e lhe disseram: Dá glória a Deus; nós sabemos que esse homem é pecador.' },
      { v: 25, en: 'He therefore answered, “I don’t know if he is a sinner. One thing I do know: that though I was blind, now I see.”', pt: 'Respondeu ele: Se é pecador, não sei; uma coisa sei: eu era cego, e agora vejo.' },
      { v: 26, en: 'They said to him again, “What did he do to you? How did he open your eyes?”', pt: 'Perguntaram-lhe pois: Que foi que te fez? Como te abriu os olhos?' },
      { v: 27, en: 'He answered them, “I told you already, and you didn’t listen. Why do you want to hear it again? You don’t also want to become his disciples, do you?”', pt: 'Respondeu-lhes: Já vo-lo disse, e não atendestes; para que o quereis tornar a ouvir? Acaso também vós quereis tornar-vos discípulos dele?' },
      { v: 28, en: 'They insulted him and said, “You are his disciple, but we are disciples of Moses.', pt: 'Então o injuriaram, e disseram: Discípulo dele és tu; nós porém, somos discípulos de Moisés.' },
      { v: 29, en: 'We know that God has spoken to Moses. But as for this man, we don’t know where he comes from.”', pt: 'Sabemos que Deus falou a Moisés; mas quanto a este, não sabemos donde é.' },
      { v: 30, en: 'The man answered them, “How amazing! You don’t know where he comes from, yet he opened my eyes.', pt: 'Respondeu-lhes o homem: Nisto, pois, está a maravilha: não sabeis donde ele é, e entretanto ele me abriu os olhos;' },
      { v: 31, en: 'We know that God doesn’t listen to sinners, but if anyone is a worshiper of God, and does his will, he listens to him.', pt: 'sabemos que Deus não ouve a pecadores; mas, se alguém for temente a Deus, e fizer a sua vontade, a esse ele ouve.' },
      { v: 32, en: 'Since the world began it has never been heard of that anyone opened the eyes of someone born blind.', pt: 'Desde o princípio do mundo nunca se ouviu que alguém abrisse os olhos a um cego de nascença.' },
      { v: 33, en: 'If this man were not from God, he could do nothing.”', pt: 'Se este não fosse de Deus, nada poderia fazer.' },
      { v: 34, en: 'They answered him, “You were altogether born in sins, and do you teach us?” They threw him out.', pt: 'Replicaram-lhe eles: Tu nasceste todo em pecados, e vens nos ensinar a nós? E expulsaram-no.' },
      { v: 35, en: 'Jesus heard that they had thrown him out, and finding him, he said, “Do you believe in the Son of God?”', pt: 'Soube Jesus que o haviam expulsado; e achando-o perguntou- lhe: Crês tu no Filho do homem?' },
      { v: 36, en: 'He answered, “Who is he, Lord, that I may believe in him?”', pt: 'Respondeu ele: Quem é, senhor, para que nele creia?' },
      { v: 37, en: 'Jesus said to him, “You have both seen him, and it is he who speaks with you.”', pt: 'Disse-lhe Jesus: Já o viste, e é ele quem fala contigo.' },
      { v: 38, en: 'He said, “Lord, I believe!” and he worshiped him.', pt: 'Disse o homem: Creio, Senhor! E o adorou.' },
      { v: 39, en: 'Jesus said, “I came into this world for judgment, that those who don’t see may see; and that those who see may become blind.”', pt: 'Prosseguiu então Jesus: Eu vim a este mundo para juízo, a fim de que os que não vêem vejam, e os que vêem se tornem cegos.' },
      { v: 40, en: 'Those of the Pharisees who were with him heard these things, and said to him, “Are we also blind?”', pt: 'Alguns fariseus que ali estavam com ele, ouvindo isso, perguntaram-lhe: Porventura somos nós também cegos?' },
      { v: 41, en: 'Jesus said to them, “If you were blind, you would have no sin; but now you say, ‘We see.’ Therefore your sin remains.', pt: 'Respondeu-lhes Jesus: Se fosseis cegos, não teríeis pecado; mas como agora dizeis: Nós vemos, permanece o vosso pecado.' },
    ],
    10: [
      { v: 1, en: '“Most certainly, I tell you, one who doesn’t enter by the door into the sheep fold, but climbs up some other way, the same is a thief and a robber.', pt: 'Em verdade, em verdade vos digo: quem não entra pela porta no aprisco das ovelhas, mas sobe por outra parte, esse é ladrão e salteador.' },
      { v: 2, en: 'But one who enters in by the door is the shepherd of the sheep.', pt: 'Mas o que entra pela porta é o pastor das ovelhas.' },
      { v: 3, en: 'The gatekeeper opens the gate for him, and the sheep listen to his voice. He calls his own sheep by name, and leads them out.', pt: 'A este o porteiro abre; e as ovelhas ouvem a sua voz; e ele chama pelo nome as suas ovelhas, e as conduz para fora.' },
      { v: 4, en: 'Whenever he brings out his own sheep, he goes before them, and the sheep follow him, for they know his voice.', pt: 'Depois de conduzir para fora todas as que lhe pertencem, vai adiante delas, e as ovelhas o seguem, porque conhecem a sua voz;' },
      { v: 5, en: 'They will by no means follow a stranger, but will flee from him; for they don’t know the voice of strangers.”', pt: 'mas de modo algum seguirão o estranho, antes fugirão dele, porque não conhecem a voz dos estranhos.' },
      { v: 6, en: 'Jesus spoke this parable to them, but they didn’t understand what he was telling them.', pt: 'Jesus propôs-lhes esta parábola, mas eles não entenderam o que era que lhes dizia.' },
      { v: 7, en: 'Jesus therefore said to them again, “Most certainly, I tell you, I am the sheep’s door.', pt: 'Tornou, pois, Jesus a dizer-lhes: Em verdade, em verdade vos digo: eu sou a porta das ovelhas.' },
      { v: 8, en: 'All who came before me are thieves and robbers, but the sheep didn’t listen to them.', pt: 'Todos quantos vieram antes de mim são ladrões e salteadores; mas as ovelhas não os ouviram.' },
      { v: 9, en: 'I am the door. If anyone enters in by me, he will be saved, and will go in and go out, and will find pasture.', pt: 'Eu sou a porta; se alguém entrar a casa; o filho fica entrará e sairá, e achará pastagens.' },
      { v: 10, en: 'The thief only comes to steal, kill, and destroy. I came that they may have life, and may have it abundantly.', pt: 'O ladrão não vem senão para roubar, matar e destruir; eu vim para que tenham vida e a tenham em abundância.' },
      { v: 11, en: 'I am the good shepherd. The good shepherd lays down his life for the sheep.', pt: 'Eu sou o bom pastor; o bom pastor dá a sua vida pelas ovelhas.' },
      { v: 12, en: 'He who is a hired hand, and not a shepherd, who doesn’t own the sheep, sees the wolf coming, leaves the sheep, and flees. The wolf snatches the sheep, and scatters them.', pt: 'Mas o que é mercenário, e não pastor, de quem não são as ovelhas, vendo vir o lobo, deixa as ovelhas e foge; e o lobo as arrebata e dispersa.' },
      { v: 13, en: 'The hired hand flees because he is a hired hand, and doesn’t care for the sheep.', pt: 'Ora, o mercenário foge porque é mercenário, e não se importa com as ovelhas.' },
      { v: 14, en: 'I am the good shepherd. I know my own, and I’m known by my own;', pt: 'Eu sou o bom pastor; conheço as minhas ovelhas, e elas me conhecem,' },
      { v: 15, en: 'even as the Father knows me, and I know the Father. I lay down my life for the sheep.', pt: 'assim como o Pai me conhece e eu conheço o Pai; e dou a minha vida pelas ovelhas.' },
      { v: 16, en: 'I have other sheep, which are not of this fold. I must bring them also, and they will hear my voice. They will become one flock with one shepherd.', pt: 'Tenho ainda outras ovelhas que não são deste aprisco; a essas também me importa conduzir, e elas ouvirão a minha voz; e haverá um rebanho e um pastor.' },
      { v: 17, en: 'Therefore the Father loves me, because I lay down my life, that I may take it again.', pt: 'Por isto o Pai me ama, porque dou a minha vida para a retomar.' },
      { v: 18, en: 'No one takes it away from me, but I lay it down by myself. I have power to lay it down, and I have power to take it again. I received this commandment from my Father.”', pt: 'Ninguém ma tira de mim, mas eu de mim mesmo a dou; tenho autoridade para a dar, e tenho autoridade para retomá-la. Este mandamento recebi de meu Pai.' },
      { v: 19, en: 'Therefore a division arose again among the Jews because of these words.', pt: 'Por causa dessas palavras, houve outra dissensão entre os judeus.' },
      { v: 20, en: 'Many of them said, “He has a demon, and is insane! Why do you listen to him?”', pt: 'E muitos deles diziam: Tem demônio, e perdeu o juízo; por que o escutais?' },
      { v: 21, en: 'Others said, “These are not the sayings of one possessed by a demon. It isn’t possible for a demon to open the eyes of the blind, is it?”', pt: 'Diziam outros: Essas palavras não são de quem está endemoninhado; pode porventura um demônio abrir os olhos aos cegos?' },
      { v: 22, en: 'It was the Feast of the Dedication at Jerusalem.', pt: 'Celebrava-se então em Jerusalém a festa da dedicação. E era inverno.' },
      { v: 23, en: 'It was winter, and Jesus was walking in the temple, in Solomon’s porch.', pt: 'Andava Jesus passeando no templo, no pórtico de Salomão.' },
      { v: 24, en: 'The Jews therefore came around him and said to him, “How long will you hold us in suspense? If you are the Christ, tell us plainly.”', pt: 'Rodearam-no, pois, os judeus e lhe perguntavam: Até quando nos deixarás perplexos? Se tu és o Cristo, dize-no-lo abertamente.' },
      { v: 25, en: 'Jesus answered them, “I told you, and you don’t believe. The works that I do in my Father’s name, these testify about me.', pt: 'Respondeu-lhes Jesus: Já vo-lo disse, e não credes. As obras que eu faço em nome de meu Pai, essas dão testemunho de mim.' },
      { v: 26, en: 'But you don’t believe, because you are not of my sheep, as I told you.', pt: 'Mas vós não credes, porque não sois das minhas ovelhas.' },
      { v: 27, en: 'My sheep hear my voice, and I know them, and they follow me.', pt: 'As minhas ovelhas ouvem a minha voz, e eu as conheço, e elas me seguem;' },
      { v: 28, en: 'I give eternal life to them. They will never perish, and no one will snatch them out of my hand.', pt: 'eu lhes dou a vida eterna, e jamais perecerão; e ninguém as arrebatará da minha mão.' },
      { v: 29, en: 'My Father, who has given them to me, is greater than all. No one is able to snatch them out of my Father’s hand.', pt: 'Meu Pai, que mas deu, é maior do que todos; e ninguém pode arrebatá-las da mão de meu Pai.' },
      { v: 30, en: 'I and the Father are one.”', pt: 'Eu e o Pai somos um.' },
      { v: 31, en: 'Therefore Jews took up stones again to stone him.', pt: 'Os judeus pegaram então outra vez em pedras para o apedrejar.' },
      { v: 32, en: 'Jesus answered them, “I have shown you many good works from my Father. For which of those works do you stone me?”', pt: 'Disse-lhes Jesus: Muitas obras boas da parte de meu Pai vos tenho mostrado; por qual destas obras ides apedrejar-me?' },
      { v: 33, en: 'The Jews answered him, “We don’t stone you for a good work, but for blasphemy: because you, being a man, make yourself God.”', pt: 'Responderam-lhe os judeus: Não é por nenhuma obra boa que vamos apedrejar-te, mas por blasfêmia; e porque, sendo tu homem, te fazes Deus.' },
      { v: 34, en: 'Jesus answered them, “Isn’t it written in your law, ‘I said, you are gods?’', pt: 'Tornou-lhes Jesus: Não está escrito na vossa lei: Eu disse: Vós sois deuses?' },
      { v: 35, en: 'If he called them gods, to whom the word of God came (and the Scripture can’t be broken),', pt: 'Se a lei chamou deuses àqueles a quem a palavra de Deus foi dirigida (e a Escritura não pode ser anulada),' },
      { v: 36, en: 'do you say of him whom the Father sanctified and sent into the world, ‘You blaspheme,’ because I said, ‘I am the Son of God?’', pt: 'àquele a quem o Pai santificou, e enviou ao mundo, dizeis vós: Blasfemas; porque eu disse: Sou Filho de Deus?' },
      { v: 37, en: 'If I don’t do the works of my Father, don’t believe me.', pt: 'Se não faço as obras de meu Pai, não me acrediteis.' },
      { v: 38, en: 'But if I do them, though you don’t believe me, believe the works; that you may know and believe that the Father is in me, and I in the Father.”', pt: 'Mas se as faço, embora não me creiais a mim, crede nas obras; para que entendais e saibais que o Pai está em mim e eu no Pai.' },
      { v: 39, en: 'They sought again to seize him, and he went out of their hand.', pt: 'Outra vez, pois, procuravam prendê-lo; mas ele lhes escapou das mãos.' },
      { v: 40, en: 'He went away again beyond the Jordan into the place where John was baptizing at first, and there he stayed.', pt: 'E retirou-se de novo para além do Jordão, para o lugar onde João batizava no princípio; e ali ficou.' },
      { v: 41, en: 'Many came to him. They said, “John indeed did no sign, but everything that John said about this man is true.”', pt: 'Muitos foram ter com ele, e diziam: João, na verdade, não fez sinal algum, mas tudo quanto disse deste homem era verdadeiro.' },
      { v: 42, en: 'Many believed in him there.', pt: 'E muitos ali creram nele.' },
    ],
    11: [
      { v: 1, en: 'Now a certain man was sick, Lazarus from Bethany, of the village of Mary and her sister, Martha.', pt: 'Ora, estava enfermo um homem chamado Lázaro, de Betânia, aldeia de Maria e de sua irmã Marta.' },
      { v: 2, en: 'It was that Mary who had anointed the Lord with ointment, and wiped his feet with her hair, whose brother, Lazarus, was sick.', pt: 'E Maria, cujo irmão Lázaro se achava enfermo, era a mesma que ungiu o Senhor com bálsamo, e lhe enxugou os pés com os seus cabelos.' },
      { v: 3, en: 'The sisters therefore sent to him, saying, “Lord, behold, he for whom you have great affection is sick.”', pt: 'Mandaram, pois, as irmãs dizer a Jesus: Senhor, eis que está enfermo aquele que tu amas.' },
      { v: 4, en: 'But when Jesus heard it, he said, “This sickness is not to death, but for the glory of God, that God’s Son may be glorified by it.”', pt: 'Jesus, porém, ao ouvir isto, disse: Esta enfermidade não é para a morte, mas para glória de Deus, para que o Filho de Deus seja glorificado por ela.' },
      { v: 5, en: 'Now Jesus loved Martha, and her sister, and Lazarus.', pt: 'Ora, Jesus amava a Marta, e a sua irmã, e a Lázaro.' },
      { v: 6, en: 'When therefore he heard that he was sick, he stayed two days in the place where he was.', pt: 'Quando, pois, ouviu que estava enfermo, ficou ainda dois dias no lugar onde se achava.' },
      { v: 7, en: 'Then after this he said to the disciples, “Let’s go into Judea again.”', pt: 'Depois disto, disse a seus discípulos: Vamos outra vez para Judéia.' },
      { v: 8, en: 'The disciples told him, “Rabbi, the Jews were just trying to stone you, and are you going there again?”', pt: 'Disseram-lhe eles: Rabi, ainda agora os judeus procuravam apedrejar-te, e voltas para lá?' },
      { v: 9, en: 'Jesus answered, “Aren’t there twelve hours of daylight? If a man walks in the day, he doesn’t stumble, because he sees the light of this world.', pt: 'Respondeu Jesus: Não são doze as horas do dia? Se alguém andar de dia, não tropeça, porque vê a luz deste mundo;' },
      { v: 10, en: 'But if a man walks in the night, he stumbles, because the light isn’t in him.”', pt: 'mas se andar de noite, tropeça, porque nele não há luz.' },
      { v: 11, en: 'He said these things, and after that, he said to them, “Our friend, Lazarus, has fallen asleep, but I am going so that I may awake him out of sleep.”', pt: 'E, tendo assim falado, acrescentou: Lázaro, o nosso amigo, dorme, mas vou despertá-lo do sono.' },
      { v: 12, en: 'The disciples therefore said, “Lord, if he has fallen asleep, he will recover.”', pt: 'Disseram-lhe, pois, os discípulos: Senhor, se dorme, ficará bom.' },
      { v: 13, en: 'Now Jesus had spoken of his death, but they thought that he spoke of taking rest in sleep.', pt: 'Mas Jesus falara da sua morte; eles, porém, entenderam que falava do repouso do sono.' },
      { v: 14, en: 'So Jesus said to them plainly then, “Lazarus is dead.', pt: 'Então Jesus lhes disse claramente: Lázaro morreu;' },
      { v: 15, en: 'I am glad for your sakes that I was not there, so that you may believe. Nevertheless, let’s go to him.”', pt: 'e, por vossa causa, folgo de que eu lá não estivesse, para para que creiais; mas vamos ter com ele.' },
      { v: 16, en: 'Thomas therefore, who is called Didymus, said to his fellow disciples, “Let’s go also, that we may die with him.”', pt: 'Disse, pois, Tomé, chamado Dídimo, aos seus condiscípulos: Vamos nós também, para morrermos com ele.' },
      { v: 17, en: 'So when Jesus came, he found that he had been in the tomb four days already.', pt: 'Chegando pois Jesus, encontrou-o já com quatro dias de sepultura.' },
      { v: 18, en: 'Now Bethany was near Jerusalem, about fifteen stadia away.', pt: 'Ora, Betânia distava de Jerusalém cerca de quinze estádios.' },
      { v: 19, en: 'Many of the Jews had joined the women around Martha and Mary, to console them concerning their brother.', pt: 'E muitos dos judeus tinham vindo visitar Marta e Maria, para as consolar acerca de seu irmão.' },
      { v: 20, en: 'Then when Martha heard that Jesus was coming, she went and met him, but Mary stayed in the house.', pt: 'Marta, pois, ao saber que Jesus chegava, saiu-lhe ao encontro; Maria, porém, ficou sentada em casa.' },
      { v: 21, en: 'Therefore Martha said to Jesus, “Lord, if you would have been here, my brother wouldn’t have died.', pt: 'Disse, pois, Marta a Jesus: Senhor, se meu irmão não teria morrido.' },
      { v: 22, en: 'Even now I know that, whatever you ask of God, God will give you.”', pt: 'E mesmo agora sei que tudo quanto pedires a Deus, Deus to concederá.' },
      { v: 23, en: 'Jesus said to her, “Your brother will rise again.”', pt: 'Respondeu-lhe Jesus: Teu irmão há de ressurgir.' },
      { v: 24, en: 'Martha said to him, “I know that he will rise again in the resurrection at the last day.”', pt: 'Disse-lhe Marta: Sei que ele há de ressurgir na ressurreição, no último dia.' },
      { v: 25, en: 'Jesus said to her, “I am the resurrection and the life. He who believes in me will still live, even if he dies.', pt: 'Declarou-lhe Jesus: Eu sou a ressurreição e a vida; quem crê em mim, ainda que morra, viverá;' },
      { v: 26, en: 'Whoever lives and believes in me will never die. Do you believe this?”', pt: 'e todo aquele que vive, e crê em mim, jamais morrerá. Crês isto?' },
      { v: 27, en: 'She said to him, “Yes, Lord. I have come to believe that you are the Christ, God’s Son, he who comes into the world.”', pt: 'Respondeu-lhe Marta: Sim, Senhor, eu creio que tu és o Cristo, o Filho de Deus, que havia de vir ao mundo.' },
      { v: 28, en: 'When she had said this, she went away, and called Mary, her sister, secretly, saying, “The Teacher is here, and is calling you.”', pt: 'Dito isto, retirou-se e foi chamar em segredo a Maria, sua irmã, e lhe disse: O Mestre está aí, e te chama.' },
      { v: 29, en: 'When she heard this, she arose quickly, and went to him.', pt: 'Ela, ouvindo isto, levantou-se depressa, e foi ter com ele.' },
      { v: 30, en: 'Now Jesus had not yet come into the village, but was in the place where Martha met him.', pt: 'Pois Jesus ainda não havia entrado na aldeia, mas estava no lugar onde Marta o encontrara.' },
      { v: 31, en: 'Then the Jews who were with her in the house, and were consoling her, when they saw Mary, that she rose up quickly and went out, followed her, saying, “She is going to the tomb to weep there.”', pt: 'Então os judeus que estavam com Maria em casa e a consolavam, vendo-a levantar-se apressadamente e sair, seguiram-na, pensando que ia ao sepulcro para chorar ali.' },
      { v: 32, en: 'Therefore when Mary came to where Jesus was, and saw him, she fell down at his feet, saying to him, “Lord, if you would have been here, my brother wouldn’t have died.”', pt: 'Tendo, pois, Maria chegado ao lugar onde Jesus estava, e vendo-a, lançou-se-lhe aos pés e disse: Senhor, se tu estiveras aqui, meu irmão não teria morrido.' },
      { v: 33, en: 'When Jesus therefore saw her weeping, and the Jews weeping who came with her, he groaned in the spirit, and was troubled,', pt: 'Jesus, pois, quando a viu chorar, e chorarem também os judeus que com ela vinham, comoveu-se em espírito, e perturbou-se,' },
      { v: 34, en: 'and said, “Where have you laid him?” They told him, “Lord, come and see.”', pt: 'e perguntou: Onde o puseste? Responderam-lhe: Senhor, vem e vê.' },
      { v: 35, en: 'Jesus wept.', pt: 'Jesus chorou.' },
      { v: 36, en: 'The Jews therefore said, “See how much affection he had for him!”', pt: 'Disseram então os judeus: Vede como o amava.' },
      { v: 37, en: 'Some of them said, “Couldn’t this man, who opened the eyes of him who was blind, have also kept this man from dying?”', pt: 'Mas alguns deles disseram: Não podia ele, que abriu os olhos ao cego, fazer também que este não morreste?' },
      { v: 38, en: 'Jesus therefore, again groaning in himself, came to the tomb. Now it was a cave, and a stone lay against it.', pt: 'Jesus, pois, comovendo-se outra vez, profundamente, foi ao sepulcro; era uma gruta, e tinha uma pedra posta sobre ela.' },
      { v: 39, en: 'Jesus said, “Take away the stone.” Martha, the sister of him who was dead, said to him, “Lord, by this time there is a stench, for he has been dead four days.”', pt: 'Disse Jesus: Tirai a pedra. Marta, irmã do defunto, disse- lhe: Senhor, já cheira mal, porque está morto há quase quatro dias.' },
      { v: 40, en: 'Jesus said to her, “Didn’t I tell you that if you believed, you would see God’s glory?”', pt: 'Respondeu-lhe Jesus: Não te disse que, se creres, verás a glória de Deus?' },
      { v: 41, en: 'So they took away the stone from the place where the dead man was lying. Jesus lifted up his eyes, and said, “Father, I thank you that you listened to me.', pt: 'Tiraram então a pedra. E Jesus, levantando os olhos ao céu, disse: Pai, graças te dou, porque me ouviste.' },
      { v: 42, en: 'I know that you always listen to me, but because of the multitude standing around I said this, that they may believe that you sent me.”', pt: 'Eu sabia que sempre me ouves; mas por causa da multidão que está em redor é que assim falei, para que eles creiam que tu me enviaste.' },
      { v: 43, en: 'When he had said this, he cried with a loud voice, “Lazarus, come out!”', pt: 'E, tendo dito isso, clamou em alta voz: Lázaro, vem para fora!' },
      { v: 44, en: 'He who was dead came out, bound hand and foot with wrappings, and his face was wrapped around with a cloth. Jesus said to them, “Free him, and let him go.”', pt: 'Saiu o que estivera morto, ligados os pés e as mãos com faixas, e o seu rosto envolto num lenço. Disse-lhes Jesus: Desligai-o e deixai-o ir.' },
      { v: 45, en: 'Therefore many of the Jews, who came to Mary and saw what Jesus did, believed in him.', pt: 'Muitos, pois, dentre os judeus que tinham vindo visitar Maria, e que tinham visto o que Jesus fizera, creram nele.' },
      { v: 46, en: 'But some of them went away to the Pharisees, and told them the things which Jesus had done.', pt: 'Mas alguns deles foram ter com os fariseus e disseram-lhes o que Jesus tinha feito.' },
      { v: 47, en: 'The chief priests therefore and the Pharisees gathered a council, and said, “What are we doing? For this man does many signs.', pt: 'Então os principais sacerdotes e os fariseus reuniram o sinédrio e diziam: Que faremos? porquanto este homem vem operando muitos sinais.' },
      { v: 48, en: 'If we leave him alone like this, everyone will believe in him, and the Romans will come and take away both our place and our nation.”', pt: 'Se o deixarmos assim, todos crerão nele, e virão os romanos, e nos tirarão tanto o nosso lugar como a nossa nação.' },
      { v: 49, en: 'But a certain one of them, Caiaphas, being high priest that year, said to them, “You know nothing at all,', pt: 'Um deles, porém, chamado Caifás, que era sumo sacerdote naquele ano, disse-lhes: Vós nada sabeis,' },
      { v: 50, en: 'nor do you consider that it is advantageous for us that one man should die for the people, and that the whole nation not perish.”', pt: 'nem considerais que vos convém que morra um só homem pelo povo, e que não pereça a nação toda.' },
      { v: 51, en: 'Now he didn’t say this of himself, but being high priest that year, he prophesied that Jesus would die for the nation,', pt: 'Ora, isso não disse ele por si mesmo; mas, sendo o sumo sacerdote naquele ano, profetizou que Jesus havia de morrer pela nação,' },
      { v: 52, en: 'and not for the nation only, but that he might also gather together into one the children of God who are scattered abroad.', pt: 'e não somente pela nação, mas também para congregar num só corpo os filhos de Deus que estão dispersos.' },
      { v: 53, en: 'So from that day forward they took counsel that they might put him to death.', pt: 'Desde aquele dia, pois, tomavam conselho para o matarem.' },
      { v: 54, en: 'Jesus therefore walked no more openly among the Jews, but departed from there into the country near the wilderness, to a city called Ephraim. He stayed there with his disciples.', pt: 'De sorte que Jesus já não andava manifestamente entre os judeus, mas retirou-se dali para a região vizinha ao deserto, a uma cidade chamada Efraim; e ali demorou com os seus discípulos.' },
      { v: 55, en: 'Now the Passover of the Jews was at hand. Many went up from the country to Jerusalem before the Passover, to purify themselves.', pt: 'Ora, estava próxima a páscoa dos judeus, e dessa região subiram muitos a Jerusalém, antes da páscoa, para se purificarem.' },
      { v: 56, en: 'Then they sought for Jesus and spoke one with another, as they stood in the temple, “What do you think—that he isn’t coming to the feast at all?”', pt: 'Buscavam, pois, a Jesus e diziam uns aos outros, estando no templo: Que vos parece? Não virá ele à festa?' },
      { v: 57, en: 'Now the chief priests and the Pharisees had commanded that if anyone knew where he was, he should report it, that they might seize him.', pt: 'Ora, os principais sacerdotes e os fariseus tinham dado ordem que, se alguém soubesse onde ele estava, o denunciasse, para que o prendessem.' },
    ],
    12: [
      { v: 1, en: 'Then six days before the Passover, Jesus came to Bethany, where Lazarus was, who had been dead, whom he raised from the dead.', pt: 'Veio, pois, Jesus seis dias antes da páscoa, a Betânia, onde estava Lázaro, a quem ele ressuscitara dentre os mortos.' },
      { v: 2, en: 'So they made him a supper there. Martha served, but Lazarus was one of those who sat at the table with him.', pt: 'Deram-lhe ali uma ceia; Marta servia, e Lázaro era um dos que estavam à mesa com ele.' },
      { v: 3, en: 'Mary, therefore, took a pound of ointment of pure nard, very precious, and anointed the feet of Jesus, and wiped his feet with her hair. The house was filled with the fragrance of the ointment.', pt: 'Então Maria, tomando uma libra de bálsamo de nardo puro, de grande preço, ungiu os pés de Jesus, e os enxugou com os seus cabelos; e encheu-se a casa do cheiro do bálsamo.' },
      { v: 4, en: 'Then Judas Iscariot, Simon’s son, one of his disciples, who would betray him, said,', pt: 'Mas Judas Iscariotes, um dos seus discípulos, aquele que o havia de trair disse:' },
      { v: 5, en: '“Why wasn’t this ointment sold for three hundred denarii, and given to the poor?”', pt: 'Por que não se vendeu este bálsamo por trezentos denários e não se deu aos pobres?' },
      { v: 6, en: 'Now he said this, not because he cared for the poor, but because he was a thief, and having the money box, used to steal what was put into it.', pt: 'Ora, ele disse isto, não porque tivesse cuidado dos pobres, mas porque era ladrão e, tendo a bolsa, subtraía o que nela se lançava.' },
      { v: 7, en: 'But Jesus said, “Leave her alone. She has kept this for the day of my burial.', pt: 'Respondeu, pois Jesus: Deixa-a; para o dia da minha preparação para a sepultura o guardou;' },
      { v: 8, en: 'For you always have the poor with you, but you don’t always have me.”', pt: 'porque os pobres sempre os tendes convosco; mas a mim nem sempre me tendes.' },
      { v: 9, en: 'A large crowd therefore of the Jews learned that he was there, and they came, not for Jesus’ sake only, but that they might see Lazarus also, whom he had raised from the dead.', pt: 'E grande número dos judeus chegou a saber que ele estava ali: e afluiram, não só por causa de Jesus mas também para verem a Lázaro, a quem ele ressuscitara dentre os mortos.' },
      { v: 10, en: 'But the chief priests conspired to put Lazarus to death also,', pt: 'Mas os principais sacerdotes deliberaram matar também a Lázaro;' },
      { v: 11, en: 'because on account of him many of the Jews went away and believed in Jesus.', pt: 'porque muitos, por causa dele, deixavam os judeus e criam em Jesus.' },
      { v: 12, en: 'On the next day a great multitude had come to the feast. When they heard that Jesus was coming to Jerusalem,', pt: 'No dia seguinte, as grandes multidões que tinham vindo à festa, ouvindo dizer que Jesus vinha a Jerusalém,' },
      { v: 13, en: 'they took the branches of the palm trees, and went out to meet him, and cried out, “Hosanna! Blessed is he who comes in the name of the Lord, the King of Israel!”', pt: 'tomaram ramos de palmeiras, e saíram-lhe ao encontro, e clamavam: Hosana! Bendito o que vem em nome do Senhor! Bendito o rei de Israel!' },
      { v: 14, en: 'Jesus, having found a young donkey, sat on it. As it is written,', pt: 'E achou Jesus um jumentinho e montou nele, conforme está escrito:' },
      { v: 15, en: '“Don’t be afraid, daughter of Zion. Behold, your King comes, sitting on a donkey’s colt.”', pt: 'Não temas, ó filha de Sião; eis que vem teu Rei, montado sobre o filho de uma jumenta.' },
      { v: 16, en: 'His disciples didn’t understand these things at first, but when Jesus was glorified, then they remembered that these things were written about him, and that they had done these things to him.', pt: 'Os seus discípulos, porém, a princípio não entenderam isto; mas quando Jesus foi glorificado, então eles se lembraram de que estas coisas estavam escritas a respeito dele, e de que assim lhe fizeram.' },
      { v: 17, en: 'The multitude therefore that was with him when he called Lazarus out of the tomb, and raised him from the dead, was testifying about it.', pt: 'Dava-lhe, pois, testemunho a multidão que estava com ele quando chamara a Lázaro da sepultura e o ressuscitara dentre os mortos;' },
      { v: 18, en: 'For this cause also the multitude went and met him, because they heard that he had done this sign.', pt: 'e foi por isso que a multidão lhe saiu ao encontro, por ter ouvido que ele fizera este sinal.' },
      { v: 19, en: 'The Pharisees therefore said among themselves, “See how you accomplish nothing. Behold, the world has gone after him.”', pt: 'De sorte que os fariseus disseram entre si: Vedes que nada aproveitais? eis que o mundo inteiro vai após ele.' },
      { v: 20, en: 'Now there were certain Greeks among those that went up to worship at the feast.', pt: 'Ora, entre os que tinham subido a adorar na festa havia alguns gregos.' },
      { v: 21, en: 'These, therefore, came to Philip, who was from Bethsaida of Galilee, and asked him, saying, “Sir, we want to see Jesus.”', pt: 'Estes, pois, dirigiram-se a Felipe, que era de Betsaida da Galiléia, e rogaram-lhe, dizendo: Senhor, queríamos ver a Jesus.' },
      { v: 22, en: 'Philip came and told Andrew, and in turn, Andrew came with Philip, and they told Jesus.', pt: 'Felipe foi dizê-lo a André, e então André e Felipe foram dizê-lo a Jesus.' },
      { v: 23, en: 'Jesus answered them, “The time has come for the Son of Man to be glorified.', pt: 'Respondeu-lhes Jesus: É chegada a hora de ser glorificado o Filho do homem.' },
      { v: 24, en: 'Most certainly I tell you, unless a grain of wheat falls into the earth and dies, it remains by itself alone. But if it dies, it bears much fruit.', pt: 'Em verdade, em verdade vos digo: Se o grão de trigo caindo na terra não morrer, fica ele só; mas se morrer, dá muito fruto.' },
      { v: 25, en: 'He who loves his life will lose it. He who hates his life in this world will keep it to eternal life.', pt: 'Quem ama a sua vida, perdê-la-á; e quem neste mundo odeia a a sua vida, guardá-la-á para a vida eterna.' },
      { v: 26, en: 'If anyone serves me, let him follow me. Where I am, there will my servant also be. If anyone serves me, the Father will honor him.', pt: 'Se alguém me quiser servir, siga-me; e onde eu estiver, ali estará também o meu servo; se alguém me servir, o Pai o honrará.' },
      { v: 27, en: '“Now my soul is troubled. What shall I say? ‘Father, save me from this time?’ But for this cause I came to this time.', pt: 'Agora a minha alma está perturbada; e que direi eu? Pai, salva-me desta hora? Mas para isto vim a esta hora.' },
      { v: 28, en: 'Father, glorify your name!” Then there came a voice out of the sky, saying, “I have both glorified it, and will glorify it again.”', pt: 'Pai, glorifica o teu nome. Veio, então, do céu esta voz: Já o tenho glorificado, e outra vez o glorificarei.' },
      { v: 29, en: 'The multitude therefore, who stood by and heard it, said that it had thundered. Others said, “An angel has spoken to him.”', pt: 'A multidão, pois, que ali estava, e que a ouvira, dizia ter havido um trovão; outros diziam: Um anjo lhe falou.' },
      { v: 30, en: 'Jesus answered, “This voice hasn’t come for my sake, but for your sakes.', pt: 'Respondeu Jesus: Não veio esta voz por minha causa, mas por causa de vós.' },
      { v: 31, en: 'Now is the judgment of this world. Now the prince of this world will be cast out.', pt: 'Agora é o juízo deste mundo; agora será expulso o príncipe deste mundo.' },
      { v: 32, en: 'And I, if I am lifted up from the earth, will draw all people to myself.”', pt: 'E eu, quando for levantado da terra, todos atrairei a mim.' },
      { v: 33, en: 'But he said this, signifying by what kind of death he should die.', pt: 'Isto dizia, significando de que modo havia de morrer.' },
      { v: 34, en: 'The multitude answered him, “We have heard out of the law that the Christ remains forever. How do you say, ‘The Son of Man must be lifted up?’ Who is this Son of Man?”', pt: 'Respondeu-lhe a multidão: Nós temos ouvido da lei que o Cristo permanece para sempre; e como dizes tu: Importa que o Filho do homem seja levantado? Quem é esse Filho do homem?' },
      { v: 35, en: 'Jesus therefore said to them, “Yet a little while the light is with you. Walk while you have the light, that darkness doesn’t overtake you. He who walks in the darkness doesn’t know where he is going.', pt: 'Disse-lhes então Jesus: Ainda por um pouco de tempo a luz está entre vós. Andai enquanto tendes a luz, para que as trevas não vos apanhem; pois quem anda nas trevas não sabe para onde vai.' },
      { v: 36, en: 'While you have the light, believe in the light, that you may become children of light.” Jesus said these things, and he departed and hid himself from them.', pt: 'Enquanto tendes a luz, crede na luz, para que vos torneis filhos da luz. Havendo Jesus assim falado, retirou-se e escondeu-se deles.' },
      { v: 37, en: 'But though he had done so many signs before them, yet they didn’t believe in him,', pt: 'E embora tivesse operado tantos sinais diante deles, não criam nele;' },
      { v: 38, en: 'that the word of Isaiah the prophet might be fulfilled, which he spoke, “Lord, who has believed our report? To whom has the arm of the Lord been revealed?”', pt: 'para que se cumprisse a palavra do profeta Isaías: Senhor, quem creu em nossa pregação? e aquem foi revelado o braço do Senhor?' },
      { v: 39, en: 'For this cause they couldn’t believe, for Isaiah said again,', pt: 'Por isso não podiam crer, porque, como disse ainda Isaías:' },
      { v: 40, en: '“He has blinded their eyes and he hardened their heart, lest they should see with their eyes, and perceive with their heart, and would turn, and I would heal them.”', pt: 'Cegou-lhes os olhos e endureceu-lhes o coração, para que não vejam com os olhos e entendam com o coração, e se convertam, e eu os cure.' },
      { v: 41, en: 'Isaiah said these things when he saw his glory, and spoke of him.', pt: 'Estas coisas disse Isaías, porque viu a sua glória, e dele falou.' },
      { v: 42, en: 'Nevertheless even of the rulers many believed in him, but because of the Pharisees they didn’t confess it, so that they wouldn’t be put out of the synagogue,', pt: 'Contudo, muitos dentre as próprias autoridades creram nele; mas por causa dos fariseus não o confessavam, para não serem expulsos da sinagoga;' },
      { v: 43, en: 'for they loved men’s praise more than God’s praise.', pt: 'porque amaram mais a glória dos homens do que a glória de Deus.' },
      { v: 44, en: 'Jesus cried out and said, “Whoever believes in me, believes not in me, but in him who sent me.', pt: 'Clamou Jesus, dizendo: Quem crê em mim, crê, nâo em mim, mas naquele que me enviou.' },
      { v: 45, en: 'He who sees me sees him who sent me.', pt: 'E quem me vê a mim, vê aquele que me enviou.' },
      { v: 46, en: 'I have come as a light into the world, that whoever believes in me may not remain in the darkness.', pt: 'Eu, que sou a luz, vim ao mundo, para que todo aquele que crê em mim não permaneça nas trevas.' },
      { v: 47, en: 'If anyone listens to my sayings, and doesn’t believe, I don’t judge him. For I came not to judge the world, but to save the world.', pt: 'E, se alguém ouvir as minhas palavras, e não as guardar, eu não o julgo; pois eu vim, não para julgar o mundo, mas para salvar o mundo.' },
      { v: 48, en: 'He who rejects me, and doesn’t receive my sayings, has one who judges him. The word that I spoke, the same will judge him in the last day.', pt: 'Quem me rejeita, e não recebe as minhas palavras, já tem quem o julgue; a palavra que tenho pregado, essa o julgará no último dia.' },
      { v: 49, en: 'For I spoke not from myself, but the Father who sent me, he gave me a commandment, what I should say, and what I should speak.', pt: 'Porque eu não falei por mim mesmo; mas o Pai, que me enviou, esse me deu mandamento quanto ao que dizer e como falar.' },
      { v: 50, en: 'I know that his commandment is eternal life. The things therefore which I speak, even as the Father has said to me, so I speak.”', pt: 'E sei que o seu mandamento é vida eterna. Aquilo, pois, que eu falo, falo-o exatamente como o Pai me ordenou.' },
    ],
    13: [
      { v: 1, en: 'Now before the feast of the Passover, Jesus, knowing that his time had come that he would depart from this world to the Father, having loved his own who were in the world, he loved them to the end.', pt: 'Antes da festa da páscoa, sabendo Jesus que era chegada a sua hora de passar deste mundo para o Pai, e havendo amado os seus que estavam no mundo, amou-os até o fim.' },
      { v: 2, en: 'During supper, the devil having already put into the heart of Judas Iscariot, Simon’s son, to betray him,', pt: 'Enquanto ceavam, tendo já o Diabo posto no coração de Judas, filho de Simão Iscariotes, que o traísse,' },
      { v: 3, en: 'Jesus, knowing that the Father had given all things into his hands, and that he came from God, and was going to God,', pt: 'Jesus, sabendo que o Pai lhe entregara tudo nas mãos, e que viera de Deus e para Deus voltava,' },
      { v: 4, en: 'arose from supper, and laid aside his outer garments. He took a towel, and wrapped a towel around his waist.', pt: 'levantou-se da ceia, tirou o manto e, tomando uma toalha, cingiu-se.' },
      { v: 5, en: 'Then he poured water into the basin, and began to wash the disciples’ feet, and to wipe them with the towel that was wrapped around him.', pt: 'Depois deitou água na bacia e começou a lavar os pés aos discípulos, e a enxugar-lhos com a toalha com que estava cingido.' },
      { v: 6, en: 'Then he came to Simon Peter. He said to him, “Lord, do you wash my feet?”', pt: 'Chegou, pois, a Simão Pedro, que lhe disse: Senhor, lavas-me os pés a mim?' },
      { v: 7, en: 'Jesus answered him, “You don’t know what I am doing now, but you will understand later.”', pt: 'Respondeu-lhe Jesus: O que eu faço, tu não o sabes agora; mas depois o entenderás.' },
      { v: 8, en: 'Peter said to him, “You will never wash my feet!” Jesus answered him, “If I don’t wash you, you have no part with me.”', pt: 'Tornou-lhe Pedro: Nunca me lavarás os pés. Replicou-lhe Jesus: Se eu não te lavar, não tens parte comigo.' },
      { v: 9, en: 'Simon Peter said to him, “Lord, not my feet only, but also my hands and my head!”', pt: 'Disse-lhe Simão Pedro: Senhor, não somente os meus pés, mas também as mãos e a cabeça.' },
      { v: 10, en: 'Jesus said to him, “Someone who has bathed only needs to have his feet washed, but is completely clean. You are clean, but not all of you.”', pt: 'Respondeu-lhe Jesus: Aquele que se banhou não necessita de lavar senão os pés, pois no mais está todo limpo; e vós estais limpos, mas não todos.' },
      { v: 11, en: 'For he knew him who would betray him, therefore he said, “You are not all clean.”', pt: 'Pois ele sabia quem o estava traindo; por isso disse: Nem todos estais limpos.' },
      { v: 12, en: 'So when he had washed their feet, put his outer garment back on, and sat down again, he said to them, “Do you know what I have done to you?', pt: 'Ora, depois de lhes ter lavado os pés, tomou o manto, tornou a reclinar-se à mesa e perguntou-lhes: Entendeis o que vos tenho feito?' },
      { v: 13, en: 'You call me, ‘Teacher’ and ‘Lord.’ You say so correctly, for so I am.', pt: 'Vós me chamais Mestre e Senhor; e dizeis bem, porque eu o sou.' },
      { v: 14, en: 'If I then, the Lord and the Teacher, have washed your feet, you also ought to wash one another’s feet.', pt: 'Ora, se eu, o Senhor e Mestre, vos lavei os pés, também vós deveis lavar os pés uns aos outros.' },
      { v: 15, en: 'For I have given you an example, that you also should do as I have done to you.', pt: 'Porque eu vos dei exemplo, para que, como eu vos fiz, façais vós também.' },
      { v: 16, en: 'Most certainly I tell you, a servant is not greater than his lord, neither one who is sent greater than he who sent him.', pt: 'Em verdade, em verdade vos digo: Não é o servo maior do que o seu senhor, nem o enviado maior do que aquele que o enviou.' },
      { v: 17, en: 'If you know these things, blessed are you if you do them.', pt: 'Se sabeis estas coisas, bem-aventurados sois se as praticardes.' },
      { v: 18, en: 'I don’t speak concerning all of you. I know whom I have chosen. But that the Scripture may be fulfilled, ‘He who eats bread with me has lifted up his heel against me.’', pt: 'Não falo de todos vós; eu conheço aqueles que escolhi; mas para que se cumprisse a escritura: O que comia do meu pão, levantou contra mim o seu calcanhar.' },
      { v: 19, en: 'From now on, I tell you before it happens, that when it happens, you may believe that I am he.', pt: 'Desde já no-lo digo, antes que suceda, para que, quando suceder, creiais que eu sou.' },
      { v: 20, en: 'Most certainly I tell you, he who receives whomever I send, receives me; and he who receives me, receives him who sent me.”', pt: 'Em verdade, em verdade vos digo: Quem receber aquele que eu enviar, a mim me recebe; e quem me recebe a mim, recebe aquele que me enviou.' },
      { v: 21, en: 'When Jesus had said this, he was troubled in spirit, and testified, “Most certainly I tell you that one of you will betray me.”', pt: 'Tendo Jesus dito isto, turbou-se em espírito, e declarou: Em verdade, em verdade vos digo que um de vós me há de trair.' },
      { v: 22, en: 'The disciples looked at one another, perplexed about whom he spoke.', pt: 'Os discípulos se entreolhavam, perplexos, sem saber de quem ele falava.' },
      { v: 23, en: 'One of his disciples, whom Jesus loved, was at the table, leaning against Jesus’ breast.', pt: 'Ora, achava-se reclinado sobre o peito de Jesus um de seus discípulos, aquele a quem Jesus amava.' },
      { v: 24, en: 'Simon Peter therefore beckoned to him, and said to him, “Tell us who it is of whom he speaks.”', pt: 'A esse, pois, fez Simão Pedro sinal, e lhe pediu: Pergunta- lhe de quem é que fala.' },
      { v: 25, en: 'He, leaning back, as he was, on Jesus’ breast, asked him, “Lord, who is it?”', pt: 'Aquele discípulo, recostando-se assim ao peito de Jesus, perguntou-lhe: Senhor, quem é?' },
      { v: 26, en: 'Jesus therefore answered, “It is he to whom I will give this piece of bread when I have dipped it.” So when he had dipped the piece of bread, he gave it to Judas, the son of Simon Iscariot.', pt: 'Respondeu Jesus: É aquele a quem eu der o pedaço de pão molhado. Tendo, pois, molhado um bocado de pão, deu-o a Judas, filho de Simão Iscariotes.' },
      { v: 27, en: 'After the piece of bread, then Satan entered into him. Then Jesus said to him, “What you do, do quickly.”', pt: 'E, logo após o bocado, entrou nele Satanás. Disse-lhe, pois, Jesus: O que fazes, faze-o depressa.' },
      { v: 28, en: 'Now no man at the table knew why he said this to him.', pt: 'E nenhum dos que estavam à mesa percebeu a que propósito lhe disse isto;' },
      { v: 29, en: 'For some thought, because Judas had the money box, that Jesus said to him, “Buy what things we need for the feast,” or that he should give something to the poor.', pt: 'pois, como Judas tinha a bolsa, pensavam alguns que Jesus lhe queria dizer: Compra o que nos é necessário para a festa; ou, que desse alguma coisa aos pobres.' },
      { v: 30, en: 'Therefore having received that morsel, he went out immediately. It was night.', pt: 'Então ele, tendo recebido o bocado saiu logo. E era noite.' },
      { v: 31, en: 'When he had gone out, Jesus said, “Now the Son of Man has been glorified, and God has been glorified in him.', pt: 'Tendo ele, pois, saído, disse Jesus: Agora é glorificado o Filho do homem, e Deus é glorificado nele;' },
      { v: 32, en: 'If God has been glorified in him, God will also glorify him in himself, and he will glorify him immediately.', pt: 'se Deus é glorificado nele, também Deus o glorificará em si mesmo, e logo o há de glorificar.' },
      { v: 33, en: 'Little children, I will be with you a little while longer. You will seek me, and as I said to the Jews, ‘Where I am going, you can’t come,’ so now I tell you.', pt: 'Filhinhos, ainda por um pouco estou convosco. Procurar-me- eis; e, como eu disse aos judeus, também a vós o digo agora: Para onde eu vou, não podeis vós ir.' },
      { v: 34, en: 'A new commandment I give to you, that you love one another. Just as I have loved you, you also love one another.', pt: 'Um novo mandamento vos dou: que vos ameis uns aos outros; assim como eu vos amei a vós, que também vós vos ameis uns aos outros.' },
      { v: 35, en: 'By this everyone will know that you are my disciples, if you have love for one another.”', pt: 'Nisto conhecerão todos que sois meus discípulos, se tiverdes amor uns aos outros.' },
      { v: 36, en: 'Simon Peter said to him, “Lord, where are you going?” Jesus answered, “Where I am going, you can’t follow now, but you will follow afterwards.”', pt: 'Perguntou-lhe Simão Pedro: Senhor, para onde vais? Respondeu Jesus; Para onde eu vou, não podes agora seguir-me; mais tarde, porém, me seguirás.' },
      { v: 37, en: 'Peter said to him, “Lord, why can’t I follow you now? I will lay down my life for you.”', pt: 'Disse-lhe Pedro: Por que não posso seguir-te agora? Por ti darei a minha vida.' },
      { v: 38, en: 'Jesus answered him, “Will you lay down your life for me? Most certainly I tell you, the rooster won’t crow until you have denied me three times.', pt: 'Respondeu Jesus: Darás a tua vida por mim? Em verdade, em verdade te digo: Não cantará o galo até que me tenhas negado três vezes.' },
    ],
    14: [
      { v: 1, en: '“Don’t let your heart be troubled. Believe in God. Believe also in me.', pt: 'Não se turbe o vosso coração; credes em Deus, crede também em mim.' },
      { v: 2, en: 'In my Father’s house are many homes. If it weren’t so, I would have told you. I am going to prepare a place for you.', pt: 'Na casa de meu Pai há muitas moradas; se não fosse assim, eu vo-lo teria dito; vou preparar-vos lugar.' },
      { v: 3, en: 'If I go and prepare a place for you, I will come again, and will receive you to myself; that where I am, you may be there also.', pt: 'E, se eu for e vos preparar lugar, virei outra vez, e vos tomarei para mim mesmo, para que onde eu estiver estejais vós também.' },
      { v: 4, en: 'Where I go, you know, and you know the way.”', pt: 'E para onde eu vou vós conheceis o caminho.' },
      { v: 5, en: 'Thomas said to him, “Lord, we don’t know where you are going. How can we know the way?”', pt: 'Disse-lhe Tomé: Senhor, não sabemos para onde vais; e como podemos saber o caminho?' },
      { v: 6, en: 'Jesus said to him, “I am the way, the truth, and the life. No one comes to the Father, except through me.', pt: 'Respondeu-lhe Jesus: Eu sou o caminho, e a verdade, e a vida; ninguém vem ao Pai, senão por mim.' },
      { v: 7, en: 'If you had known me, you would have known my Father also. From now on, you know him, and have seen him.”', pt: 'Se vós me conhecêsseis a mim, também conheceríeis a meu Pai; e já desde agora o conheceis, e o tendes visto.' },
      { v: 8, en: 'Philip said to him, “Lord, show us the Father, and that will be enough for us.”', pt: 'Disse-lhe Felipe: Senhor, mostra-nos o Pai, e isso nos basta.' },
      { v: 9, en: 'Jesus said to him, “Have I been with you such a long time, and do you not know me, Philip? He who has seen me has seen the Father. How do you say, ‘Show us the Father?’', pt: 'Respondeu-lhe Jesus: Há tanto tempo que estou convosco, e ainda não me conheces, Felipe? Quem me viu a mim, viu o Pai; como dizes tu: Mostra-nos o Pai?' },
      { v: 10, en: 'Don’t you believe that I am in the Father, and the Father in me? The words that I tell you, I speak not from myself; but the Father who lives in me does his works.', pt: 'Não crês tu que eu estou no Pai, e que o Pai está em mim? As palavras que eu vos digo, não as digo por mim mesmo; mas o Pai, que permanece em mim, é quem faz as suas obras.' },
      { v: 11, en: 'Believe me that I am in the Father, and the Father in me; or else believe me for the very works’ sake.', pt: 'Crede-me que eu estou no Pai, e que o Pai está em mim; crede ao menos por causa das mesmas obras.' },
      { v: 12, en: 'Most certainly I tell you, he who believes in me, the works that I do, he will do also; and he will do greater works than these, because I am going to my Father.', pt: 'Em verdade, em verdade vos digo: Aquele que crê em mim, esse também fará as obras que eu faço, e as fará maiores do que estas; porque eu vou para o Pai;' },
      { v: 13, en: 'Whatever you will ask in my name, that will I do, that the Father may be glorified in the Son.', pt: 'e tudo quanto pedirdes em meu nome, eu o farei, para que o Pai seja glorificado no Filho.' },
      { v: 14, en: 'If you will ask anything in my name, I will do it.', pt: 'Se me pedirdes alguma coisa em meu nome, eu a farei.' },
      { v: 15, en: 'If you love me, keep my commandments.', pt: 'Se me amardes, guardareis os meus mandamentos.' },
      { v: 16, en: 'I will pray to the Father, and he will give you another Counselor, that he may be with you forever,—', pt: 'E eu rogarei ao Pai, e ele vos dará outro Ajudador, para que fique convosco para sempre.' },
      { v: 17, en: 'the Spirit of truth, whom the world can’t receive; for it doesn’t see him, neither knows him. You know him, for he lives with you, and will be in you.', pt: 'a saber, o Espírito da verdade, o qual o mundo não pode receber; porque não o vê nem o conhece; mas vós o conheceis, porque ele habita convosco, e estará em vós.' },
      { v: 18, en: 'I will not leave you orphans. I will come to you.', pt: 'Não vos deixarei órfãos; voltarei a vós.' },
      { v: 19, en: 'Yet a little while, and the world will see me no more; but you will see me. Because I live, you will live also.', pt: 'Ainda um pouco, e o mundo não me verá mais; mas vós me vereis, porque eu vivo, e vós vivereis.' },
      { v: 20, en: 'In that day you will know that I am in my Father, and you in me, and I in you.', pt: 'Naquele dia conhecereis que estou em meu Pai, e vós em mim, e eu em vós.' },
      { v: 21, en: 'One who has my commandments, and keeps them, that person is one who loves me. One who loves me will be loved by my Father, and I will love him, and will reveal myself to him.”', pt: 'Aquele que tem os meus mandamentos e os guarda, esse é o que me ama; e aquele que me ama será amado de meu Pai, e eu o amarei, e me manifestarei a ele.' },
      { v: 22, en: 'Judas (not Iscariot) said to him, “Lord, what has happened that you are about to reveal yourself to us, and not to the world?”', pt: 'Perguntou-lhe Judas (não o Iscariotes): O que houve, Senhor, que te hás de manifestar a nós, e não ao mundo?' },
      { v: 23, en: 'Jesus answered him, “If a man loves me, he will keep my word. My Father will love him, and we will come to him, and make our home with him.', pt: 'Respondeu-lhe Jesus: Se alguém me amar, guardará a minha palavra; e meu Pai o amará, e viremos a ele, e faremos nele morada.' },
      { v: 24, en: 'He who doesn’t love me doesn’t keep my words. The word which you hear isn’t mine, but the Father’s who sent me.', pt: 'Quem não me ama, não guarda as minhas palavras; ora, a palavra que estais ouvindo não é minha, mas do Pai que me enviou.' },
      { v: 25, en: 'I have said these things to you, while still living with you.', pt: 'Estas coisas vos tenho falado, estando ainda convosco.' },
      { v: 26, en: 'But the Counselor, the Holy Spirit, whom the Father will send in my name, he will teach you all things, and will remind you of all that I said to you.', pt: 'Mas o Ajudador, o Espírito Santo a quem o Pai enviará em meu nome, esse vos ensinará todas as coisas, e vos fará lembrar de tudo quanto eu vos tenho dito.' },
      { v: 27, en: 'Peace I leave with you. My peace I give to you; not as the world gives, give I to you. Don’t let your heart be troubled, neither let it be fearful.', pt: 'Deixo-vos a paz, a minha paz vos dou; eu não vo-la dou como o mundo a dá. Não se turbe o vosso coração, nem se atemorize.' },
      { v: 28, en: 'You heard how I told you, ‘I go away, and I come to you.’ If you loved me, you would have rejoiced, because I said ‘I am going to my Father;’ for the Father is greater than I.', pt: 'Ouvistes que eu vos disse: Vou, e voltarei a vós. Se me amásseis, alegrar-vos-íeis de que eu vá para o Pai; porque o Pai é maior do que eu.' },
      { v: 29, en: 'Now I have told you before it happens so that, when it happens, you may believe.', pt: 'Eu vo-lo disse agora, antes que aconteça, para que, quando acontecer, vós creiais.' },
      { v: 30, en: 'I will no more speak much with you, for the prince of the world comes, and he has nothing in me.', pt: 'Já não falarei muito convosco, porque vem o príncipe deste mundo, e ele nada tem em mim;' },
      { v: 31, en: 'But that the world may know that I love the Father, and as the Father commanded me, even so I do. Arise, let us go from here.', pt: 'mas, assim como o Pai me ordenou, assim mesmo faço, para que o mundo saiba que eu amo o Pai. Levantai-vos, vamo-nos daqui.' },
    ],
    15: [
      { v: 1, en: '“I am the true vine, and my Father is the farmer.', pt: 'Eu sou a videira verdadeira, e meu Pai é o viticultor.' },
      { v: 2, en: 'Every branch in me that doesn’t bear fruit, he takes away. Every branch that bears fruit, he prunes, that it may bear more fruit.', pt: 'Toda vara em mim que não dá fruto, ele a corta; e toda vara que dá fruto, ele a limpa, para que dê mais fruto.' },
      { v: 3, en: 'You are already pruned clean because of the word which I have spoken to you.', pt: 'Vós já estais limpos pela palavra que vos tenho falado.' },
      { v: 4, en: 'Remain in me, and I in you. As the branch can’t bear fruit by itself, unless it remains in the vine, so neither can you, unless you remain in me.', pt: 'Permanecei em mim, e eu permanecerei em vós; como a vara de si mesma não pode dar fruto, se não permanecer na videira, assim também vós, se não permanecerdes em mim.' },
      { v: 5, en: 'I am the vine. You are the branches. He who remains in me, and I in him, the same bears much fruit, for apart from me you can do nothing.', pt: 'Eu sou a videira; vós sois as varas. Quem permanece em mim e eu nele, esse dá muito fruto; porque sem mim nada podeis fazer.' },
      { v: 6, en: 'If a man doesn’t remain in me, he is thrown out as a branch, and is withered; and they gather them, throw them into the fire, and they are burned.', pt: 'Quem não permanece em mim é lançado fora, como a vara, e seca; tais varas são recolhidas, lançadas no fogo e queimadas.' },
      { v: 7, en: 'If you remain in me, and my words remain in you, you will ask whatever you desire, and it will be done for you.', pt: 'Se vós permanecerdes em mim, e as minhas palavras permanecerem em vós, pedi o que quiserdes, e vos será feito.' },
      { v: 8, en: '“In this is my Father glorified, that you bear much fruit; and so you will be my disciples.', pt: 'Nisto é glorificado meu Pai, que deis muito fruto; e assim sereis meus discípulos.' },
      { v: 9, en: 'Even as the Father has loved me, I also have loved you. Remain in my love.', pt: 'Como o Pai me amou, assim também eu vos amei; permanecei no meu amor.' },
      { v: 10, en: 'If you keep my commandments, you will remain in my love; even as I have kept my Father’s commandments, and remain in his love.', pt: 'Se guardardes os meus mandamentos, permanecereis no meu amor; do mesmo modo que eu tenho guardado os mandamentos de meu Pai, e permaneço no seu amor.' },
      { v: 11, en: 'I have spoken these things to you, that my joy may remain in you, and that your joy may be made full.', pt: 'Estas coisas vos tenho dito, para que o meu gozo permaneça em vós, e o vosso gozo seja completo.' },
      { v: 12, en: '“This is my commandment, that you love one another, even as I have loved you.', pt: 'O meu mandamento é este: Que vos ameis uns aos outros, assim como eu vos amei.' },
      { v: 13, en: 'Greater love has no one than this, that someone lay down his life for his friends.', pt: 'Ninguém tem maior amor do que este, de dar alguém a sua vida pelos seus amigos.' },
      { v: 14, en: 'You are my friends, if you do whatever I command you.', pt: 'Vós sois meus amigos, se fizerdes o que eu vos mando.' },
      { v: 15, en: 'No longer do I call you servants, for the servant doesn’t know what his lord does. But I have called you friends, for everything that I heard from my Father, I have made known to you.', pt: 'Já não vos chamo servos, porque o servo não sabe o que faz o seu senhor; mas chamei-vos amigos, porque tudo quanto ouvi de meu Pai vos dei a conhecer.' },
      { v: 16, en: 'You didn’t choose me, but I chose you, and appointed you, that you should go and bear fruit, and that your fruit should remain; that whatever you will ask of the Father in my name, he may give it to you.', pt: 'Vós não me escolhestes a mim mas eu vos escolhi a vós, e vos designei, para que vades e deis frutos, e o vosso fruto permaneça, a fim de que tudo quanto pedirdes ao Pai em meu nome, ele vo-lo conceda.' },
      { v: 17, en: '“I command these things to you, that you may love one another.', pt: 'Isto vos mando: que vos ameis uns aos outros.' },
      { v: 18, en: 'If the world hates you, you know that it has hated me before it hated you.', pt: 'Se o mundo vos odeia, sabei que, primeiro do que a vós, me odiou a mim.' },
      { v: 19, en: 'If you were of the world, the world would love its own. But because you are not of the world, since I chose you out of the world, therefore the world hates you.', pt: 'Se fôsseis do mundo, o mundo amaria o que era seu; mas, porque não sois do mundo, antes eu vos escolhi do mundo, por isso é que o mundo vos odeia.' },
      { v: 20, en: 'Remember the word that I said to you: ‘A servant is not greater than his lord.’ If they persecuted me, they will also persecute you. If they kept my word, they will also keep yours.', pt: 'Lembrai-vos da palavra que eu vos disse: Não é o servo maior do que o seu senhor. Se a mim me perseguiram, também vos perseguirão a vós; se guardaram a minha palavra, guardarão também a vossa.' },
      { v: 21, en: 'But all these things will they do to you for my name’s sake, because they don’t know him who sent me.', pt: 'Mas tudo isto vos farão por causa do meu nome, porque não conhecem aquele que me enviou.' },
      { v: 22, en: 'If I had not come and spoken to them, they would not have had sin; but now they have no excuse for their sin.', pt: 'Se eu não viera e não lhes falara, não teriam pecado; agora, porém, não têm desculpa do seu pecado.' },
      { v: 23, en: 'He who hates me, hates my Father also.', pt: 'Aquele que me odeia a mim, odeia também a meu Pai.' },
      { v: 24, en: 'If I hadn’t done among them the works which no one else did, they wouldn’t have had sin. But now have they seen and also hated both me and my Father.', pt: 'Se eu entre eles não tivesse feito tais obras, quais nenhum outro fez, não teriam pecado; mas agora, não somente viram, mas também odiaram tanto a mim como a meu Pai.' },
      { v: 25, en: 'But this happened so that the word may be fulfilled which was written in their law, ‘They hated me without a cause.’', pt: 'Mas isto é para que se cumpra a palavra que está escrita na sua lei: Odiaram-me sem causa.' },
      { v: 26, en: '“When the Counselor has come, whom I will send to you from the Father, the Spirit of truth, who proceeds from the Father, he will testify about me.', pt: 'Quando vier o Ajudador, que eu vos enviarei da parte do Pai, o Espírito da verdade, que do Pai procede, esse dará testemunho de mim;' },
      { v: 27, en: 'You will also testify, because you have been with me from the beginning.', pt: 'e também vós dareis testemunho, porque estais comigo desde o princípio.' },
    ],
    16: [
      { v: 1, en: '“I have said these things to you so that you wouldn’t be caused to stumble.', pt: 'Tenho-vos dito estas coisas para que não vos escandalizeis.' },
      { v: 2, en: 'They will put you out of the synagogues. Yes, the time comes that whoever kills you will think that he offers service to God.', pt: 'Expulsar-vos-ão das sinagogas; ainda mais, vem a hora em que qualquer que vos matar julgará prestar um serviço a Deus.' },
      { v: 3, en: 'They will do these things because they have not known the Father, nor me.', pt: 'E isto vos farão, porque não conheceram ao Pai nem a mim.' },
      { v: 4, en: 'But I have told you these things, so that when the time comes, you may remember that I told you about them. I didn’t tell you these things from the beginning, because I was with you.', pt: 'Mas tenho-vos dito estas coisas, a fim de que, quando chegar aquela hora, vos lembreis de que eu vo-las tinha dito. Não vo-las disse desde o princípio, porque estava convosco.' },
      { v: 5, en: 'But now I am going to him who sent me, and none of you asks me, ‘Where are you going?’', pt: 'Agora, porém, vou para aquele que me enviou; e nenhum de vós me pergunta: Para onde vais?' },
      { v: 6, en: 'But because I have told you these things, sorrow has filled your heart.', pt: 'Antes, porque vos disse isto, o vosso coração se encheu de tristeza.' },
      { v: 7, en: 'Nevertheless I tell you the truth: It is to your advantage that I go away, for if I don’t go away, the Counselor won’t come to you. But if I go, I will send him to you.', pt: 'Todavia, digo-vos a verdade, convém-vos que eu vá; pois se eu não for, o Ajudador não virá a vós; mas, se eu for, vo-lo enviarei.' },
      { v: 8, en: 'When he has come, he will convict the world about sin, about righteousness, and about judgment;', pt: 'E quando ele vier, convencerá o mundo do pecado, da justiça e do juízo:' },
      { v: 9, en: 'about sin, because they don’t believe in me;', pt: 'do pecado, porque não crêem em mim;' },
      { v: 10, en: 'about righteousness, because I am going to my Father, and you won’t see me any more;', pt: 'da justiça, porque vou para meu Pai, e não me vereis mais,' },
      { v: 11, en: 'about judgment, because the prince of this world has been judged.', pt: 'e do juízo, porque o príncipe deste mundo já está julgado.' },
      { v: 12, en: '“I have yet many things to tell you, but you can’t bear them now.', pt: 'Ainda tenho muito que vos dizer; mas vós não o podeis suportar agora.' },
      { v: 13, en: 'However when he, the Spirit of truth, has come, he will guide you into all truth, for he will not speak from himself; but whatever he hears, he will speak. He will declare to you things that are coming.', pt: 'Quando vier, porém, aquele, o Espírito da verdade, ele vos guiará a toda a verdade; porque não falará por si mesmo, mas dirá o que tiver ouvido, e vos anunciará as coisas vindouras.' },
      { v: 14, en: 'He will glorify me, for he will take from what is mine, and will declare it to you.', pt: 'Ele me glorificará, porque receberá do que é meu, e vo-lo anunciará.' },
      { v: 15, en: 'All things whatever the Father has are mine; therefore I said that he takes of mine, and will declare it to you.', pt: 'Tudo quanto o Pai tem é meu; por isso eu vos disse que ele, recebendo do que é meu, vo-lo anunciará.' },
      { v: 16, en: 'A little while, and you will not see me. Again a little while, and you will see me.”', pt: 'Um pouco, e já não me vereis; e outra vez um pouco, e ver-me-eis.' },
      { v: 17, en: 'Some of his disciples therefore said to one another, “What is this that he says to us, ‘A little while, and you won’t see me, and again a little while, and you will see me;’ and, ‘Because I go to the Father’ ?”', pt: 'Então alguns dos seus discípulos perguntaram uns para os outros: Que é isto que nos diz? Um pouco, e não me vereis; e outra vez um pouco, e ver-me-eis; e: Porquanto vou para o Pai?' },
      { v: 18, en: 'They said therefore, “What is this that he says, ‘A little while’ ? We don’t know what he is saying.”', pt: 'Diziam pois: Que quer dizer isto: Um pouco? Não compreendemos o que ele está dizendo.' },
      { v: 19, en: 'Therefore Jesus perceived that they wanted to ask him, and he said to them, “Do you inquire among yourselves concerning this, that I said, ‘A little while, and you won’t see me, and again a little while, and you will see me?’', pt: 'Percebeu Jesus que o queriam interrogar, e disse-lhes: Indagais entre vós acerca disto que disse: Um pouco, e não me vereis; e outra vez um pouco, e ver-me-eis?' },
      { v: 20, en: 'Most certainly I tell you, that you will weep and lament, but the world will rejoice. You will be sorrowful, but your sorrow will be turned into joy.', pt: 'Em verdade, em verdade, vos digo que vós chorareis e vos lamentareis, mas o mundo se alegrará; vós estareis tristes, porém a vossa tristeza se converterá em alegria.' },
      { v: 21, en: 'A woman, when she gives birth, has sorrow, because her time has come. But when she has delivered the child, she doesn’t remember the anguish any more, for the joy that a human being is born into the world.', pt: 'A mulher, quando está para dar à luz, sente tristeza porque é chegada a sua hora; mas, depois de ter dado à luz a criança, já não se lembra da aflição, pelo gozo de haver um homem nascido ao mundo.' },
      { v: 22, en: 'Therefore you now have sorrow, but I will see you again, and your heart will rejoice, and no one will take your joy away from you.', pt: 'Assim também vós agora, na verdade, tendes tristeza; mas eu vos tornarei a ver, e alegrar-se-á o vosso coração, e a vossa alegria ninguém vo-la tirará.' },
      { v: 23, en: '“In that day you will ask me no questions. Most certainly I tell you, whatever you may ask of the Father in my name, he will give it to you.', pt: 'Naquele dia nada me perguntareis. Em verdade, em verdade vos digo que tudo quanto pedirdes ao Pai, ele vo-lo concederá em meu nome.' },
      { v: 24, en: 'Until now, you have asked nothing in my name. Ask, and you will receive, that your joy may be made full.', pt: 'Até agora nada pedistes em meu nome; pedi, e recebereis, para que o vosso gozo seja completo.' },
      { v: 25, en: 'I have spoken these things to you in figures of speech. But the time is coming when I will no more speak to you in figures of speech, but will tell you plainly about the Father.', pt: 'Disse-vos estas coisas por figuras; chega, porém, a hora em que vos não falarei mais por figuras, mas abertamente vos falarei acerca do Pai.' },
      { v: 26, en: 'In that day you will ask in my name; and I don’t say to you, that I will pray to the Father for you,', pt: 'Naquele dia pedireis em meu nome, e não vos digo que eu rogarei por vós ao Pai;' },
      { v: 27, en: 'for the Father himself loves you, because you have loved me, and have believed that I came from God.', pt: 'pois o Pai mesmo vos ama; visto que vós me amastes e crestes que eu saí de Deus.' },
      { v: 28, en: 'I came from the Father, and have come into the world. Again, I leave the world, and go to the Father.”', pt: 'Saí do Pai, e vim ao mundo; outra vez deixo o mundo, e vou para o Pai.' },
      { v: 29, en: 'His disciples said to him, “Behold, now you are speaking plainly, and using no figures of speech.', pt: 'Disseram os seus discípulos: Eis que agora falas abertamente, e não por figura alguma.' },
      { v: 30, en: 'Now we know that you know all things, and don’t need for anyone to question you. By this we believe that you came from God.”', pt: 'Agora conhecemos que sabes todas as coisas, e não necessitas de que alguém te interrogue. Por isso cremos que saíste de Deus.' },
      { v: 31, en: 'Jesus answered them, “Do you now believe?', pt: 'Respondeu-lhes Jesus: Credes agora?' },
      { v: 32, en: 'Behold, the time is coming, yes, and has now come, that you will be scattered, everyone to his own place, and you will leave me alone. Yet I am not alone, because the Father is with me.', pt: 'Eis que vem a hora, e já é chegada, em que vós sereis dispersos cada um para o seu lado, e me deixareis só; mas não estou só, porque o Pai está comigo.' },
      { v: 33, en: 'I have told you these things, that in me you may have peace. In the world you have oppression; but cheer up! I have overcome the world.”', pt: 'Tenho-vos dito estas coisas, para que em mim tenhais paz. No mundo tereis tribulações; mas tende bom ânimo, eu venci o mundo.' },
    ],
    17: [
      { v: 1, en: 'Jesus said these things, and lifting up his eyes to heaven, he said, “Father, the time has come. Glorify your Son, that your Son may also glorify you;', pt: 'Depois de assim falar, Jesus, levantando os olhos ao céu, disse: Pai, é chegada a hora; glorifica a teu Filho, para que também o Filho te glorifique;' },
      { v: 2, en: 'even as you gave him authority over all flesh, so he will give eternal life to all whom you have given him.', pt: 'assim como lhe deste autoridade sobre toda a carne, para que dê a vida eterna a todos aqueles que lhe tens dado.' },
      { v: 3, en: 'This is eternal life, that they should know you, the only true God, and him whom you sent, Jesus Christ.', pt: 'E a vida eterna é esta: que te conheçam a ti, como o único Deus verdadeiro, e a Jesus Cristo, aquele que tu enviaste.' },
      { v: 4, en: 'I glorified you on the earth. I have accomplished the work which you have given me to do.', pt: 'Eu te glorifiquei na terra, completando a obra que me deste para fazer.' },
      { v: 5, en: 'Now, Father, glorify me with your own self with the glory which I had with you before the world existed.', pt: 'Agora, pois, glorifica-me tu, ó Pai, junto de ti mesmo, com aquela glória que eu tinha contigo antes que o mundo existisse.' },
      { v: 6, en: 'I revealed your name to the people whom you have given me out of the world. They were yours, and you have given them to me. They have kept your word.', pt: 'Manifestei o teu nome aos homens que do mundo me deste. Eram teus, e tu mos deste; e guardaram a tua palavra.' },
      { v: 7, en: 'Now they have known that all things whatever you have given me are from you,', pt: 'Agora sabem que tudo quanto me deste provém de ti;' },
      { v: 8, en: 'for the words which you have given me I have given to them, and they received them, and knew for sure that I came from you, and they have believed that you sent me.', pt: 'porque eu lhes dei as palavras que tu me deste, e eles as receberam, e verdadeiramente conheceram que saí de ti, e creram que tu me enviaste.' },
      { v: 9, en: 'I pray for them. I don’t pray for the world, but for those whom you have given me, for they are yours.', pt: 'Eu rogo por eles; não rogo pelo mundo, mas por aqueles que me tens dado, porque são teus;' },
      { v: 10, en: 'All things that are mine are yours, and yours are mine, and I am glorified in them.', pt: 'todas as minhas coisas são tuas, e as tuas coisas são minhas; e neles sou glorificado.' },
      { v: 11, en: 'I am no more in the world, but these are in the world, and I am coming to you. Holy Father, keep them through your name which you have given me, that they may be one, even as we are.', pt: 'Eu não estou mais no mundo; mas eles estão no mundo, e eu vou para ti. Pai santo, guarda-os no teu nome, o qual me deste, para que eles sejam um, assim como nós.' },
      { v: 12, en: 'While I was with them in the world, I kept them in your name. Those whom you have given me I have kept. None of them is lost, except the son of destruction, that the Scripture might be fulfilled.', pt: 'Enquanto eu estava com eles, eu os guardava no teu nome que me deste; e os conservei, e nenhum deles se perdeu, senão o filho da perdição, para que se cumprisse a Escritura.' },
      { v: 13, en: 'But now I come to you, and I say these things in the world, that they may have my joy made full in themselves.', pt: 'Mas agora vou para ti; e isto falo no mundo, para que eles tenham a minha alegria completa em si mesmos.' },
      { v: 14, en: 'I have given them your word. The world hated them, because they are not of the world, even as I am not of the world.', pt: 'Eu lhes dei a tua palavra; e o mundo os odiou, porque não são do mundo, assim como eu não sou do mundo.' },
      { v: 15, en: 'I pray not that you would take them from the world, but that you would keep them from the evil one.', pt: 'Não rogo que os tires do mundo, mas que os guardes do Maligno.' },
      { v: 16, en: 'They are not of the world even as I am not of the world.', pt: 'Eles não são do mundo, assim como eu não sou do mundo.' },
      { v: 17, en: 'Sanctify them in your truth. Your word is truth.', pt: 'Santifica-os na verdade, a tua palavra é a verdade.' },
      { v: 18, en: 'As you sent me into the world, even so I have sent them into the world.', pt: 'Assim como tu me enviaste ao mundo, também eu os enviarei ao mundo.' },
      { v: 19, en: 'For their sakes I sanctify myself, that they themselves also may be sanctified in truth.', pt: 'E por eles eu me santifico, para que também eles sejam santificados na verdade.' },
      { v: 20, en: 'Not for these only do I pray, but for those also who will believe in me through their word,', pt: 'E rogo não somente por estes, mas também por aqueles que pela sua palavra hão de crer em mim;' },
      { v: 21, en: 'that they may all be one; even as you, Father, are in me, and I in you, that they also may be one in us; that the world may believe that you sent me.', pt: 'para que todos sejam um; assim como tu, ó Pai, és em mim, e eu em ti, que também eles sejam um em nós; para que o mundo creia que tu me enviaste.' },
      { v: 22, en: 'The glory which you have given me, I have given to them; that they may be one, even as we are one;', pt: 'E eu lhes dei a glória que a mim me deste, para que sejam um, como nós somos um;' },
      { v: 23, en: 'I in them, and you in me, that they may be perfected into one; that the world may know that you sent me, and loved them, even as you loved me.', pt: 'eu neles, e tu em mim, para que eles sejam perfeitos em unidade, a fim de que o mundo conheça que tu me enviaste, e que os amaste a eles, assim como me amaste a mim.' },
      { v: 24, en: 'Father, I desire that they also whom you have given me be with me where I am, that they may see my glory, which you have given me, for you loved me before the foundation of the world.', pt: 'Pai, desejo que onde eu estou, estejam comigo também aqueles que me tens dado, para verem a minha glória, a qual me deste; pois que me amaste antes da fundação do mundo.' },
      { v: 25, en: 'Righteous Father, the world hasn’t known you, but I knew you; and these knew that you sent me.', pt: 'Pai justo, o mundo não te conheceu, mas eu te conheço; conheceram que tu me enviaste;' },
      { v: 26, en: 'I made known to them your name, and will make it known; that the love with which you loved me may be in them, and I in them.”', pt: 'e eu lhes fiz conhecer o teu nome, e lho farei conhecer ainda; para que haja neles aquele amor com que me amaste, e também eu neles esteja.' },
    ],
    18: [
      { v: 1, en: 'When Jesus had spoken these words, he went out with his disciples over the brook Kidron, where there was a garden, into which he and his disciples entered.', pt: 'Tendo Jesus dito isto, saiu com seus discípulos para o outro lado do ribeiro de Cedrom, onde havia um jardim, e com eles ali entrou.' },
      { v: 2, en: 'Now Judas, who betrayed him, also knew the place, for Jesus often met there with his disciples.', pt: 'Ora, Judas, que o traía, também conhecia aquele lugar, porque muitas vezes Jesus se reunira ali com os discípulos.' },
      { v: 3, en: 'Judas then, having taken a detachment of soldiers and officers from the chief priests and the Pharisees, came there with lanterns, torches, and weapons.', pt: 'Tendo, pois, Judas tomado a coorte e uns guardas da parte dos principais sacerdotes e fariseus, chegou ali com lanternas archotes e armas.' },
      { v: 4, en: 'Jesus therefore, knowing all the things that were happening to him, went out, and said to them, “Who are you looking for?”', pt: 'Sabendo, pois, Jesus tudo o que lhe havia de suceder, adiantou-se e perguntou-lhes: A quem buscais?' },
      { v: 5, en: 'They answered him, “Jesus of Nazareth.” Jesus said to them, “I am he.” Judas also, who betrayed him, was standing with them.', pt: 'Responderam-lhe: A Jesus, o nazareno. Disse-lhes Jesus: Sou eu. E Judas, que o traía, também estava com eles.' },
      { v: 6, en: 'When therefore he said to them, “I am he,” they went backward, and fell to the ground.', pt: 'Quando Jesus lhes disse: Sou eu, recuaram, e cairam por terra.' },
      { v: 7, en: 'Again therefore he asked them, “Who are you looking for?” They said, “Jesus of Nazareth.”', pt: 'Tornou-lhes então a perguntar: A quem buscais? e responderam: A Jesus, o nazareno.' },
      { v: 8, en: 'Jesus answered, “I told you that I am he. If therefore you seek me, let these go their way,”', pt: 'Replicou-lhes Jesus: Já vos disse que sou eu; se, pois, é a mim que buscais, deixai ir estes;' },
      { v: 9, en: 'that the word might be fulfilled which he spoke, “Of those whom you have given me, I have lost none.”', pt: 'para que se cumprisse a palavra que dissera: Dos que me tens dado, nenhum deles perdi.' },
      { v: 10, en: 'Simon Peter therefore, having a sword, drew it, and struck the high priest’s servant, and cut off his right ear. The servant’s name was Malchus.', pt: 'Então Simão Pedro, que tinha uma espada, desembainhou-a e feriu o servo do sumo sacerdote, cortando-lhe a orelha direita. O nome do servo era Malco.' },
      { v: 11, en: 'Jesus therefore said to Peter, “Put the sword into its sheath. The cup which the Father has given me, shall I not surely drink it?”', pt: 'Disse, pois, Jesus a Pedro: Mete a tua espada na bainha; não hei de beber o cálice que o Pai me deu?' },
      { v: 12, en: 'So the detachment, the commanding officer, and the officers of the Jews, seized Jesus and bound him,', pt: 'Então a coorte, e o comandante, e os guardas dos judeus prenderam a Jesus, e o maniataram.' },
      { v: 13, en: 'and led him to Annas first, for he was father-in-law to Caiaphas, who was high priest that year.', pt: 'E conduziram-no primeiramente a Anás; pois era sogro de Caifás, sumo sacerdote naquele ano.' },
      { v: 14, en: 'Now it was Caiaphas who advised the Jews that it was expedient that one man should perish for the people.', pt: 'Ora, Caifás era quem aconselhara aos judeus que convinha morrer um homem pelo povo.' },
      { v: 15, en: 'Simon Peter followed Jesus, as did another disciple. Now that disciple was known to the high priest, and entered in with Jesus into the court of the high priest;', pt: 'Simão Pedro e outro discípulo seguiam a Jesus. Este discípulo era conhecido do sumo sacerdote, e entrou com Jesus no pátio do sumo sacerdote,' },
      { v: 16, en: 'but Peter was standing at the door outside. So the other disciple, who was known to the high priest, went out and spoke to her who kept the door, and brought in Peter.', pt: 'enquanto Pedro ficava da parte de fora, à porta. Saiu, então, o outro discípulo que era conhecido do sumo sacerdote, falou à porteira, e levou Pedro para dentro.' },
      { v: 17, en: 'Then the maid who kept the door said to Peter, “Are you also one of this man’s disciples?” He said, “I am not.”', pt: 'Então a porteira perguntou a Pedro: Não és tu também um dos discípulos deste homem? Respondeu ele: Não sou.' },
      { v: 18, en: 'Now the servants and the officers were standing there, having made a fire of coals, for it was cold. They were warming themselves. Peter was with them, standing and warming himself.', pt: 'Ora, estavam ali os servos e os guardas, que tinham acendido um braseiro e se aquentavam, porque fazia frio; e também Pedro estava ali em pé no meio deles, aquentando-se.' },
      { v: 19, en: 'The high priest therefore asked Jesus about his disciples, and about his teaching.', pt: 'Então o sumo sacerdote interrogou Jesus acerca dos seus discípulos e da sua doutrina.' },
      { v: 20, en: 'Jesus answered him, “I spoke openly to the world. I always taught in synagogues, and in the temple, where the Jews always meet. I said nothing in secret.', pt: 'Respondeu-lhe Jesus: Eu tenho falado abertamente ao mundo; eu sempre ensinei nas sinagogas e no templo, onde todos os judeus se congregam, e nada falei em oculto.' },
      { v: 21, en: 'Why do you ask me? Ask those who have heard me what I said to them. Behold, these know the things which I said.”', pt: 'Por que me perguntas a mim? pergunta aos que me ouviram o que é que lhes falei; eis que eles sabem o que eu disse.' },
      { v: 22, en: 'When he had said this, one of the officers standing by slapped Jesus with his hand, saying, “Do you answer the high priest like that?”', pt: 'E, havendo ele dito isso, um dos guardas que ali estavam deu uma bofetada em Jesus, dizendo: É assim que respondes ao sumo sacerdote?' },
      { v: 23, en: 'Jesus answered him, “If I have spoken evil, testify of the evil; but if well, why do you beat me?”', pt: 'Respondeu-lhe Jesus: Se falei mal, dá testemunho do mal; mas, se bem, por que me feres?' },
      { v: 24, en: 'Annas sent him bound to Caiaphas, the high priest.', pt: 'Então Anás o enviou, maniatado, a Caifás, o sumo sacerdote.' },
      { v: 25, en: 'Now Simon Peter was standing and warming himself. They said therefore to him, “You aren’t also one of his disciples, are you?” He denied it, and said, “I am not.”', pt: 'E Simão Pedro ainda estava ali, aquentando-se. Perguntaram- lhe, pois: Não és também tu um dos seus discípulos? Ele negou, e disse: Não sou.' },
      { v: 26, en: 'One of the servants of the high priest, being a relative of him whose ear Peter had cut off, said, “Didn’t I see you in the garden with him?”', pt: 'Um dos servos do sumo sacerdote, parente daquele a quem Pedro cortara a orelha, disse: Não te vi eu no jardim com ele?' },
      { v: 27, en: 'Peter therefore denied it again, and immediately the rooster crowed.', pt: 'Pedro negou outra vez, e imediatamente o galo cantou.' },
      { v: 28, en: 'They led Jesus therefore from Caiaphas into the Praetorium. It was early, and they themselves didn’t enter into the Praetorium, that they might not be defiled, but might eat the Passover.', pt: 'Depois conduziram Jesus da presença de Caifás para o pretório; era de manhã cedo; e eles não entraram no pretório, para não se contaminarem, mas poderem comer a páscoa.' },
      { v: 29, en: 'Pilate therefore went out to them, and said, “What accusation do you bring against this man?”', pt: 'Então Pilatos saiu a ter com eles, e perguntou: Que acusação trazeis contra este homem?' },
      { v: 30, en: 'They answered him, “If this man weren’t an evildoer, we wouldn’t have delivered him up to you.”', pt: 'Responderam-lhe: Se ele não fosse malfeitor, não to entregaríamos.' },
      { v: 31, en: 'Pilate therefore said to them, “Take him yourselves, and judge him according to your law.” Therefore the Jews said to him, “It is not lawful for us to put anyone to death,”', pt: 'Disse-lhes, então, Pilatos: Tomai-o vós, e julgai-o segundo a vossa lei. Disseram-lhe os judeus: A nós não nos é lícito tirar a vida a ninguém.' },
      { v: 32, en: 'that the word of Jesus might be fulfilled, which he spoke, signifying by what kind of death he should die.', pt: 'Isso foi para que se cumprisse a palavra que dissera Jesus, significando de que morte havia de morrer.' },
      { v: 33, en: 'Pilate therefore entered again into the Praetorium, called Jesus, and said to him, “Are you the King of the Jews?”', pt: 'Pilatos, pois, tornou a entrar no pretório, chamou a Jesus e perguntou-lhe: És tu o rei dos judeus?' },
      { v: 34, en: 'Jesus answered him, “Do you say this by yourself, or did others tell you about me?”', pt: 'Respondeu Jesus: Dizes isso de ti mesmo, ou foram outros que to disseram de mim?' },
      { v: 35, en: 'Pilate answered, “I’m not a Jew, am I? Your own nation and the chief priests delivered you to me. What have you done?”', pt: 'Replicou Pilatos: Porventura sou eu judeu? O teu povo e os principais sacerdotes entregaram-te a mim; que fizeste?' },
      { v: 36, en: 'Jesus answered, “My Kingdom is not of this world. If my Kingdom were of this world, then my servants would fight, that I wouldn’t be delivered to the Jews. But now my Kingdom is not from here.”', pt: 'Respondeu Jesus: O meu reino não é deste mundo; se o meu reino fosse deste mundo, pelejariam os meus servos, para que eu não fosse entregue aos judeus; entretanto o meu reino não é daqui.' },
      { v: 37, en: 'Pilate therefore said to him, “Are you a king then?” Jesus answered, “You say that I am a king. For this reason I have been born, and for this reason I have come into the world, that I should testify to the truth. Everyone who is of the truth listens to my voice.”', pt: 'Perguntou-lhe, pois, Pilatos: Logo tu és rei? Respondeu Jesus: Tu dizes que eu sou rei. Eu para isso nasci, e para isso vim ao mundo, a fim de dar testemunho da verdade. Todo aquele que é da verdade ouve a minha voz.' },
      { v: 38, en: 'Pilate said to him, “What is truth?” When he had said this, he went out again to the Jews, and said to them, “I find no basis for a charge against him.', pt: 'Perguntou-lhe Pilatos: Que é a verdade? E dito isto, de novo saiu a ter com os judeus, e disse-lhes: Não acho nele crime algum.' },
      { v: 39, en: 'But you have a custom, that I should release someone to you at the Passover. Therefore, do you want me to release to you the King of the Jews?”', pt: 'Tendes, porém, por costume que eu vos solte alguém por ocasião da páscoa; quereis, pois, que vos solte o rei dos judeus?' },
      { v: 40, en: 'Then they all shouted again, saying, “Not this man, but Barabbas!” Now Barabbas was a robber.', pt: 'Então todos tornaram a clamar dizendo: Este não, mas Barrabás. Ora, Barrabás era salteador.' },
    ],
    19: [
      { v: 1, en: 'So Pilate then took Jesus, and flogged him.', pt: 'Nisso, pois, Pilatos tomou a Jesus, e mandou açoitá-lo.' },
      { v: 2, en: 'The soldiers twisted thorns into a crown, and put it on his head, and dressed him in a purple garment.', pt: 'E os soldados, tecendo uma coroa de espinhos, puseram-lha sobre a cabeça, e lhe vestiram um manto de púrpura;' },
      { v: 3, en: 'They kept saying, “Hail, King of the Jews!” and they kept slapping him.', pt: 'e chegando-se a ele, diziam: Salve, rei dos judeus! e e davam-lhe bofetadas.' },
      { v: 4, en: 'Then Pilate went out again, and said to them, “Behold, I bring him out to you, that you may know that I find no basis for a charge against him.”', pt: 'Então Pilatos saiu outra vez, e disse-lhes: Eis aqui vo-lo trago fora, para que saibais que não acho nele crime algum.' },
      { v: 5, en: 'Jesus therefore came out, wearing the crown of thorns and the purple garment. Pilate said to them, “Behold, the man!”', pt: 'Saiu, pois, Jesus, trazendo a coroa de espinhos e o manto de púrpura. E disse-lhes Pilatos: Eis o homem!' },
      { v: 6, en: 'When therefore the chief priests and the officers saw him, they shouted, saying, “Crucify! Crucify!” Pilate said to them, “Take him yourselves, and crucify him, for I find no basis for a charge against him.”', pt: 'Quando o viram os principais sacerdotes e os guardas, clamaram, dizendo: Crucifica-o! Crucifica-o! Disse-lhes Pilatos: Tomai-o vós, e crucificai-o; porque nenhum crime acho nele.' },
      { v: 7, en: 'The Jews answered him, “We have a law, and by our law he ought to die, because he made himself the Son of God.”', pt: 'Responderam-lhe os judeus: Nós temos uma lei, e segundo esta lei ele deve morrer, porque se fez Filho de Deus.' },
      { v: 8, en: 'When therefore Pilate heard this saying, he was more afraid.', pt: 'Ora, Pilatos, quando ouviu esta palavra, mais atemorizado ficou;' },
      { v: 9, en: 'He entered into the Praetorium again, and said to Jesus, “Where are you from?” But Jesus gave him no answer.', pt: 'e entrando outra vez no pretório, perguntou a Jesus: Donde és tu? Mas Jesus não lhe deu resposta.' },
      { v: 10, en: 'Pilate therefore said to him, “Aren’t you speaking to me? Don’t you know that I have power to release you, and have power to crucify you?”', pt: 'Disse-lhe, então, Pilatos: Não me respondes? não sabes que tenho autoridade para te soltar, e autoridade para te crucificar?' },
      { v: 11, en: 'Jesus answered, “You would have no power at all against me, unless it were given to you from above. Therefore he who delivered me to you has greater sin.”', pt: 'Respondeu-lhe Jesus: Nenhuma autoridade terias sobre mim, se de cima não te fora dado; por isso aquele que me entregou a ti, maior pecado tem.' },
      { v: 12, en: 'At this, Pilate was seeking to release him, but the Jews cried out, saying, “If you release this man, you aren’t Caesar’s friend! Everyone who makes himself a king speaks against Caesar!”', pt: 'Daí em diante Pilatos procurava soltá-lo; mas os judeus clamaram: Se soltares a este, não és amigo de César; todo aquele que se faz rei é contra César.' },
      { v: 13, en: 'When Pilate therefore heard these words, he brought Jesus out, and sat down on the judgment seat at a place called “The Pavement”, but in Hebrew, “Gabbatha.”', pt: 'Pilatos, pois, quando ouviu isto, trouxe Jesus para fora e sentou-se no tribunal, no lugar chamado Pavimento, e em hebraico Gabatá.' },
      { v: 14, en: 'Now it was the Preparation Day of the Passover, at about the sixth hour. He said to the Jews, “Behold, your King!”', pt: 'Ora, era a preparação da páscoa, e cerca da hora sexta. E disse aos judeus: Eis o vosso rei.' },
      { v: 15, en: 'They cried out, “Away with him! Away with him! Crucify him!” Pilate said to them, “Shall I crucify your King?” The chief priests answered, “We have no king but Caesar!”', pt: 'Mas eles clamaram: Tira-o! tira-o! crucifica-o! Disse-lhes Pilatos: Hei de crucificar o vosso rei? responderam, os principais sacerdotes: Não temos rei, senão César.' },
      { v: 16, en: 'So then he delivered him to them to be crucified. So they took Jesus and led him away.', pt: 'Então lho entregou para ser crucificado.' },
      { v: 17, en: 'He went out, bearing his cross, to the place called “The Place of a Skull”, which is called in Hebrew, “Golgotha”,', pt: 'Tomaram, pois, a Jesus; e ele, carregando a sua própria cruz, saiu para o lugar chamado Caveira, que em hebraico se chama Gólgota,' },
      { v: 18, en: 'where they crucified him, and with him two others, on either side one, and Jesus in the middle.', pt: 'onde o crucificaram, e com ele outros dois, um de cada lado, e Jesus no meio.' },
      { v: 19, en: 'Pilate wrote a title also, and put it on the cross. There was written, “JESUS OF NAZARETH, THE KING OF THE JEWS.”', pt: 'E Pilatos escreveu também um título, e o colocou sobre a cruz; e nele estava escrito: JESUS O NAZARENO, O REI DOS JUDEUS.' },
      { v: 20, en: 'Therefore many of the Jews read this title, for the place where Jesus was crucified was near the city; and it was written in Hebrew, in Latin, and in Greek.', pt: 'Muitos dos judeus, pois, leram este título; porque o lugar onde Jesus foi crucificado era próximo da cidade; e estava escrito em hebraico, latim e grego.' },
      { v: 21, en: 'The chief priests of the Jews therefore said to Pilate, “Don’t write, ‘The King of the Jews,’ but, ‘he said, “I am King of the Jews.”’”', pt: 'Diziam então a Pilatos os principais sacerdotes dos judeus: Não escrevas: O rei dos judeus; mas que ele disse: Sou rei dos judeus.' },
      { v: 22, en: 'Pilate answered, “What I have written, I have written.”', pt: 'Respondeu Pilatos: O que escrevi, escrevi.' },
      { v: 23, en: 'Then the soldiers, when they had crucified Jesus, took his garments and made four parts, to every soldier a part; and also the coat. Now the coat was without seam, woven from the top throughout.', pt: 'Tendo, pois, os soldados crucificado a Jesus, tomaram as suas vestes, e fizeram delas quatro partes, para cada soldado uma parte. Tomaram também a túnica; ora a túnica não tinha costura, sendo toda tecida de alto a baixo.' },
      { v: 24, en: 'Then they said to one another, “Let’s not tear it, but cast lots for it to decide whose it will be,” that the Scripture might be fulfilled, which says, “They parted my garments among them. For my cloak they cast lots.” Therefore the soldiers did these things.', pt: 'Pelo que disseram uns aos outros: Não a rasguemos, mas lancemos sortes sobre ela, para ver de quem será (para que se cumprisse a escritura que diz: Repartiram entre si as minhas vestes, e lançaram sortes). E, de fato, os soldados assim fizeram.' },
      { v: 25, en: 'But there were standing by the cross of Jesus his mother, and his mother’s sister, Mary the wife of Clopas, and Mary Magdalene.', pt: 'Estavam em pé, junto à cruz de Jesus, sua mãe, e a irmã de sua mãe, e Maria, mulher de Clôpas, e Maria Madalena.' },
      { v: 26, en: 'Therefore when Jesus saw his mother, and the disciple whom he loved standing there, he said to his mother, “Woman, behold, your son!”', pt: 'Ora, Jesus, vendo ali sua mãe, e ao lado dela o discípulo a quem ele amava, disse a sua mãe: Mulher, eis aí o teu filho.' },
      { v: 27, en: 'Then he said to the disciple, “Behold, your mother!” From that hour, the disciple took her to his own home.', pt: 'Então disse ao discípulo: Eis aí tua mãe. E desde aquela hora o discípulo a recebeu em sua casa.' },
      { v: 28, en: 'After this, Jesus, seeing that all things were now finished, that the Scripture might be fulfilled, said, “I am thirsty.”', pt: 'Depois, sabendo Jesus que todas as coisas já estavam consumadas, para que se cumprisse a Escritura, disse: Tenho sede.' },
      { v: 29, en: 'Now a vessel full of vinegar was set there; so they put a sponge full of the vinegar on hyssop, and held it at his mouth.', pt: 'Estava ali um vaso cheio de vinagre. Puseram, pois, numa cana de hissopo uma esponja ensopada de vinagre, e lha chegaram à boca.' },
      { v: 30, en: 'When Jesus therefore had received the vinegar, he said, “It is finished.” He bowed his head, and gave up his spirit.', pt: 'Então Jesus, depois de ter tomado o vinagre, disse: está consumado. E, inclinando a cabeça, entregou o espírito.' },
      { v: 31, en: 'Therefore the Jews, because it was the Preparation Day, so that the bodies wouldn’t remain on the cross on the Sabbath (for that Sabbath was a special one), asked of Pilate that their legs might be broken, and that they might be taken away.', pt: 'Ora, os judeus, como era a preparação, e para que no sábado não ficassem os corpos na cruz, pois era grande aquele dia de sábado, rogaram a Pilatos que se lhes quebrassem as pernas, e fossem tirados dali.' },
      { v: 32, en: 'Therefore the soldiers came, and broke the legs of the first, and of the other who was crucified with him;', pt: 'Foram então os soldados e, na verdade, quebraram as pernas ao primeiro e ao outro que com ele fora crucificado;' },
      { v: 33, en: 'but when they came to Jesus, and saw that he was already dead, they didn’t break his legs.', pt: 'mas vindo a Jesus, e vendo que já estava morto, não lhe quebraram as pernas;' },
      { v: 34, en: 'However one of the soldiers pierced his side with a spear, and immediately blood and water came out.', pt: 'contudo um dos soldados lhe furou o lado com uma lança, e logo saiu sangue e água.' },
      { v: 35, en: 'He who has seen has testified, and his testimony is true. He knows that he tells the truth, that you may believe.', pt: 'E é quem viu isso que dá testemunho, e o seu testemunho é verdadeiro; e sabe que diz a verdade, para que também vós creiais.' },
      { v: 36, en: 'For these things happened, that the Scripture might be fulfilled, “A bone of him will not be broken.”', pt: 'Porque isto aconteceu para que se cumprisse a escritura: Nenhum dos seus ossos será quebrado.' },
      { v: 37, en: 'Again another Scripture says, “They will look on him whom they pierced.”', pt: 'Também há outra escritura que diz: Olharão para aquele que traspassaram.' },
      { v: 38, en: 'After these things, Joseph of Arimathaea, being a disciple of Jesus, but secretly for fear of the Jews, asked of Pilate that he might take away Jesus’ body. Pilate gave him permission. He came therefore and took away his body.', pt: 'Depois disto, José de Arimatéia, que era discípulo de Jesus, embora oculto por medo dos judeus, rogou a Pilatos que lhe permitisse tirar o corpo de Jesus; e Pilatos lho permitiu. Então foi e o tirou.' },
      { v: 39, en: 'Nicodemus, who at first came to Jesus by night, also came bringing a mixture of myrrh and aloes, about a hundred Roman pounds.', pt: 'E Nicodemos, aquele que anteriormente viera ter com Jesus de noite, foi também, levando cerca de cem libras duma mistura de mirra e aloés.' },
      { v: 40, en: 'So they took Jesus’ body, and bound it in linen cloths with the spices, as the custom of the Jews is to bury.', pt: 'Tomaram, pois, o corpo de Jesus, e o envolveram em panos de linho com as especiarias, como os judeus costumavam fazer na preparação para a sepultura.' },
      { v: 41, en: 'Now in the place where he was crucified there was a garden. In the garden was a new tomb in which no man had ever yet been laid.', pt: 'No lugar onde Jesus foi crucificado havia um jardim, e nesse jardim um sepulcro novo, em que ninguém ainda havia sido posto.' },
      { v: 42, en: 'Then because of the Jews’ Preparation Day (for the tomb was near at hand) they laid Jesus there.', pt: 'Ali, pois, por ser a vespera do sábado dos judeus, e por estar perto aquele sepulcro, puseram a Jesus.' },
    ],
    20: [
      { v: 1, en: 'Now on the first day of the week, Mary Magdalene went early, while it was still dark, to the tomb, and saw the stone taken away from the tomb.', pt: 'No primeiro dia da semana Maria Madalena foi ao sepulcro de madrugada, sendo ainda escuro, e viu que a pedra fora removida do sepulcro.' },
      { v: 2, en: 'Therefore she ran and came to Simon Peter, and to the other disciple whom Jesus loved, and said to them, “They have taken away the Lord out of the tomb, and we don’t know where they have laid him!”', pt: 'Correu, pois, e foi ter com Simão Pedro, e o outro discípulo, a quem Jesus amava, e disse-lhes: Tiraram do sepulcro o Senhor, e não sabemos onde o puseram.' },
      { v: 3, en: 'Therefore Peter and the other disciple went out, and they went toward the tomb.', pt: 'Saíram então Pedro e o outro discípulo e foram ao sepulcro.' },
      { v: 4, en: 'They both ran together. The other disciple outran Peter, and came to the tomb first.', pt: 'Corriam os dois juntos, mas o outro discípulo correu mais ligeiro do que Pedro, e chegou primeiro ao sepulcro;' },
      { v: 5, en: 'Stooping and looking in, he saw the linen cloths lying, yet he didn’t enter in.', pt: 'e, abaixando-se viu os panos de linho ali deixados, todavia não entrou.' },
      { v: 6, en: 'Then Simon Peter came, following him, and entered into the tomb. He saw the linen cloths lying,', pt: 'Chegou, pois, Simão Pedro, que o seguia, e entrou no sepulcro e viu os panos de linho ali deixados,' },
      { v: 7, en: 'and the cloth that had been on his head, not lying with the linen cloths, but rolled up in a place by itself.', pt: 'e que o lenço, que estivera sobre a cabeça de Jesus, não estava com os panos, mas enrolado num lugar à parte.' },
      { v: 8, en: 'So then the other disciple who came first to the tomb also entered in, and he saw and believed.', pt: 'Então entrou também o outro discípulo, que chegara primeiro ao sepulcro, e viu e creu.' },
      { v: 9, en: 'For as yet they didn’t know the Scripture, that he must rise from the dead.', pt: 'Porque ainda não entendiam a escritura, que era necessário que ele ressurgisse dentre os mortos.' },
      { v: 10, en: 'So the disciples went away again to their own homes.', pt: 'Tornaram, pois, os discípulos para casa.' },
      { v: 11, en: 'But Mary was standing outside at the tomb weeping. So, as she wept, she stooped and looked into the tomb,', pt: 'Maria, porém, estava em pé, diante do sepulcro, a chorar. Enquanto chorava, abaixou-se a olhar para dentro do sepulcro,' },
      { v: 12, en: 'and she saw two angels in white sitting, one at the head, and one at the feet, where the body of Jesus had lain.', pt: 'e viu dois anjos vestidos de branco sentados onde jazera o corpo de Jesus, um à cabeceira e outro aos pés.' },
      { v: 13, en: 'They told her, “Woman, why are you weeping?” She said to them, “Because they have taken away my Lord, and I don’t know where they have laid him.”', pt: 'E perguntaram-lhe eles: Mulher, por que choras? Respondeu- lhes: Porque tiraram o meu Senhor, e não sei onde o puseram.' },
      { v: 14, en: 'When she had said this, she turned around and saw Jesus standing, and didn’t know that it was Jesus.', pt: 'Ao dizer isso, voltou-se para trás, e viu a Jesus ali em pé, mas não sabia que era Jesus.' },
      { v: 15, en: 'Jesus said to her, “Woman, why are you weeping? Who are you looking for?” She, supposing him to be the gardener, said to him, “Sir, if you have carried him away, tell me where you have laid him, and I will take him away.”', pt: 'Perguntou-lhe Jesus: Mulher, por que choras? A quem procuras? Ela, julgando que fosse o jardineiro, respondeu-lhe: Senhor, se tu o levaste, dize-me onde o puseste, e eu o levarei.' },
      { v: 16, en: 'Jesus said to her, “Mary.” She turned and said to him, “Rabboni!” which is to say, “Teacher!”', pt: 'Disse-lhe Jesus: Maria! Ela, virando-se, disse-lhe em hebraico: Raboni! - que quer dizer, Mestre.' },
      { v: 17, en: 'Jesus said to her, “Don’t hold me, for I haven’t yet ascended to my Father; but go to my brothers, and tell them, ‘I am ascending to my Father and your Father, to my God and your God.’”', pt: 'Disse-lhe Jesus: Deixa de me tocar, porque ainda não subi ao Pai; mas vai a meus irmãos e dize-lhes que eu subo para meu Pai e vosso Pai, meu Deus e vosso Deus.' },
      { v: 18, en: 'Mary Magdalene came and told the disciples that she had seen the Lord, and that he had said these things to her.', pt: 'E foi Maria Madalena anunciar aos discípulos: Vi o Senhor! - e que ele lhe dissera estas coisas.' },
      { v: 19, en: 'When therefore it was evening, on that day, the first day of the week, and when the doors were locked where the disciples were assembled, for fear of the Jews, Jesus came and stood in the middle, and said to them, “Peace be to you.”', pt: 'Chegada, pois, a tarde, naquele dia, o primeiro da semana, e estando os discípulos reunidos com as portas cerradas por medo dos judeus, chegou Jesus, pôs-se no meio e disse-lhes: Paz seja convosco.' },
      { v: 20, en: 'When he had said this, he showed them his hands and his side. The disciples therefore were glad when they saw the Lord.', pt: 'Dito isto, mostrou-lhes as mãos e o lado. Alegraram-se, pois, os discípulos ao verem o Senhor.' },
      { v: 21, en: 'Jesus therefore said to them again, “Peace be to you. As the Father has sent me, even so I send you.”', pt: 'Disse-lhes, então, Jesus segunda vez: Paz seja convosco; assim como o Pai me enviou, também eu vos envio a vós.' },
      { v: 22, en: 'When he had said this, he breathed on them, and said to them, “Receive the Holy Spirit!', pt: 'E havendo dito isso, assoprou sobre eles, e disse-lhes: Recebei o Espírito Santo.' },
      { v: 23, en: 'If you forgive anyone’s sins, they have been forgiven them. If you retain anyone’s sins, they have been retained.”', pt: 'Âqueles a quem perdoardes os pecados, são-lhes perdoados; e àqueles a quem os retiverdes, são-lhes retidos.' },
      { v: 24, en: 'But Thomas, one of the twelve, called Didymus, wasn’t with them when Jesus came.', pt: 'Ora, Tomé, um dos doze, chamado Dídimo, não estava com eles quando veio Jesus.' },
      { v: 25, en: 'The other disciples therefore said to him, “We have seen the Lord!” But he said to them, “Unless I see in his hands the print of the nails, put my finger into the print of the nails, and put my hand into his side, I will not believe.”', pt: 'Diziam-lhe, pois, ou outros discípulos: Vimos o Senhor. Ele, porém, lhes respondeu: Se eu não vir o sinal dos cravos nas mãos, e não meter a mão no seu lado, de maneira nenhuma crerei.' },
      { v: 26, en: 'After eight days again his disciples were inside, and Thomas was with them. Jesus came, the doors being locked, and stood in the middle, and said, “Peace be to you.”', pt: 'Oito dias depois estavam os discípulos outra vez ali reunidos, e Tomé com eles. Chegou Jesus, estando as portas fechadas, pôs-se no meio deles e disse: Paz seja convosco.' },
      { v: 27, en: 'Then he said to Thomas, “Reach here your finger, and see my hands. Reach here your hand, and put it into my side. Don’t be unbelieving, but believing.”', pt: 'Depois disse a Tomé: Chega aqui o teu dedo, e vê as minhas mãos; chega a tua mão, e mete-a no meu lado; e não mais sejas incrédulo, mas crente.' },
      { v: 28, en: 'Thomas answered him, “My Lord and my God!”', pt: 'Respondeu-lhe Tomé: Senhor meu, e Deus meu!' },
      { v: 29, en: 'Jesus said to him, “Because you have seen me, you have believed. Blessed are those who have not seen, and have believed.”', pt: 'Disse-lhe Jesus: Porque me viste, creste? Bem-aventurados os que não viram e creram.' },
      { v: 30, en: 'Therefore Jesus did many other signs in the presence of his disciples, which are not written in this book;', pt: 'Jesus, na verdade, operou na presença de seus discípulos ainda muitos outros sinais que não estão escritos neste livro;' },
      { v: 31, en: 'but these are written, that you may believe that Jesus is the Christ, the Son of God, and that believing you may have life in his name.', pt: 'estes, porém, estão escritos para que creiais que Jesus é o Cristo, o Filho de Deus, e para que, crendo, tenhais vida em seu nome.' },
    ],
    21: [
      { v: 1, en: 'After these things, Jesus revealed himself again to the disciples at the sea of Tiberias. He revealed himself this way.', pt: 'Depois disto manifestou-se Jesus outra vez aos discípulos junto do mar de Tiberíades; e manifestou-se deste modo:' },
      { v: 2, en: 'Simon Peter, Thomas called Didymus, Nathanael of Cana in Galilee, and the sons of Zebedee, and two others of his disciples were together.', pt: 'Estavam juntos Simão Pedro, Tomé, chamado Dídimo, Natanael, que era de Caná da Galiléia, os filhos de Zebedeu, e outros dois dos seus discípulos.' },
      { v: 3, en: 'Simon Peter said to them, “I’m going fishing.” They told him, “We are also coming with you.” They immediately went out, and entered into the boat. That night, they caught nothing.', pt: 'Disse-lhes Simão Pedro: Vou pescar. Responderam-lhe: Nós também vamos contigo. Saíram e entraram no barco; e naquela noite nada apanharam.' },
      { v: 4, en: 'But when day had already come, Jesus stood on the beach, yet the disciples didn’t know that it was Jesus.', pt: 'Mas ao romper da manhã, Jesus se apresentou na praia; todavia os discípulos não sabiam que era ele.' },
      { v: 5, en: 'Jesus therefore said to them, “Children, have you anything to eat?” They answered him, “No.”', pt: 'Disse-lhes, pois, Jesus: Filhos, não tendes nada que comer? Responderam-lhe: Não.' },
      { v: 6, en: 'He said to them, “Cast the net on the right side of the boat, and you will find some.” They cast it therefore, and now they weren’t able to draw it in for the multitude of fish.', pt: 'Disse-lhes ele: Lançai a rede à direita do barco, e achareis. Lançaram-na, pois, e já não a podiam puxar por causa da grande quantidade de peixes.' },
      { v: 7, en: 'That disciple therefore whom Jesus loved said to Peter, “It’s the Lord!” So when Simon Peter heard that it was the Lord, he wrapped his coat around him (for he was naked), and threw himself into the sea.', pt: 'Então aquele discípulo a quem Jesus amava disse a Pedro: Senhor. Quando, pois, Simão Pedro ouviu que era o Senhor, cingiu-se com a túnica, porque estava despido, e lançou-se ao mar;' },
      { v: 8, en: 'But the other disciples came in the little boat (for they were not far from the land, but about two hundred cubits away), dragging the net full of fish.', pt: 'mas os outros discípulos vieram no barquinho, puxando a rede com os peixes, porque não estavam distantes da terra senão cerca de duzentos côvados.' },
      { v: 9, en: 'So when they got out on the land, they saw a fire of coals there, and fish laid on it, and bread.', pt: 'Ora, ao saltarem em terra, viram ali brasas, e um peixe posto em cima delas, e pão.' },
      { v: 10, en: 'Jesus said to them, “Bring some of the fish which you have just caught.”', pt: 'Disse-lhes Jesus: Trazei alguns dos peixes que agora apanhastes.' },
      { v: 11, en: 'Simon Peter went up, and drew the net to land, full of great fish, one hundred fifty-three; and even though there were so many, the net wasn’t torn.', pt: 'Entrou Simão Pedro no barco e puxou a rede para terra, cheia de cento e cinquenta e três grandes peixes; e, apesar de serem tantos, não se rompeu a rede.' },
      { v: 12, en: 'Jesus said to them, “Come and eat breakfast.” None of the disciples dared inquire of him, “Who are you?” knowing that it was the Lord.', pt: 'Disse-lhes Jesus: Vinde, comei. Nenhum dos discípulos ousava perguntar-lhe: Quem és tu? sabendo que era o Senhor.' },
      { v: 13, en: 'Then Jesus came and took the bread, gave it to them, and the fish likewise.', pt: 'Chegou Jesus, tomou o pão e deu-lho, e semelhantemente o peixe.' },
      { v: 14, en: 'This is now the third time that Jesus was revealed to his disciples, after he had risen from the dead.', pt: 'Foi esta a terceira vez que Jesus se manifestou aos seus discípulos, depois de ter ressurgido dentre os mortos.' },
      { v: 15, en: 'So when they had eaten their breakfast, Jesus said to Simon Peter, “Simon, son of Jonah, do you love me more than these?” He said to him, “Yes, Lord; you know that I have affection for you.” He said to him, “Feed my lambs.”', pt: 'Depois de terem comido, perguntou Jesus a Simão Pedro: Simão Pedro: Simão, filho de João, amas-me mais do que estes? Respondeu- lhe: Sim, Senhor; tu sabes que te amo. Disse-lhe: Apascenta os meus cordeirinhos.' },
      { v: 16, en: 'He said to him again a second time, “Simon, son of Jonah, do you love me?” He said to him, “Yes, Lord; you know that I have affection for you.” He said to him, “Tend my sheep.”', pt: 'Tornou a perguntar-lhe: Simão, filho de João, amas-me? Respondeu-lhe: Sim, Senhor; tu sabes que te amo. Disse-lhe: Pastoreia as minhas ovelhas.' },
      { v: 17, en: 'He said to him the third time, “Simon, son of Jonah, do you have affection for me?” Peter was grieved because he asked him the third time, “Do you have affection for me?” He said to him, “Lord, you know everything. You know that I have affection for you.” Jesus said to him, “Feed my sheep.', pt: 'Perguntou-lhe terceira vez: Simão, filho de João, amas-me? Entristeceu-se Pedro por lhe ter perguntado pela terceira vez: Amas- me? E respondeu-lhe: Senhor, tu sabes todas as coisas; tu sabes que te amo. Disse-lhe Jesus: Apascenta as minhas ovelhas.' },
      { v: 18, en: 'Most certainly I tell you, when you were young, you dressed yourself, and walked where you wanted to. But when you are old, you will stretch out your hands, and another will dress you, and carry you where you don’t want to go.”', pt: 'Em verdade, em verdade te digo que, quando eras mais moço, te cingias a ti mesmo, e andavas por onde querias; mas, quando fores velho, estenderás as mãos e outro te cingirá, e te levará para onde tu não queres.' },
      { v: 19, en: 'Now he said this, signifying by what kind of death he would glorify God. When he had said this, he said to him, “Follow me.”', pt: 'Ora, isto ele disse, significando com que morte havia Pedro de glorificar a Deus. E, havendo dito isto, ordenou-lhe: Segue-me.' },
      { v: 20, en: 'Then Peter, turning around, saw a disciple following. This was the disciple whom Jesus loved, the one who had also leaned on Jesus’ breast at the supper and asked, “Lord, who is going to betray You?”', pt: 'E Pedro, virando-se, viu que o seguia aquele discípulo a quem Jesus amava, o mesmo que na ceia se recostara sobre o peito de Jesus e perguntara: Senhor, quem é o que te trai?' },
      { v: 21, en: 'Peter seeing him, said to Jesus, “Lord, what about this man?”', pt: 'Ora, vendo Pedro a este, perguntou a Jesus: Senhor, e deste que será?' },
      { v: 22, en: 'Jesus said to him, “If I desire that he stay until I come, what is that to you? You follow me.”', pt: 'Respondeu-lhe Jesus: Se eu quiser que ele fique até que eu venha, que tens tu com isso? Segue-me tu.' },
      { v: 23, en: 'This saying therefore went out among the brothers, that this disciple wouldn’t die. Yet Jesus didn’t say to him that he wouldn’t die, but, “If I desire that he stay until I come, what is that to you?”', pt: 'Divulgou-se, pois, entre os irmãos este dito, que aquele discípulo não havia de morrer. Jesus, porém, não disse que não morreria, mas: se eu quiser que ele fique até que eu venha, que tens tu com isso?' },
      { v: 24, en: 'This is the disciple who testifies about these things, and wrote these things. We know that his witness is true.', pt: 'Este é o discípulo que dá testemunho destas coisas e as escreveu; e sabemos que o seu testemunho é verdadeiro.' },
      { v: 25, en: 'There are also many other things which Jesus did, which if they would all be written, I suppose that even the world itself wouldn’t have room for the books that would be written.', pt: 'E ainda muitas outras coisas há que Jesus fez; as quais, se fossem escritas uma por uma, creio que nem ainda no mundo inteiro caberiam os livros que se escrevessem.' },
    ],
  },
};

export default book;
